-- Poems batch 478
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-5','贈亡妻張氏','唐暄','唐','御定全唐诗','yuding','','[]','嶧陽桐半死，延津劍一沈。如何宿昔內，空負百年心。',24,'御定全唐詩/json/770.json','["嶧陽桐半死，延津劍一沈。如何宿昔內，空負百年心。"]'),
('yuding-6','題司空山觀','李韶','唐','御定全唐诗','yuding','','[]','梁代真人上紫微，水盤山腳五雲飛。',32,'御定全唐詩/json/770.json','["梁代真人上紫微，水盤山腳五雲飛。", "松杉老盡無消息，猶得千年一度歸。"]'),
('yuding-7','戲題盱眙壁','韋鵬翼','唐','御定全唐诗','yuding','','[]','豈肯閑尋竹徑行，卻嫌絲管好蛙聲。',32,'御定全唐詩/json/770.json','["豈肯閑尋竹徑行，卻嫌絲管好蛙聲。", "自從煮鶴燒琴後，背卻青山臥月明。"]'),
('yuding-8','題楊少卿書後','安鴻漸','唐','御定全唐诗','yuding','','[]','端溪石硯宣城管，王屋松煙紫兔毫。',32,'御定全唐詩/json/770.json','["端溪石硯宣城管，王屋松煙紫兔毫。", "更得孤卿老書劄，人間無此五般高。"]'),
('yuding-9','自紫陽觀至華陽洞，宿侯尊師草堂簡同游','李延陵','唐','御定全唐诗','yuding','','[]','石林媚煙景，句曲盤江甸。南向佳氣濃，峰峰遙隱見。',144,'御定全唐詩/json/770.json','["石林媚煙景，句曲盤江甸。南向佳氣濃，峰峰遙隱見。", "漸臨華陽口，微路入蔥蒨。七曜懸洞宮，五雲抱山殿。", "銀函意誰發，金液徒堪薦。千載桃花春，秦人深不見。", "東溪喜相遇，貞白如會面。青鳥來去閑，紅霞朝夕變。", "一從化真骨，萬里乘飛電。蘿月延步虛，松花醉閑宴。", "幽人即長往，茂宰應交戰。明發歸琴堂，知君懶為縣。"]'),
('yuding-10','題鐘雅青紗枕','秦尚運','唐','御定全唐诗','yuding','','[]','陰香裝豔入青紗，還與欹眠好事家。',32,'御定全唐詩/json/770.json','["陰香裝豔入青紗，還與欹眠好事家。", "夢裏卻成山色雨，沈山不敢鬥青華。"]'),
('yuding-11','題搔口','張仲謀','唐','御定全唐诗','yuding','','[]','嘗聞燒尾便拏空，只過天門更一重。',32,'御定全唐詩/json/770.json','["嘗聞燒尾便拏空，只過天門更一重。", "大禹未生門未鑿，可能天下總無龍。"]'),
('yuding-12','山寺見楊少卿書壁，因題其尾','馮少吉','唐','御定全唐诗','yuding','','[]','少卿真跡滿僧居，只恐鐘王也不如。',32,'御定全唐詩/json/770.json','["少卿真跡滿僧居，只恐鐘王也不如。", "為報遠公須愛惜，此書書後更無書。"]'),
('yuding-13','經杜甫舊宅','殷陶','唐','御定全唐诗','yuding','','[]','浣花溪裏花多處，為憶先生在蜀時。萬古只應留舊宅，',40,'御定全唐詩/json/770.json','["浣花溪裏花多處，為憶先生在蜀時。萬古只應留舊宅，", "山月不知人事變，夜來江上與誰期。"]'),
('yuding-14','行縣至浮查寺','羅炯','唐','御定全唐诗','yuding','','[]','二十年前此布衣，鹿鳴西上虎符歸。行時賓從光前事，',40,'御定全唐詩/json/770.json','["二十年前此布衣，鹿鳴西上虎符歸。行時賓從光前事，", "春風一宿琉璃地，自有泉聲愜素機。"]'),
('yuding-15','敕和元相公家園即事寄王相公','韓雄','唐','御定全唐诗','yuding','','[]','共列中台貴，能齊物外心。回車青閣晚，解帶碧芳深。',48,'御定全唐詩/json/770.json','["共列中台貴，能齊物外心。回車青閣晚，解帶碧芳深。", "夜水隨畦入，晴花度竹尋。題詩更相應，一字重千金。"]'),
('yuding-16','仲秋太常寺觀公輅車拜陵','苗仲方','唐','御定全唐诗','yuding','','[]','南宮初開律，金風已戒涼。拜陵將展敬，車輅儼成行。',72,'御定全唐詩/json/770.json','["南宮初開律，金風已戒涼。拜陵將展敬，車輅儼成行。", "士庶觀祠禮，公卿習舊章。郊原佳氣引，園寢瑞煙長。", "鹵簿辭丹闕，威儀列太常。聖心何所寄，惟德在無忘。"]'),
('yuding-17','尋易尊師不遇','陳嶰','唐','御定全唐诗','yuding','','[]','爛熳紅霞光照衣，苔封白石路微微。',32,'御定全唐詩/json/770.json','["爛熳紅霞光照衣，苔封白石路微微。", "華陽洞裏何人在，落盡松花不見歸。"]'),
('yuding-18','早過梨嶺，喜雪書情呈崔判官','張起','唐','御定全唐诗','yuding','','[]','度嶺逢朝雪，行看馬跡深。輕標南國瑞，寒慰北人心。',48,'御定全唐詩/json/770.json','["度嶺逢朝雪，行看馬跡深。輕標南國瑞，寒慰北人心。", "皎潔停丹嶂，飄颻映綠林。共君歌樂土，無作白頭吟。"]'),
('yuding-19','春情','張起','唐','御定全唐诗','yuding','','[]','畫閣餘寒在，新年舊燕歸。梅花猶帶雪，未得試春衣。',24,'御定全唐詩/json/770.json','["畫閣餘寒在，新年舊燕歸。梅花猶帶雪，未得試春衣。"]'),
('yuding-20','贈竇蔡二記室入蜀','陳政','唐','御定全唐诗','yuding','','[]','昆山積良寶，大廈構眾材。馬卿委官去，鄒子背淮來。',144,'御定全唐詩/json/770.json','["昆山積良寶，大廈構眾材。馬卿委官去，鄒子背淮來。", "風流信多美，朝夕豫平臺。逸翮獨不群，清才複遒上。", "六輔昔推名，二江今振響。英華雖外發，磨琢終內朗。", "四海奮羽儀，清風久播馳。沈郁林難廁，青山翻易阻。", "回首望煙霞，誰知慕儔侶。飄然不系舟，為情自可求。", "若奉西園夜，浩想北園愁。無因逐萍藻，從爾泛清流。"]'),
('yuding-21','采菊','李建業','唐','御定全唐诗','yuding','','[]','簇簇竟相鮮，一枝開幾番。味甘資麹糵，香好勝蘭蓀。',48,'御定全唐詩/json/770.json','["簇簇竟相鮮，一枝開幾番。味甘資麹糵，香好勝蘭蓀。", "古道風搖遠，荒籬露壓繁。盈筐時采得，服餌近知門。"]'),
('yuding-22','水精環','羅維','唐','御定全唐诗','yuding','','[]','王室符長慶，環中得水精。任圓循不極，見素質仍貞。',72,'御定全唐詩/json/770.json','["王室符長慶，環中得水精。任圓循不極，見素質仍貞。", "信是天然瑞，非因朴斫成。無瑕勝玉美，至潔過冰清。", "未肯齊瑉價，寧同雜佩聲。能銜任黃雀，亦欲應時明。"]'),
('yuding-23','看牡丹','殷益','唐','御定全唐诗','yuding','','[]','擁毳對芳叢，由來趣不同。發從今日白，花是去年紅。',48,'御定全唐詩/json/770.json','["擁毳對芳叢，由來趣不同。發從今日白，花是去年紅。", "豔色隨朝露，馨香逐晚風。何須待零落，然後始知空。"]'),
('yuding-24','賦得垣衣','李得','唐','御定全唐诗','yuding','','[]','漠漠複霏霏，為君垣上衣。昭陽輦下草，應笑此生非。',48,'御定全唐詩/json/770.json','["漠漠複霏霏，為君垣上衣。昭陽輦下草，應笑此生非。", "掩藹青春去，蒼茫白露稀。猶勝萍逐水，流浪不相依。"]'),
('yuding-25','冬晚對雪憶胡處士','王邵','唐','御定全唐诗','yuding','','[]','寒更傳唱晚，清鏡覽衰顏。隔牖風驚竹，開簾雪滿山。',48,'御定全唐詩/json/770.json','["寒更傳唱晚，清鏡覽衰顏。隔牖風驚竹，開簾雪滿山。", "灑空深巷靜，積素廣庭閑。借問袁安舍，翛然尚閉關。"]'),
('yuding-26','池上','曹修古','唐','御定全唐诗','yuding','','[]','荷葉罩芙蓉，圓青映嫩紅。佳人南陌上，翠蓋立春風。',24,'御定全唐詩/json/770.json','["荷葉罩芙蓉，圓青映嫩紅。佳人南陌上，翠蓋立春風。"]'),
('yuding-27','對趙穎歌','朱子真','唐','御定全唐诗','yuding','','[]','人間幾日變桑田，誰識神仙洞裏天。',32,'御定全唐詩/json/770.json','["人間幾日變桑田，誰識神仙洞裏天。", "短促雖知有殊異，且須歡醉在生前。"]'),
('yuding-28','賦百舌鳥','嚴郭','唐','御定全唐诗','yuding','','[]','此禽輕巧少同倫，我聽長疑舌滿身。星未沒河先報曉，',40,'御定全唐詩/json/770.json','["此禽輕巧少同倫，我聽長疑舌滿身。星未沒河先報曉，", "莫倚清風更多事，玉樓還有晏眠人。"]'),
('yuding-29','孤雁','張子明','唐','御定全唐诗','yuding','','[]','只影翩翩下碧湘，傍池鴛鷺宿銀塘。雖逢夜雨迷深浦，',40,'御定全唐詩/json/770.json','["只影翩翩下碧湘，傍池鴛鷺宿銀塘。雖逢夜雨迷深浦，", "江南塞北俱關念，兩地飛歸是故鄉。"]'),
('yuding-30','水殿拋球曲二首','李謹言','唐','御定全唐诗','yuding','','[]','侍宴黃昏曉未休，玉階夜色月如流。',64,'御定全唐詩/json/770.json','["侍宴黃昏曉未休，玉階夜色月如流。", "朝來自覺承恩最，笑倩傍人認繡球。", "堪恨隋家幾帝王，舞裀揉盡繡鴛鴦。", "如今重到拋球處，不是金爐舊日香。"]'),
('yuding-31','銅雀妓','吳燭','唐','御定全唐诗','yuding','','[]','秋色西陵滿綠蕪，繁弦急管強歡娛。',32,'御定全唐詩/json/770.json','["秋色西陵滿綠蕪，繁弦急管強歡娛。", "長舒羅袖不成舞，卻向風前承淚珠。"]'),
('yuding-32','戲示諸妓','張保嗣','唐','御定全唐诗','yuding','','[]','綠羅裙上標三棒，紅粉腮邊淚兩行。',32,'御定全唐詩/json/770.json','["綠羅裙上標三棒，紅粉腮邊淚兩行。", "抄手向前咨大使，這回不敢惱兒郎。"]'),
('yuding-33','末秋到家','潘圖','唐','御定全唐诗','yuding','','[]','歸來無所利，骨肉亦不喜。黃犬卻有情，當門臥搖尾。',24,'御定全唐詩/json/770.json','["歸來無所利，骨肉亦不喜。黃犬卻有情，當門臥搖尾。"]'),
('yuding-34','送人往宣城','潘佐','唐','御定全唐诗','yuding','','[]','江畔送行人，千山生暮氛。謝安團扇上，為畫敬亭雲。',24,'御定全唐詩/json/770.json','["江畔送行人，千山生暮氛。謝安團扇上，為畫敬亭雲。"]'),
('yuding-35','洛陽河亭奉酬留守郡公追送','李逸','唐','御定全唐诗','yuding','','[]','離亭餞落暉，臘酒減征衣。歲晚煙霞重，川寒雲樹微。',48,'御定全唐詩/json/770.json','["離亭餞落暉，臘酒減征衣。歲晚煙霞重，川寒雲樹微。", "戎裝千里至，舊路十年歸。還似汀洲雁，相逢又背飛。"]'),
('yuding-36','送道士曾昭瑩','沈麟','唐','御定全唐诗','yuding','','[]','南北東西事，人間會也無。昔曾棲玉笥，今也返玄都。',48,'御定全唐詩/json/770.json','["南北東西事，人間會也無。昔曾棲玉笥，今也返玄都。", "雪片隨天闊，泉聲落石孤。丹霄人有約，去采石菖蒲。"]'),
('yuding-37','贈別徐侃','安鳳','唐','御定全唐诗','yuding','','[]','一自離鄉國，十年在咸秦。泣盡卞和血，不逢一故人。',60,'御定全唐詩/json/770.json','["一自離鄉國，十年在咸秦。泣盡卞和血，不逢一故人。", "今日舊友別，羞此漂泊身。離情吟詩處，麻衣掩淚頻。", "淚別各分袂，且及來年春。"]'),
('yuding-38','顧城','李倫','唐','御定全唐诗','yuding','','[]','世久荒墟在，白雲幾代耕。市廛新草綠，裏社故煙輕。',48,'御定全唐詩/json/770.json','["世久荒墟在，白雲幾代耕。市廛新草綠，裏社故煙輕。", "不謹罹天討，來蘇豈忿兵。誰雲殷鑒遠，今古在人程。"]'),
('yuding-39','金錢花','盧子發','唐','御定全唐诗','yuding','','[]','輪廓休誇四字書，紅窠寫出對庭除。',32,'御定全唐詩/json/770.json','["輪廓休誇四字書，紅窠寫出對庭除。", "時時買得佳人笑，本色金錢卻不如。"]'),
('yuding-40','故白岩禪師院','王夢周','唐','御定全唐诗','yuding','','[]','能師還世名還在，空閉禪堂滿院苔。',32,'御定全唐詩/json/770.json','["能師還世名還在，空閉禪堂滿院苔。", "花樹不隨人寂寞，數株猶自出牆來。"]'),
('yuding-41','題九天使者廟','孫咸','唐','御定全唐诗','yuding','','[]','獨入玄宮禮至真，焚香不為賤貧身。秦淮兩岸沙埋骨，',40,'御定全唐詩/json/770.json','["獨入玄宮禮至真，焚香不為賤貧身。秦淮兩岸沙埋骨，", "九江太守勤王事，好放天兵渡要津。"]'),
('yuding-42','房公舊竹亭聞琴','李澣','唐','御定全唐诗','yuding','','[]','石室寒飆警，孫枝雅器裁。坐來山水操，弦斷吊塵埃。',24,'御定全唐詩/json/770.json','["石室寒飆警，孫枝雅器裁。坐來山水操，弦斷吊塵埃。"]'),
('yuding-43','清溪館作','錢戭','唐','御定全唐诗','yuding','','[]','指途清溪裏，左右唯深林。雲蔽望鄉處，雨愁為客心。',48,'御定全唐詩/json/770.json','["指途清溪裏，左右唯深林。雲蔽望鄉處，雨愁為客心。", "遇人多物役，聽鳥時幽音。何必滄浪水，庶茲浣塵襟。"]'),
('yuding-44','晚春宴','韋道遜','唐','御定全唐诗','yuding','','[]','日斜賓館晚，春輕麥候初。簷暄巢幕燕，池躍戲蓮魚。',48,'御定全唐詩/json/770.json','["日斜賓館晚，春輕麥候初。簷暄巢幕燕，池躍戲蓮魚。", "石聲隨流響，桐影傍岩疏。誰能千裏外，獨寄八行書。"]'),
('yuding-45','長沙六快詩','王揆','唐','御定全唐诗','yuding','','[]','湖外風物奇，長沙信難續。衡峰排古青，湘水湛寒綠。',156,'御定全唐詩/json/770.json','["湖外風物奇，長沙信難續。衡峰排古青，湘水湛寒綠。", "舟楫通大江，車輪會平陸。昔賢官是邦，仁澤流豐沃。", "今賢官是邦，刳啖人脂肉。懷昔甘棠花，傷今猛虎毒。", "然此一郡內，所樂人才六。漕與二憲僚，守連兩通屬。", "高堂日暮會，深夜繼以燭。幃幕皆綺紈，器皿盡金玉。", "歌喉若珠累，舞腰如素束。千態與萬狀，六人歡不足。", "因成快活詩，薦之堯舜目。"]'),
('yuding-46','廣州王園寺伏日即事寄北中親友','王言史','唐','御定全唐诗','yuding','','[]','南越逢初伏，東林度一朝。曲池煎畏景，高閣絕微飆。',120,'御定全唐詩/json/770.json','["南越逢初伏，東林度一朝。曲池煎畏景，高閣絕微飆。", "竹簟移先灑，蒲葵破複搖。地偏毛瘴近，山毒火威饒。", "裛汗絺如濯，親床枕並燒。墮枝傷翠羽，萎葉惜紅蕉。", "且困流金熾，難成獨酌謠。望霖窺潤礎，思吹候纖條。", "旅恨生烏滸，鄉心系浴橋。誰憐在炎客，一夕壯容銷。"]'),
('yuding-0','春日','宋雍','唐','御定全唐诗','yuding','','[]','輕花細葉滿林端，昨夜春風曉色寒。',32,'御定全唐詩/json/771.json','["輕花細葉滿林端，昨夜春風曉色寒。", "黃鳥不堪愁裏聽，綠楊宜向雨中看。"]'),
('yuding-1','失題','宋雍','唐','御定全唐诗','yuding','','[]','斜雨飛絲織晚風，疏簾半卷野亭空。',32,'御定全唐詩/json/771.json','["斜雨飛絲織晚風，疏簾半卷野亭空。", "荷花開盡秋光晚，零落殘紅綠沼中。"]'),
('yuding-2','古意','戴休珽','唐','御定全唐诗','yuding','','[]','窮秋朔風起，滄海愁陰漲。虜騎掠河南，漢兵屯灞上。',96,'御定全唐詩/json/771.json','["窮秋朔風起，滄海愁陰漲。虜騎掠河南，漢兵屯灞上。", "羽書驚沙漠，刁鬥喧亭障。關塞何蒼茫，遙烽遞相望。", "弱齡負奇節，俠客多招訪。投筆棄繻生，提戈逐飛將。", "拔劍照霜白，怒髮衝冠壯。會立萬里功，視君封侯相。"]'),
('yuding-3','勖曹生','盧鉟','唐','御定全唐诗','yuding','','[]','桑扈交飛百舌忙，祖亭聞樂倍思鄉。尊前有恨慚卑宦，',40,'御定全唐詩/json/771.json','["桑扈交飛百舌忙，祖亭聞樂倍思鄉。尊前有恨慚卑宦，", "遊蜂采掇何時已，只恐多言議短長。"]'),
('yuding-4','琴歌','趙摶','唐','御定全唐诗','yuding','','[]','綠琴制自桐孫枝，十年窗下無人知。清聲不與眾樂雜，',136,'御定全唐詩/json/771.json','["綠琴制自桐孫枝，十年窗下無人知。清聲不與眾樂雜，", "琴聲若似琵琶聲，賣與時人應已久。玉徽冷落無光彩，", "向曾守貧貧不徹，賤價與人人不別。前回忍淚卻收來，", "真龍不聖土龍聖，鳳凰啞舌鴟梟鳴。何殊此琴哀怨苦，", "知君立身待分義，驅喝風雷在平地。一生從事不因人，", "莫辭憔悴與買取，為君一曲號青春。"]'),
('yuding-5','廢長行','趙摶','唐','御定全唐诗','yuding','','[]','紫牙鏤合方如鬥，二十四星銜月口。貴人迷此華筵中，',72,'御定全唐詩/json/771.json','["紫牙鏤合方如鬥，二十四星銜月口。貴人迷此華筵中，", "門前有吏嚇孤窮，欲訴門深抱冤哭。耳厭人催坐衙早，", "何當化局為明鏡，掛在高堂辨邪正。何當化子作筆鋒，"]'),
('yuding-6','玉女詞','張安石','唐','御定全唐诗','yuding','','[]','綺薦銀屏空積塵，柳眉桃臉暗銷春。',32,'御定全唐詩/json/771.json','["綺薦銀屏空積塵，柳眉桃臉暗銷春。", "不須更學陽臺女，為雨為雲趁惱人。"]'),
('yuding-7','苦別','張安石','唐','御定全唐诗','yuding','','[]','向前不信別離苦，而今自到別離處。',32,'御定全唐詩/json/771.json','["向前不信別離苦，而今自到別離處。", "兩行粉淚紅闌幹，一朵芙蕖帶殘露。"]'),
('yuding-8','石城','蔣吉','唐','御定全唐诗','yuding','','[]','系纜石城下，恣吟懷暫開。江人橈艇子，將謂莫愁來。',24,'御定全唐詩/json/771.json','["系纜石城下，恣吟懷暫開。江人橈艇子，將謂莫愁來。"]'),
('yuding-9','漢東道中','蔣吉','唐','御定全唐诗','yuding','','[]','九十九岡遙，天寒雪未消。羸童牽瘦馬，不敢過危橋。',24,'御定全唐詩/json/771.json','["九十九岡遙，天寒雪未消。羸童牽瘦馬，不敢過危橋。"]'),
('yuding-10','高溪有懷','蔣吉','唐','御定全唐诗','yuding','','[]','駐馬高溪側，旅人千里情。雁山山下水，還作此泉聲。',24,'御定全唐詩/json/771.json','["駐馬高溪側，旅人千里情。雁山山下水，還作此泉聲。"]'),
('yuding-11','寄進士賈希','蔣吉','唐','御定全唐诗','yuding','','[]','恨苦淚不落，耿然東北心。空囊與瘦馬，羈絏意應深。',24,'御定全唐詩/json/771.json','["恨苦淚不落，耿然東北心。空囊與瘦馬，羈絏意應深。"]'),
('yuding-12','出塞','蔣吉','唐','御定全唐诗','yuding','','[]','瘦馬羸童行背秦，暮鴉撩亂入殘雲。',32,'御定全唐詩/json/771.json','["瘦馬羸童行背秦，暮鴉撩亂入殘雲。", "北風吹起寒營角，直至榆關人盡聞。"]'),
('yuding-13','旅泊','蔣吉','唐','御定全唐诗','yuding','','[]','霜月正高鸚鵡洲，美人清唱發紅樓。',32,'御定全唐詩/json/771.json','["霜月正高鸚鵡洲，美人清唱發紅樓。", "鄉心暗逐秋江水，直到吳山腳下流。"]'),
('yuding-14','次青雲驛','蔣吉','唐','御定全唐诗','yuding','','[]','馬轉櫟林山鳥飛，商溪流水背殘暉。',32,'御定全唐詩/json/771.json','["馬轉櫟林山鳥飛，商溪流水背殘暉。", "行人幾在青雲路，底事風塵猶滿衣。"]'),
('yuding-15','大庾驛有懷','蔣吉','唐','御定全唐诗','yuding','','[]','一囊書重百餘斤，郵吏甯知去計貧。',32,'御定全唐詩/json/771.json','["一囊書重百餘斤，郵吏甯知去計貧。", "莫訝偏吟望鄉句，明朝便見嶺南人。"]'),
('yuding-16','題商山修路僧院','蔣吉','唐','御定全唐诗','yuding','','[]','此地修行山幾枯，草堂生計只瓶盂。',32,'御定全唐詩/json/771.json','["此地修行山幾枯，草堂生計只瓶盂。", "支郎既解除艱險，試看人心平得無。"]'),
('yuding-17','題長安僧院','蔣吉','唐','御定全唐诗','yuding','','[]','出門爭走九衢塵，總是浮生不了身。',32,'御定全唐詩/json/771.json','["出門爭走九衢塵，總是浮生不了身。", "惟有水田衣下客，大家忙處作閒人。"]'),
('yuding-18','次商於感舊寄盧中丞','蔣吉','唐','御定全唐诗','yuding','','[]','昔年簪組隘丘門，今日旌幢一院存。',32,'御定全唐詩/json/771.json','["昔年簪組隘丘門，今日旌幢一院存。", "何事商於淚如雨，小儒偏受陸家恩。"]'),
('yuding-19','樵翁','蔣吉','唐','御定全唐诗','yuding','','[]','獨入深山信腳行，慣當貙虎不曾驚。',32,'御定全唐詩/json/771.json','["獨入深山信腳行，慣當貙虎不曾驚。", "路傍花發無心看，惟見枯枝刮眼明。"]'),
('yuding-20','四老廟','蔣吉','唐','御定全唐诗','yuding','','[]','無端舍釣學幹名，不得溪山養性情。',32,'御定全唐詩/json/771.json','["無端舍釣學幹名，不得溪山養性情。", "自省此身非達者，今朝羞拜四先生。"]'),
('yuding-21','昭君塚','蔣吉','唐','御定全唐诗','yuding','','[]','曾為漢帝眼中人，今作狂胡陌上塵。',32,'御定全唐詩/json/771.json','["曾為漢帝眼中人，今作狂胡陌上塵。", "身死不知多少載，塚花猶帶洛陽春。"]'),
('yuding-22','聞歌竹枝','蔣吉','唐','御定全唐诗','yuding','','[]','巡堤聽唱竹枝詞，正是月高風靜時。',32,'御定全唐詩/json/771.json','["巡堤聽唱竹枝詞，正是月高風靜時。", "獨向東南人不會，弟兄俱在楚江湄。"]'),
('yuding-23','重門曲','周濆','唐','御定全唐诗','yuding','','[]','憔悴容華怯對春，寂寥宮殿鎖閑門。',32,'御定全唐詩/json/771.json','["憔悴容華怯對春，寂寥宮殿鎖閑門。", "此身卻羨宮中樹，不失芳時雨露恩。"]'),
('yuding-24','山下水','周濆','唐','御定全唐诗','yuding','','[]','背雲沖石出深山，淺碧泠泠一帶寒。',32,'御定全唐詩/json/771.json','["背雲沖石出深山，淺碧泠泠一帶寒。", "不獨有聲流出此，會歸滄海助波瀾。"]'),
('yuding-25','逢鄰女','周濆','唐','御定全唐诗','yuding','','[]','日高鄰女笑相逢，慢束羅裙半露胸。',32,'御定全唐詩/json/771.json','["日高鄰女笑相逢，慢束羅裙半露胸。", "莫向秋池照綠水，參差羞殺白芙蓉。"]'),
('yuding-26','廢宅','周濆','唐','御定全唐诗','yuding','','[]','牢落畫堂空鎖塵，荒涼庭樹暗消春。',32,'御定全唐詩/json/771.json','["牢落畫堂空鎖塵，荒涼庭樹暗消春。", "豪家莫笑此中事，曾見此中人笑人。"]'),
('yuding-0','奉和登會昌山應制','趙起','唐','御定全唐诗','yuding','','[]','睿想入希夷，真遊到具茨。玉鸞登嶂遠，雲輅出花遲。',48,'御定全唐詩/json/772.json','["睿想入希夷，真遊到具茨。玉鸞登嶂遠，雲輅出花遲。", "泉壑凝神處，陽和布澤時。六龍多順動，四海正雍熙。"]'),
('yuding-1','冬日與群公泛舟焦山','王瓚','唐','御定全唐诗','yuding','','[]','江外水不凍，今年寒複遲。眾芳且未歇，近臘仍袷衣。',120,'御定全唐詩/json/772.json','["江外水不凍，今年寒複遲。眾芳且未歇，近臘仍袷衣。", "載酒適我情，興來趣漸微。方舟大川上，環酌對落暉。", "兩片青石棱，波際無因依。三山安可到，欲到風引歸。", "滄溟壯觀多，心目豁暫時。況得窮日夕，乘槎何所之。", "縱步不知遠，夕陽猶未回。好花隨處發，流水趁人來。"]'),
('yuding-2','度揭鴻嶺','慕容韋','唐','御定全唐诗','yuding','','[]','閩越曾為塞，將軍舊置營。我歌空感慨，西北望神京。',24,'御定全唐詩/json/772.json','["閩越曾為塞，將軍舊置營。我歌空感慨，西北望神京。"]'),
('yuding-3','湘江','黃文','唐','御定全唐诗','yuding','','[]','瀟湘江頭三月春，柳條弄日搖黃金。鷓鴣一聲在何許，',40,'御定全唐詩/json/772.json','["瀟湘江頭三月春，柳條弄日搖黃金。鷓鴣一聲在何許，", "馬蹄不為行客留，心掛長林屢回首。"]'),
('yuding-4','題龍陽縣青草湖','唐溫如','唐','御定全唐诗','yuding','','[]','西風吹老洞庭波，一夜湘君白髮多。',32,'御定全唐詩/json/772.json','["西風吹老洞庭波，一夜湘君白髮多。", "醉後不知天在水，滿船清夢壓星河。"]'),
('yuding-5','訾家洲','歐陽賓','唐','御定全唐诗','yuding','','[]','舊業分明桂水頭，人歸業盡水東流。',32,'御定全唐詩/json/772.json','["舊業分明桂水頭，人歸業盡水東流。", "春風日暮江頭立，不及漁人有釣舟。"]'),
('yuding-6','題吉州龍溪','何敬','唐','御定全唐诗','yuding','','[]','龍溪之山秀而峙，龍溪之水清無底。狂風激烈翻春濤，',40,'御定全唐詩/json/772.json','["龍溪之山秀而峙，龍溪之水清無底。狂風激烈翻春濤，", "四時佳境不可窮，仿佛直與桃源通。"]'),
('yuding-7','過睦州青溪渡','楊彝','唐','御定全唐诗','yuding','','[]','天闊銜江雨，冥冥上客衣。潭清魚可數，沙晚雁爭飛。',48,'御定全唐詩/json/772.json','["天闊銜江雨，冥冥上客衣。潭清魚可數，沙晚雁爭飛。", "川穀留雲氣，鵜鶘傍釣磯。飄零江海客，欹側一帆歸。"]'),
('yuding-8','闔閭城懷古','裴瑤','唐','御定全唐诗','yuding','','[]','五湖春水接遙天，國破君亡不記年。',32,'御定全唐詩/json/772.json','["五湖春水接遙天，國破君亡不記年。", "惟有妖娥曾舞處，古台寂寞起愁煙。"]'),
('yuding-9','葦谷','鄭玉','唐','御定全唐诗','yuding','','[]','水會三川漾碧波，雕陰人唱采花歌。',32,'御定全唐詩/json/772.json','["水會三川漾碧波，雕陰人唱采花歌。", "舊時白翟今荒壤，葦穀淒淒風雨多。"]'),
('yuding-10','登岳陽樓','麻溫其','唐','御定全唐诗','yuding','','[]','湖邊景物屬秋天，樓上風光似去年。仙侶緱生留福地，',40,'御定全唐詩/json/772.json','["湖邊景物屬秋天，樓上風光似去年。仙侶緱生留福地，", "極目江山何處是，一帆萬里信歸船。"]'),
('yuding-11','經望湖驛','韋鎰','唐','御定全唐诗','yuding','','[]','大漠無屯雲，孤峰出亂柳。前驅白登道，顧失飛狐口。',120,'御定全唐詩/json/772.json','["大漠無屯雲，孤峰出亂柳。前驅白登道，顧失飛狐口。", "遙憶代王城，俯臨恒山後。累累多古墓，寂寞為墟久。", "豈不固金湯，終聞擊銅鬥。交歡初仗信，接宴翻貽咎。", "埋寶賊夫人，磨笄傷彼婦。功成行且薄，義立名不朽。", "莫慎纖微端，其何社稷守。身歿國遂亡，此立人君醜。"]'),
('yuding-12','杪秋洞庭懷王道士','謝太虛','唐','御定全唐诗','yuding','','[]','漂泊日複日，洞庭今更秋。青桃亦何意，此夜催人愁。',96,'御定全唐詩/json/772.json','["漂泊日複日，洞庭今更秋。青桃亦何意，此夜催人愁。", "惆悵客中月，裴回江上樓。心知楚天遠，目送滄波流。", "謝客久已滅，微言無處求。空餘白雲在，客興隨孤舟。", "千里杳難盡，一身常獨遊。故園複何許，江漢徒遲留。"]'),
('yuding-13','君山祠','周岳秀','唐','御定全唐诗','yuding','','[]','萬頃湖波浸碧天，旌封香火幾千年。風濤澎湃魚龍舞，',40,'御定全唐詩/json/772.json','["萬頃湖波浸碧天，旌封香火幾千年。風濤澎湃魚龍舞，", "江河願借吹噓便，應有神功在目前。"]'),
('yuding-14','新樂府','馬逢','唐','御定全唐诗','yuding','','[]','溫穀春生至，宸游近甸榮。雲隨天上轉，風入禦筵輕。',48,'御定全唐詩/json/772.json','["溫穀春生至，宸游近甸榮。雲隨天上轉，風入禦筵輕。", "翠蓋浮佳氣，朱樓依太清。朝臣冠劍退，宮女管弦迎。"]'),
('yuding-15','部落曲','馬逢','唐','御定全唐诗','yuding','','[]','蕃軍傍塞游，代馬噴風秋。老將垂金甲，閼支著錦裘。',48,'御定全唐詩/json/772.json','["蕃軍傍塞游，代馬噴風秋。老將垂金甲，閼支著錦裘。", "雕戈蒙豹尾，紅旆插狼頭。日暮天山下，鳴笳漢使愁。"]'),
('yuding-16','從軍','馬逢','唐','御定全唐诗','yuding','','[]','漢馬千蹄合一群，單于鼓角隔山聞。',32,'御定全唐詩/json/772.json','["漢馬千蹄合一群，單于鼓角隔山聞。", "沙塠風起紅樓下，飛上胡天作陣雲。"]'),
('yuding-17','宮詞二首','馬逢','唐','御定全唐诗','yuding','','[]','金吾持戟護軒簷，天樂傳教萬姓瞻。',64,'御定全唐詩/json/772.json','["金吾持戟護軒簷，天樂傳教萬姓瞻。", "樓上美人相倚看，紅妝透出水晶簾。", "玉樓天半起笙歌，風送宮人笑語和。", "月影殿開聞曉漏，水晶簾卷近秋河。"]'),
('yuding-0','長門失寵','蕭意','唐','御定全唐诗','yuding','','[]','自從別鑾殿，長門幾度春。不知金屋裏，更貯若為人。',24,'御定全唐詩/json/773.json','["自從別鑾殿，長門幾度春。不知金屋裏，更貯若為人。"]'),
('yuding-1','下山逢故夫','徐之才','唐','御定全唐诗','yuding','','[]','踟躕下山婦，共申別離久。為問織縑人，何必長相守。',24,'御定全唐詩/json/773.json','["踟躕下山婦，共申別離久。為問織縑人，何必長相守。"]'),
('yuding-2','虜患','張陵','唐','御定全唐诗','yuding','','[]','今日漢家探使回，蟻疊胡兵來未歇。',32,'御定全唐詩/json/773.json','["今日漢家探使回，蟻疊胡兵來未歇。", "春風渭水不敢流，總作六軍心上血。"]'),
('yuding-3','夏日閨怨','蔡瑰','唐','御定全唐诗','yuding','','[]','桃徑李蹊絕芳園，炎氛熾日滿愁軒。枝上鳥驚朱槿落，',88,'御定全唐詩/json/773.json','["桃徑李蹊絕芳園，炎氛熾日滿愁軒。枝上鳥驚朱槿落，", "非關曾入楚王宮，直為相思腰轉細。臥簟乘閑乍逐涼，", "全由獨自羞看影，豔是孤眠疑夜永。無情拂鏡不成妝，", "但恐愁容不相識，為教恒著別時衣。"]'),
('yuding-4','詠破扇','唐怡','唐','御定全唐诗','yuding','','[]','輪如明月盡，羅似薄雲穿。無由重掩笑，分在秋風前。',24,'御定全唐詩/json/773.json','["輪如明月盡，羅似薄雲穿。無由重掩笑，分在秋風前。"]'),
('yuding-5','述懷','唐怡','唐','御定全唐诗','yuding','','[]','萬事皆零落，平生不可思。惟餘酒中趣，不減少年時。',24,'御定全唐詩/json/773.json','["萬事皆零落，平生不可思。惟餘酒中趣，不減少年時。"]'),
('yuding-6','詠燭寄人','潘求仁','唐','御定全唐诗','yuding','','[]','燭與人相似，通宵遽白煎。不應須下淚，只是為人然。',24,'御定全唐詩/json/773.json','["燭與人相似，通宵遽白煎。不應須下淚，只是為人然。"]'),
('yuding-7','薛王花燭行','閻德隱','唐','御定全唐诗','yuding','','[]','王子仙車下鳳台，紫纓金勒馭龍媒。□□□□□□出，',120,'御定全唐詩/json/773.json','["王子仙車下鳳台，紫纓金勒馭龍媒。□□□□□□出，", "玉盤錯落銀燈照，珠帳玲瓏寶扇開。盈盈二八誰家子，", "楚王宮裏能服飾，顧盼傾城複傾國。合歡錦帶蒲萄花，", "不學曹王遇神女，莫言羅敷邀使君。同心婉娩若琴瑟，", "富貴榮華實可憐，路傍觀者謂神仙。只應早得淮南術，"]'),
('yuding-8','三月歌','閻德隱','唐','御定全唐诗','yuding','','[]','洛陽城路九春衢，洛陽城外柳千株。',32,'御定全唐詩/json/773.json','["洛陽城路九春衢，洛陽城外柳千株。", "能得來時作眼覓，天津橋側錦屠蘇。"]'),
('yuding-9','妾薄命','劉元叔','唐','御定全唐诗','yuding','','[]','自從離別守空閨，遙聞征戰赴雲梯。夜夜思君遼海北，',96,'御定全唐詩/json/773.json','["自從離別守空閨，遙聞征戰赴雲梯。夜夜思君遼海北，", "彩鸞琴裏怨聲多，飛鵲鏡前妝梳斷。誰家夫婿不從征，", "旦逐新人殊未歸，還令秋至夜霜飛。北斗星前橫旅雁，", "暗啼羅帳空自憐，夢度陽關向誰說。每憐容貌宛如神，"]'),
('yuding-10','古別離','常理','唐','御定全唐诗','yuding','','[]','君禦狐白裘，妾居緗綺幬。粟鈿金夾膝，花錯玉搔頭。',72,'御定全唐詩/json/773.json','["君禦狐白裘，妾居緗綺幬。粟鈿金夾膝，花錯玉搔頭。", "離別生庭草，征衣斷戍樓。蠨蛸網清曙，菡萏落紅秋。", "小膽空房怯，長眉滿鏡愁。為傳兒女意，不用遠封侯。"]'),
('yuding-11','妾薄命','常理','唐','御定全唐诗','yuding','','[]','十五玉童色，雙蛾青彎彎。鳥銜櫻桃花，此時刺繡閑。',68,'御定全唐詩/json/773.json','["十五玉童色，雙蛾青彎彎。鳥銜櫻桃花，此時刺繡閑。", "嬌小恣所愛，誤人金指環。豔花句引落，滅燭屏風關。", "妾怕愁中畫，君偷薄裏還。初謂來心平若案，"]'),
('yuding-12','虞姬怨','馮待征','唐','御定全唐诗','yuding','','[]','妾本江南採蓮女，君是江東學劍人。逢君遊俠英雄日，',120,'御定全唐詩/json/773.json','["妾本江南採蓮女，君是江東學劍人。逢君遊俠英雄日，", "行逢楚漢正相持，辭家上馬從君起。歲歲年年事征戰，", "相期相許定關中，鳴鑾鳴佩入秦宮。誰誤四面楚歌起，", "澤中馬力先戰疲，帳下蛾眉□□□。君王是日無神彩，", "終天隔地與君辭，恨似流波無息時。使妾本來不相識，"]'),
('yuding-13','越溪怨','冷朝光','唐','御定全唐诗','yuding','','[]','越王宮裏如花人，越水溪頭采白蘋。白蘋未盡人先盡，誰見江南春複春。',32,'御定全唐詩/json/773.json','["越王宮裏如花人，越水溪頭采白蘋。白蘋未盡人先盡，誰見江南春複春。"]'),
('yuding-14','吳宮怨','衛萬','唐','御定全唐诗','yuding','','[]','君不見吳王宮閣臨江起，不見珠簾見江水。',43,'御定全唐詩/json/773.json','["君不見吳王宮閣臨江起，不見珠簾見江水。", "曉氣晴來雙闕間，潮聲夜落千門裏。句踐城中非舊春，"]'),
('yuding-15','春遊吟','李章','唐','御定全唐诗','yuding','','[]','初春遍芳甸，十裏藹盈矚。美人摘新英，步步玩春綠。',44,'御定全唐詩/json/773.json','["初春遍芳甸，十裏藹盈矚。美人摘新英，步步玩春綠。", "所思杳何處，宛在吳江曲。可憐不得共芳菲，"]'),
('yuding-16','婕妤怨','王沈','唐','御定全唐诗','yuding','','[]','長信梨花暗欲棲，應門上鑰草萋萋。',32,'御定全唐詩/json/773.json','["長信梨花暗欲棲，應門上鑰草萋萋。", "春風吹花亂撲戶，班絕車聲不至啼。"]'),
('yuding-17','夜夜曲','王偃','唐','御定全唐诗','yuding','','[]','北斗星移銀漢低，班姬愁思鳳城西。',32,'御定全唐詩/json/773.json','["北斗星移銀漢低，班姬愁思鳳城西。", "青槐陌上行人絕，明月樓前烏夜啼。"]'),
('yuding-18','明君詞','王偃','唐','御定全唐诗','yuding','','[]','北望單于日半斜，明君馬上泣胡沙。',32,'御定全唐詩/json/773.json','["北望單于日半斜，明君馬上泣胡沙。", "一雙淚滴黃河水，應得東流入漢家。"]'),
('yuding-19','擬古東飛伯勞歌','李暇','唐','御定全唐诗','yuding','','[]','秦王龍劍燕後琴，珊瑚寶匣鏤雙心。誰家女兒抱香枕，',48,'御定全唐詩/json/773.json','["秦王龍劍燕後琴，珊瑚寶匣鏤雙心。誰家女兒抱香枕，", "青綺幃中坐相憶，紅鸞鏡裏見愁色。簷花照月鶯對棲，"]'),
('yuding-20','怨詩三首','李暇','唐','御定全唐诗','yuding','','[]','羅敷初總髻，蕙芳正嬌小。月落始歸船，春眠恒著曉。',72,'御定全唐詩/json/773.json','["羅敷初總髻，蕙芳正嬌小。月落始歸船，春眠恒著曉。", "何處期郎游，小苑花台間。相憶不可見，且複乘月還。", "別前花照路，別後露垂葉。歌舞須及時，如何坐悲妾。"]'),
('yuding-21','碧玉歌','李暇','唐','御定全唐诗','yuding','','[]','碧玉上官妓，出入千花林。珠被玳瑁床，感郎情意深。',24,'御定全唐詩/json/773.json','["碧玉上官妓，出入千花林。珠被玳瑁床，感郎情意深。"]'),
('yuding-22','見美人聞琴不聽','李播','唐','御定全唐诗','yuding','','[]','洛浦風流雪，陽臺朝暮雲。聞琴不肯聽，似妒卓文君。',24,'御定全唐詩/json/773.json','["洛浦風流雪，陽臺朝暮雲。聞琴不肯聽，似妒卓文君。"]'),
('yuding-23','賦詩','辛弘智','唐','御定全唐诗','yuding','','[]','君為河邊草，逢春心剩生。妾如臺上鏡，得照始分明。',24,'御定全唐詩/json/773.json','["君為河邊草，逢春心剩生。妾如臺上鏡，得照始分明。"]'),
('yuding-24','自君之出矣','辛弘智','唐','御定全唐诗','yuding','','[]','自君之出矣，梁塵靜不飛。思君如滿月，夜夜減容輝。',24,'御定全唐詩/json/773.json','["自君之出矣，梁塵靜不飛。思君如滿月，夜夜減容輝。"]'),
('yuding-25','自君之出矣','辛弘智','唐','御定全唐诗','yuding','','[]','自君之出矣，寶鏡為誰明。思君如隴水，常聞嗚咽聲。',24,'御定全唐詩/json/773.json','["自君之出矣，寶鏡為誰明。思君如隴水，常聞嗚咽聲。"]'),
('yuding-0','題春夢秋歸故里','吉師老','唐','御定全唐诗','yuding','','[]','故國歸路賒，春晚在天涯。明月夜來夢，碧山秋到家。',48,'御定全唐詩/json/774.json','["故國歸路賒，春晚在天涯。明月夜來夢，碧山秋到家。", "開窗聞落葉，遠墅見晴鴉。驚起曉庭際，鶯啼桃杏花。"]'),
('yuding-1','看蜀女轉昭君變','吉師老','唐','御定全唐诗','yuding','','[]','妖姬未著石榴裙，自道家連錦水濆。檀口解知千載事，',40,'御定全唐詩/json/774.json','["妖姬未著石榴裙，自道家連錦水濆。檀口解知千載事，", "說盡綺羅當日恨，昭君傳意向文君。"]'),
('yuding-2','放猿','吉師老','唐','御定全唐诗','yuding','','[]','放爾千山萬水身，野泉晴樹好為鄰。',32,'御定全唐詩/json/774.json','["放爾千山萬水身，野泉晴樹好為鄰。", "啼時莫近瀟湘岸，明月孤舟有旅人。"]'),
('yuding-3','鴛鴦','吉師老','唐','御定全唐诗','yuding','','[]','江島濛濛煙靄微，綠蕪深處刷毛衣。',32,'御定全唐詩/json/774.json','["江島濛濛煙靄微，綠蕪深處刷毛衣。", "渡頭驚起一雙去，飛上文君舊錦機。"]'),
('yuding-4','巫峽聽猿','吳商浩','唐','御定全唐诗','yuding','','[]','巴江猿嘯苦，響入客舟中。孤枕破殘夢，三聲隨曉風。',48,'御定全唐詩/json/774.json','["巴江猿嘯苦，響入客舟中。孤枕破殘夢，三聲隨曉風。", "連雲波澹澹，和霧雨濛濛。巫峽去家遠，不堪魂斷空。"]'),
('yuding-5','長安春贈友人','吳商浩','唐','御定全唐诗','yuding','','[]','繁華堪泣帝城春，粉堞青樓勢礙雲。花對玉鉤簾外發，',40,'御定全唐詩/json/774.json','["繁華堪泣帝城春，粉堞青樓勢礙雲。花對玉鉤簾外發，", "各有歸程千萬里，東風時節恨離群。"]'),
('yuding-6','塞上即事','吳商浩','唐','御定全唐诗','yuding','','[]','身似星流跡似蓬，玉關孤望杳溟蒙。寒沙萬里平鋪月，',40,'御定全唐詩/json/774.json','["身似星流跡似蓬，玉關孤望杳溟蒙。寒沙萬里平鋪月，", "分明更想殘宵夢，故國依然在甬東。"]'),
('yuding-7','宿山驛','吳商浩','唐','御定全唐诗','yuding','','[]','文戰何堪功未圖，又驅羸馬指天衢。露華凝夜渚蓮盡，',40,'御定全唐詩/json/774.json','["文戰何堪功未圖，又驅羸馬指天衢。露華凝夜渚蓮盡，", "好同範蠡扁舟興，高掛一帆歸五湖。"]'),
('yuding-8','北邙山','吳商浩','唐','御定全唐诗','yuding','','[]','北邙山草又青青，今日銷魂事可明。綠酒醉來春未歇，',40,'御定全唐詩/json/774.json','["北邙山草又青青，今日銷魂事可明。綠酒醉來春未歇，", "堪取金爐九還藥，不能隨夢向浮生。"]'),
('yuding-9','秋塘曉望','吳商浩','唐','御定全唐诗','yuding','','[]','鐘盡疏桐散曙鴉，故山煙樹隔天涯。',32,'御定全唐詩/json/774.json','["鐘盡疏桐散曙鴉，故山煙樹隔天涯。", "西風一夜秋塘曉，零落幾多紅藕花。"]'),
('yuding-10','水樓感事','吳商浩','唐','御定全唐诗','yuding','','[]','高柳螿啼雨後秋，年光空感淚如流。',32,'御定全唐詩/json/774.json','["高柳螿啼雨後秋，年光空感淚如流。", "滿湖菱荇東歸晚，閑倚南軒盡日愁。"]'),
('yuding-11','泊舟','吳商浩','唐','御定全唐诗','yuding','','[]','身逐煙波魂自驚，木蘭舟上一帆輕。',32,'御定全唐詩/json/774.json','["身逐煙波魂自驚，木蘭舟上一帆輕。", "雲中有寺在何處，山底宿時聞磬聲。"]'),
('yuding-12','湘雲','吳商浩','唐','御定全唐诗','yuding','','[]','□滿湘江雲瑩空，紛紛長對水溶溶。',32,'御定全唐詩/json/774.json','["□滿湘江雲瑩空，紛紛長對水溶溶。", "日西遙望自歸處，盡掛九疑千萬峰。"]'),
('yuding-13','秋閨','沈祖仙','唐','御定全唐诗','yuding','','[]','白馬三軍客，青娥十載思。玉庭霜落夜，羅幌月明時。',48,'御定全唐詩/json/774.json','["白馬三軍客，青娥十載思。玉庭霜落夜，羅幌月明時。", "爐冷蜘蛛喜，燈高熠耀期。愁多不可曙，流涕坐空幃。"]'),
('yuding-14','秋閨','邵士彥','唐','御定全唐诗','yuding','','[]','斜日空庭暮，幽閨積恨盈。細風吹帳冷，微月度窗明。',48,'御定全唐詩/json/774.json','["斜日空庭暮，幽閨積恨盈。細風吹帳冷，微月度窗明。", "怨坐啼相續，愁眠夢不成。調琴欲有弄，畏作斷腸聲。"]'),
('yuding-15','擣衣','吳大江','唐','御定全唐诗','yuding','','[]','沙塞秋應晚，金閨恨已空。那堪裂紈素，時許出房櫳。',48,'御定全唐詩/json/774.json','["沙塞秋應晚，金閨恨已空。那堪裂紈素，時許出房櫳。", "杵影弄寒月，砧聲調夜風。裁縫雙淚盡，萬里寄雲中。"]'),
('yuding-16','題慈恩塔','荊叔','唐','御定全唐诗','yuding','','[]','漢國山河在，秦陵草樹深。暮雲千里色，無處不傷心。',24,'御定全唐詩/json/774.json','["漢國山河在，秦陵草樹深。暮雲千里色，無處不傷心。"]'),
('yuding-17','三湘有懷','蕭靜','唐','御定全唐诗','yuding','','[]','柳絮飛來別洛陽，梅花落後到三湘。',32,'御定全唐詩/json/774.json','["柳絮飛來別洛陽，梅花落後到三湘。", "世情已逐浮雲散，離恨空隨江水長。"]'),
('yuding-18','九日對酒','元凜','唐','御定全唐诗','yuding','','[]','嘉辰複遇登高台，良朋笑語傾金罍。煙攤秋色正堪玩，',40,'御定全唐詩/json/774.json','["嘉辰複遇登高台，良朋笑語傾金罍。煙攤秋色正堪玩，", "誰知靖節當時事，空學狂歌倒載回。"]'),
('yuding-19','中秋夜不見月','元凜','唐','御定全唐诗','yuding','','[]','蟾輪何事色全微，賺得佳人出繡幃。四野霧凝空寂寞，',40,'御定全唐詩/json/774.json','["蟾輪何事色全微，賺得佳人出繡幃。四野霧凝空寂寞，", "公子倚欄猶悵望，懶將紅燭草堂歸。"]'),
('yuding-20','雷塘','徐振','唐','御定全唐诗','yuding','','[]','九重城闕悲涼盡，一聚園林怨恨長。花憶所為猶自笑，',40,'御定全唐詩/json/774.json','["九重城闕悲涼盡，一聚園林怨恨長。花憶所為猶自笑，", "若問皇天惆悵事，只應斜日照雷塘。"]'),
('yuding-21','古意','徐振','唐','御定全唐诗','yuding','','[]','擾擾都城曉又昏，六街車馬五侯門。',32,'御定全唐詩/json/774.json','["擾擾都城曉又昏，六街車馬五侯門。", "箕山渭水空明月，可是巢由絕子孫。"]'),
('yuding-22','寄人','張侹','唐','御定全唐诗','yuding','','[]','酷憐風月為多情，還到春時別恨生。',32,'御定全唐詩/json/774.json','["酷憐風月為多情，還到春時別恨生。", "倚柱尋思倍惆悵，一場春夢不分明。"]'),
('yuding-23','武昌阻風','方澤','唐','御定全唐诗','yuding','','[]','江上春風留客舟，無窮歸思滿東流。',32,'御定全唐詩/json/774.json','["江上春風留客舟，無窮歸思滿東流。", "與君盡日閑臨水，貪看飛花忘卻愁。"]'),
('yuding-24','秋夜宿淮口','景池','唐','御定全唐诗','yuding','','[]','露白草猶青，淮舟倚岸停。風帆幾處客，天地兩河星。',48,'御定全唐詩/json/774.json','["露白草猶青，淮舟倚岸停。風帆幾處客，天地兩河星。", "樹靜禽眠草，沙寒鹿過汀。明朝誰結伴，直去泛滄溟。"]'),
('yuding-25','贈喬尊師','張鴻','唐','御定全唐诗','yuding','','[]','長忌時人識，有家雲澗深。性惟耽嗜酒，貧不破除琴。',48,'御定全唐詩/json/774.json','["長忌時人識，有家雲澗深。性惟耽嗜酒，貧不破除琴。", "靜鼓三通齒，頻湯一味參。知師最知我，相引坐檉陰。"]'),
('yuding-26','村行','姚揆','唐','御定全唐诗','yuding','','[]','天淡雨初晴，遊人恨不勝。亂山啼蜀魄，孤棹宿巴陵。',48,'御定全唐詩/json/774.json','["天淡雨初晴，遊人恨不勝。亂山啼蜀魄，孤棹宿巴陵。", "影暗村橋柳，光寒水寺燈。罷吟思故國，窗外有漁罾。"]'),
('yuding-27','潁川客舍','姚揆','唐','御定全唐诗','yuding','','[]','素琴孤劍尚閒遊，誰共芳尊話唱酬。鄉夢有時生枕上，',40,'御定全唐詩/json/774.json','["素琴孤劍尚閒遊，誰共芳尊話唱酬。鄉夢有時生枕上，", "回首帝京歸未得，不堪吟倚夕陽樓。"]'),
('yuding-28','獨不見','王訓','唐','御定全唐诗','yuding','','[]','日晚宜春暮，風軟上林朝。對酒近初節，開樓蕩夜謠。',48,'御定全唐詩/json/774.json','["日晚宜春暮，風軟上林朝。對酒近初節，開樓蕩夜謠。", "石橋通小澗，竹路上青霄。持底誰見許，長愁成細腰。"]'),
('yuding-29','歸去來引','張熾','唐','御定全唐诗','yuding','','[]','歸去來，歸期不可違。相見旋明月，浮雲共我歸。',22,'御定全唐詩/json/774.json','["歸去來，歸期不可違。相見旋明月，浮雲共我歸。"]'),
('yuding-30','結客少年場行','虞羽客','唐','御定全唐诗','yuding','','[]','幽並俠少年，金絡控連錢。竊符方救趙，擊築正懷燕。',120,'御定全唐詩/json/774.json','["幽並俠少年，金絡控連錢。竊符方救趙，擊築正懷燕。", "輕生辭鳳闕，揮袂上祁連。陸離橫寶劍，出沒騖征旃。", "蒙輪恒顧敵，超乘忽爭先。摧枯逾百戰，拓地遠三千。", "骨都魂已散，樓蘭首複傳。龍城含宿霧，瀚海接遙天。", "歌吹金微返，振旅玉門旋。烽火今已息，非複照甘泉。"]'),
('yuding-31','塞上','鄭渥','唐','御定全唐诗','yuding','','[]','出門何處問西東，指畫翻為語論同。到此客頭潛覺白，',40,'御定全唐詩/json/774.json','["出門何處問西東，指畫翻為語論同。到此客頭潛覺白，", "早晚回鞭複南去，大衣高蓋漢鄉風。"]'),
('yuding-32','洛陽道','鄭渥','唐','御定全唐诗','yuding','','[]','客亭門外路東西，多少喧騰事不齊。楊柳惹鞭公子醉，',40,'御定全唐詩/json/774.json','["客亭門外路東西，多少喧騰事不齊。楊柳惹鞭公子醉，", "頃刻知音幾存歿，半回依約認輪蹄。"]'),
('yuding-0','宜春郡城聞猿','崔江','唐','御定全唐诗','yuding','','[]','怨抱霜枝向月啼，數聲清繞郡城低。',32,'御定全唐詩/json/775.json','["怨抱霜枝向月啼，數聲清繞郡城低。", "那堪日夜有雲雨，便似巫山與建溪。"]'),
('yuding-1','謫宜陽到荊渚','李伉','唐','御定全唐诗','yuding','','[]','漢江江水水連天，被謫宜陽路幾千。',32,'御定全唐詩/json/775.json','["漢江江水水連天，被謫宜陽路幾千。", "為問野人山鳥語，問予歸棹是何年。"]'),
('yuding-2','九嶷山','劉望','唐','御定全唐诗','yuding','','[]','鼎湖冠劍有遺蹤，晉漢真人羽化同。九轉藥成丹灶冷，',40,'御定全唐詩/json/775.json','["鼎湖冠劍有遺蹤，晉漢真人羽化同。九轉藥成丹灶冷，", "徒有舊山流水畔，老松枝葉苦吟風。"]'),
('yuding-3','郡城放猿獻衛使君','易思','唐','御定全唐诗','yuding','','[]','千岩萬壑與雲連，放出雕籠任自然。葉灑驚風啼暮雨，',40,'御定全唐詩/json/775.json','["千岩萬壑與雲連，放出雕籠任自然。葉灑驚風啼暮雨，", "應解感恩尋太守，攀蘿時複到樓前。"]'),
('yuding-4','題袁州龍興寺','易思','唐','御定全唐诗','yuding','','[]','百尺古松松下寺，寶幡朱蓋畫珊珊。',32,'御定全唐詩/json/775.json','["百尺古松松下寺，寶幡朱蓋畫珊珊。", "閒庭甘露幾回落，青石綠苔猶未幹。"]'),
('yuding-5','山中送弟方質','易思','唐','御定全唐诗','yuding','','[]','山中殷勤弟別兄，兄還送弟下山行。',32,'御定全唐詩/json/775.json','["山中殷勤弟別兄，兄還送弟下山行。", "蘆花飛處秋風起，日暮不堪聞雁聲。"]'),
('yuding-6','尋易尊師不遇','易思','唐','御定全唐诗','yuding','','[]','爛熳紅霞光照衣，苔封白石路微微。',32,'御定全唐詩/json/775.json','["爛熳紅霞光照衣，苔封白石路微微。", "華陽洞裏人何在，落盡松花不見歸。"]'),
('yuding-7','秋日寄弟','趙防','唐','御定全唐诗','yuding','','[]','涼風颯庭戶，漸疑華髮侵。已經楊柳謝，猶聽蟪蛄吟。',48,'御定全唐詩/json/775.json','["涼風颯庭戶，漸疑華髮侵。已經楊柳謝，猶聽蟪蛄吟。", "雨助灘聲出，雲連野色深。鶺鴒今在遠，年酒共誰斟。"]'),
('yuding-8','楊岐山','劉廓','唐','御定全唐诗','yuding','','[]','千峰圍古寺，深處敞樓臺。景異尋常處，人須特達來。',48,'御定全唐詩/json/775.json','["千峰圍古寺，深處敞樓臺。景異尋常處，人須特達來。", "松杉寒更茂，嵐靄晝還開。欲續豐碑語，含毫恨不才。"]'),
('yuding-9','南源山','姚偓','唐','御定全唐诗','yuding','','[]','修徑投幽隱，輕裘怯暮寒。閑僧能解榻，倦客得休鞍。',48,'御定全唐詩/json/775.json','["修徑投幽隱，輕裘怯暮寒。閑僧能解榻，倦客得休鞍。", "白雨鳴山麓，青燈語夜闌。明朝梯石路，更仗筍輿安。"]'),
('yuding-10','下第夜吟','戴衢','唐','御定全唐诗','yuding','','[]','擾擾東西南北情，何人於此悟浮生。',32,'御定全唐詩/json/775.json','["擾擾東西南北情，何人於此悟浮生。", "還緣無月春風夜，暫得獨聞流水聲。"]'),
('yuding-11','句','戴衢','唐','御定全唐诗','yuding','','[]','坐落千門日，吟殘午夜燈。',12,'御定全唐詩/json/775.json','["坐落千門日，吟殘午夜燈。"]'),
('yuding-12','詠月','李建樞','唐','御定全唐诗','yuding','','[]','昨夜圓非今夜圓，卻疑圓處減嬋娟。',32,'御定全唐詩/json/775.json','["昨夜圓非今夜圓，卻疑圓處減嬋娟。", "一年十二度圓缺，能得幾多時少年。"]'),
('yuding-13','謝人惠琴材','謝邈','唐','御定全唐诗','yuding','','[]','風撼桐絲帶月明，羽人乘醉截秋聲。七弦妙制饒仙品，',40,'御定全唐詩/json/775.json','["風撼桐絲帶月明，羽人乘醉截秋聲。七弦妙制饒仙品，", "何因乞與元中術，臨化無妨膝上橫。"]'),
('yuding-14','謝僧寄拄杖','謝邈','唐','御定全唐诗','yuding','','[]','峭壁猿啼采處深，一枝奇異出孤岑。感師千里寄來意，',40,'御定全唐詩/json/775.json','["峭壁猿啼采處深，一枝奇異出孤岑。感師千里寄來意，", "他年必藉相攜力，蹇步猶能返故林。"]'),
('yuding-15','失題二首','唐備','唐','御定全唐诗','yuding','','[]','天若無雪霜，青松不如草。地若無山川，何人重平道。',48,'御定全唐詩/json/775.json','["天若無雪霜，青松不如草。地若無山川，何人重平道。", "一日天無風，四溟波盡息。人心風不吹，波浪高百尺。"]'),
('yuding-16','道傍木','唐備','唐','御定全唐诗','yuding','','[]','狂風拔倒樹，樹倒根已露。上有數枝藤，青青猶未悟。',24,'御定全唐詩/json/775.json','["狂風拔倒樹，樹倒根已露。上有數枝藤，青青猶未悟。"]'),
('yuding-17','失題','方棫','唐','御定全唐诗','yuding','','[]','午醉醒來晚，無人夢自驚。夕陽如有意，長傍小窗明。',24,'御定全唐詩/json/775.json','["午醉醒來晚，無人夢自驚。夕陽如有意，長傍小窗明。"]'),
('yuding-18','失題','範夜','唐','御定全唐诗','yuding','','[]','舉意三江竭，興心四海枯。南游李邕死，北望宋珪殂。',24,'御定全唐詩/json/775.json','["舉意三江竭，興心四海枯。南游李邕死，北望宋珪殂。"]'),
('yuding-19','失題','盧群玉','唐','御定全唐诗','yuding','','[]','酒瀉銀瓶倒底清，夜深絲竹鳳凰鳴。',32,'御定全唐詩/json/775.json','["酒瀉銀瓶倒底清，夜深絲竹鳳凰鳴。", "紅妝醉起一花落，更引春風無限情。"]'),
('yuding-20','投盧尚書','盧群玉','唐','御定全唐诗','yuding','','[]','無力不任為走役，有文安敢滯清平。',32,'御定全唐詩/json/775.json','["無力不任為走役，有文安敢滯清平。", "從來若把耕桑定，免恃雕蟲誤此生。"]'),
('yuding-21','失題二首','楊行敏','唐','御定全唐诗','yuding','','[]','駑駘嘶叫知無定，騏驥低垂自有心。',64,'御定全唐詩/json/775.json','["駑駘嘶叫知無定，騏驥低垂自有心。", "山上高松溪畔竹，清風才動是知音。", "杜鵑花裏杜鵑啼，淺紫深紅更傍溪。", "遲日霽光搜客思，曉來山路恨如迷。"]'),
('yuding-22','吳江別王長史','張懷','唐','御定全唐诗','yuding','','[]','多年襆被玉山岑，鬢雪欺人忽滿簪。駑馬雖然貪短豆，',40,'御定全唐詩/json/775.json','["多年襆被玉山岑，鬢雪欺人忽滿簪。駑馬雖然貪短豆，", "見說新橋好風景，會須乘月濯煩襟。"]'),
('yuding-23','題天臺石橋','趙湘','唐','御定全唐诗','yuding','','[]','白石峰猶在，橫橋一徑微。多年無客過，落日有雲歸。',48,'御定全唐詩/json/775.json','["白石峰猶在，橫橋一徑微。多年無客過，落日有雲歸。", "水淨苔生髮，山寒樹著衣。如何方廣寺，千古去人稀。"]'),
('yuding-24','寄朗陵兄','楊持','唐','御定全唐诗','yuding','','[]','刺舉官猶屈，風謠政已成。行看換龜組，奏最謁承明。',24,'御定全唐詩/json/775.json','["刺舉官猶屈，風謠政已成。行看換龜組，奏最謁承明。"]'),
('yuding-25','詠dD溪在曆陽西一裏','李聰','唐','御定全唐诗','yuding','','[]','泠泠一帶清溪水，遠派□通曆陽市。',32,'御定全唐詩/json/775.json','["泠泠一帶清溪水，遠派□通曆陽市。", "涓涓出自碧湖中，流入楚江煙霧裏。"]'),
('yuding-26','耒陽杜工部祠堂','徐介','唐','御定全唐诗','yuding','','[]','手接汨羅水，天心知所存。固教工部死，來伴大夫魂。',48,'御定全唐詩/json/775.json','["手接汨羅水，天心知所存。固教工部死，來伴大夫魂。", "流落同千古，風騷共一源。消凝傷往事，斜日隱頹垣。"]'),
('yuding-27','登單于台','李士元','唐','御定全唐诗','yuding','','[]','悔上層樓望，翻成極目愁。路沿蔥嶺去，河背玉關流。',48,'御定全唐詩/json/775.json','["悔上層樓望，翻成極目愁。路沿蔥嶺去，河背玉關流。", "馬散眠沙磧，兵閑倚戍樓。殘陽三會角，吹白旅人頭。"]'),
('yuding-28','登閣','李士元','唐','御定全唐诗','yuding','','[]','亂後獨來登大閣，憑闌舉目盡傷心。長堤過雨人行少，',40,'御定全唐詩/json/775.json','["亂後獨來登大閣，憑闌舉目盡傷心。長堤過雨人行少，", "總輸釋氏青蓮館，依舊重重布地金。"]'),
('yuding-0','山中作','馮道之','唐','御定全唐诗','yuding','','[]','草堂在岩下，卜居聊自適。桂氣滿階庭，松陰生枕席。',72,'御定全唐詩/json/776.json','["草堂在岩下，卜居聊自適。桂氣滿階庭，松陰生枕席。", "遠瞻惟鳥度，旁信無人跡。靄靄雲生峰，潺潺水流石。", "頗尋黃卷理，庶就丹砂益。此即契吾生，何為苦塵役。"]'),
('yuding-1','短歌二首','徐謙','唐','御定全唐诗','yuding','','[]','窮通皆是運，榮辱豈關身。不願門前客，看時逢故人。',48,'御定全唐詩/json/776.json','["窮通皆是運，榮辱豈關身。不願門前客，看時逢故人。", "意氣青雲裏，爽朗煙霞外。不羨一囊錢，唯重心襟會。"]'),
('yuding-2','塞下曲','楊達','唐','御定全唐诗','yuding','','[]','秋日並州路，黃榆落故關。孤城吹角罷，數騎射雕還。',48,'御定全唐詩/json/776.json','["秋日並州路，黃榆落故關。孤城吹角罷，數騎射雕還。", "帳幕遙臨水，牛羊自下山。行人正垂淚，烽火起雲間。"]'),
('yuding-3','明妃怨','楊達','唐','御定全唐诗','yuding','','[]','漢國明妃去不還，馬駝弦管向陰山。',32,'御定全唐詩/json/776.json','["漢國明妃去不還，馬駝弦管向陰山。", "匣中縱有菱花鏡，羞對單于照舊顏。"]'),
('yuding-4','送鄒尊師歸洞庭','楊逵','唐','御定全唐诗','yuding','','[]','眾島在波心，曾居舊隱林。近聞飛檄急，轉憶臥雲深。',48,'御定全唐詩/json/776.json','["眾島在波心，曾居舊隱林。近聞飛檄急，轉憶臥雲深。", "賣藥唯供酒，歸舟只載琴。遙知明月夜，坐石自開襟。"]'),
('yuding-5','送張兵曹赴營田','魏兼恕','唐','御定全唐诗','yuding','','[]','河曲今無戰，王師每務農。選才當重委，足食乃深功。',48,'御定全唐詩/json/776.json','["河曲今無戰，王師每務農。選才當重委，足食乃深功。", "草色孤城外，雲陰絕漠中。蕭關休歎別，歸望在乘驄。"]'),
('yuding-6','晚霽登汝南大雲閣','賈彥璋','唐','御定全唐诗','yuding','','[]','禪宮新歇雨，香閣晚登臨。邑樹晴光起，川苗佳氣深。',48,'御定全唐詩/json/776.json','["禪宮新歇雨，香閣晚登臨。邑樹晴光起，川苗佳氣深。", "水包城下岸，雲細郢中岑。自歎牽卑日，聊開望遠心。"]'),
('yuding-7','宿香山閣','賈彥璋','唐','御定全唐诗','yuding','','[]','暝望香山閣，梯雲宿半空。軒窗閉潮海，枕席拂煙虹。',48,'御定全唐詩/json/776.json','["暝望香山閣，梯雲宿半空。軒窗閉潮海，枕席拂煙虹。", "朱網防棲鴿，紗燈護夕蟲。一聞雞唱曉，已見日曈曈。"]'),
('yuding-8','蘇著作山池','賈彥璋','唐','御定全唐诗','yuding','','[]','水樹子雲家，峰瀛宛不賒。芥浮舟是葉，蓮發岫為花。',48,'御定全唐詩/json/776.json','["水樹子雲家，峰瀛宛不賒。芥浮舟是葉，蓮發岫為花。", "酌蟻開春甕，觀魚憑海查。游蘇多石友，題贈滿瑤華。"]'),
('yuding-9','王龍驤墓','賈彥璋','唐','御定全唐诗','yuding','','[]','昔擅登壇寵，爰光典午朝。刀懸臨益夢，龍啟渡江謠。',48,'御定全唐詩/json/776.json','["昔擅登壇寵，爰光典午朝。刀懸臨益夢，龍啟渡江謠。", "茂績當年舉，英魂此地銷。唯餘孤壟上，日夕起松飆。"]'),
('yuding-10','折楊柳','歐陽瑾','唐','御定全唐诗','yuding','','[]','垂柳拂妝台，葳蕤葉半開。年華枝上見，邊思曲中來。',48,'御定全唐詩/json/776.json','["垂柳拂妝台，葳蕤葉半開。年華枝上見，邊思曲中來。", "嫩色宜新雨，輕花伴落梅。朝朝倦攀折，征戍幾時回。"]'),
('yuding-11','江南曲','李叔卿','唐','御定全唐诗','yuding','','[]','湖上女，江南花，無雙越女春浣紗。風似箭，月如弦，',64,'御定全唐詩/json/776.json','["湖上女，江南花，無雙越女春浣紗。風似箭，月如弦，", "菱歌思欲絕，楚舞斷人腸。歌舞未終涕雙隕，", "渡口水流緩，妾歸宵剩遲。含情為君再理曲，"]'),
('yuding-12','芳樹','李叔卿','唐','御定全唐诗','yuding','','[]','春看玫瑰樹，西鄰即宋家。門深重暗葉，牆近度飛花。',48,'御定全唐詩/json/776.json','["春看玫瑰樹，西鄰即宋家。門深重暗葉，牆近度飛花。", "影拂桃陰淺，香傳李徑斜。靚妝愁日暮，流涕向窗紗。"]'),
('yuding-13','送楊諫議赴河西節度判官兼呈韓王二侍禦','熊曜','唐','御定全唐诗','yuding','','[]','賢哉征西將，幕府多俊人。籌議秉刀尺，話言在經綸。',108,'御定全唐詩/json/776.json','["賢哉征西將，幕府多俊人。籌議秉刀尺，話言在經綸。", "先鞭羨之子，走馬辭咸秦。庭論許名實，數公當即真。", "行行弄文翰，婉婉光使臣。今者所從誰，不聞歌苦辛。", "黃雲蕭關道，白日驚沙塵。虜寇有時獵，漢兵行複巡。", "王師已無戰，傳檄奉良臣。"]'),
('yuding-14','登巴陵開元寺西閣贈衡岳僧方外','李賓','唐','御定全唐诗','yuding','','[]','衡嶽有開士，五峰秀貞骨。見君萬里心，海水照秋月。',72,'御定全唐詩/json/776.json','["衡嶽有開士，五峰秀貞骨。見君萬里心，海水照秋月。", "大臣南溟去，問道皆請謁。灑以甘露言，清涼潤肌發。", "湖海落天鏡，香閣淩銀闕。登眺餐惠風，心花期啟發。"]'),
('yuding-15','登瓦官寺閣','李賓','唐','御定全唐诗','yuding','','[]','晨登瓦官閣，極眺金陵城。鐘山對北戶，淮水入南榮。',120,'御定全唐詩/json/776.json','["晨登瓦官閣，極眺金陵城。鐘山對北戶，淮水入南榮。", "漫漫雨花落，嘈嘈天樂鳴。兩廊振法鼓，四角吹風箏。", "杳無霄漢上，仰攀日月行。山空霸氣滅，地古寒陰生。", "寥廓雲海晚，蒼茫宮觀平。門餘閶闔字，樓識鳳凰名。", "雷作百川動，神扶萬栱傾。靈光一向貴，長此鎮吳京。"]'),
('yuding-16','金陵懷古','唐堯臣','唐','御定全唐诗','yuding','','[]','晉末英雄起，神器淪荒服。胡月蝕中原，白日升暘穀。',217,'御定全唐詩/json/776.json','["晉末英雄起，神器淪荒服。胡月蝕中原，白日升暘穀。", "金陵實形勝，關山固重複。巨壑隍北壖，長江塹西隩。", "鑿山擬嵩華，穿地象伊穀。草昧席羅圖，蓽路戴黃屋。", "一時因地險，五世享天祿。禮樂何煌煌，文章紛鬱鬱。", "多士春林秀，作頌清風穆。出入三百年，朝事幾翻覆。", "攙搶如雲勃，鯨鯢旋自曝。倦聞金鼎移，驟睹靈龜蔔。", "籲嗟王氣盡，坐悲天運倏。天道何茫茫，善淫乃相複。", "行路偏衣半，遂亡大樑族。日隱汀洲上，登艫fS川陸。", "月回吳山樹，風聞楚江鵠。因依蘭蕙叢，采襭不盈掬。"]'),
('yuding-17','詠浮漚為辛明府作','鄭縉','唐','御定全唐诗','yuding','','[]','行潦散輕漚，清規吐未收。雨來波際合，風起浪中浮。',84,'御定全唐詩/json/776.json','["行潦散輕漚，清規吐未收。雨來波際合，風起浪中浮。", "晶晃明苔砌，參差繞芥舟。影疑星泛曉，光似露涵秋。", "皎皎珠同淨，漂漂梗共流。潔容無變染，圓知有謙柔。", "欲作微涓效，先從淡水遊。"]'),
('yuding-18','鶯','鄭縉','唐','御定全唐诗','yuding','','[]','欲囀聲猶澀，將飛羽未調。高風不借便，何處得遷喬。',24,'御定全唐詩/json/776.json','["欲囀聲猶澀，將飛羽未調。高風不借便，何處得遷喬。"]'),
('yuding-19','鸚鵡','吳英秀','唐','御定全唐诗','yuding','','[]','莫把金籠閉鸚鵡，個個聰明解人語。',32,'御定全唐詩/json/776.json','["莫把金籠閉鸚鵡，個個聰明解人語。", "忽然更向君前言，三十六宮愁幾許。"]'),
('yuding-20','馬','陳凝','唐','御定全唐诗','yuding','','[]','未明龍骨駿，幸得到神州。自有千金價，甯忘伯樂酬。',48,'御定全唐詩/json/776.json','["未明龍骨駿，幸得到神州。自有千金價，甯忘伯樂酬。", "雖知殊款段，莫敢比驊騮。若遇追風便，當軒一舉頭。"]'),
('yuding-21','鳳','伊夢昌','唐','御定全唐诗','yuding','','[]','好是山家鳳，歌成非楚雞。毫光灑風雨，紋彩動雲霓。',48,'御定全唐詩/json/776.json','["好是山家鳳，歌成非楚雞。毫光灑風雨，紋彩動雲霓。", "竹實不得飽，桐孫何足棲。岐陽今好去，律呂正淒淒。"]'),
('yuding-22','送韋員外赴朔方','鄭嚴','唐','御定全唐诗','yuding','','[]','白露邊秋早，皇華戎事催。已推仙省妙，更是幕中才。',48,'御定全唐詩/json/776.json','["白露邊秋早，皇華戎事催。已推仙省妙，更是幕中才。", "出餞傾朝列，深功佇帝台。坐聞長策利，終見勒銘回。"]'),
('yuding-23','險竿行','柳曾','唐','御定全唐诗','yuding','','[]','山險驚摧輈，水險能覆舟。奈何平地不肯立，',86,'御定全唐詩/json/776.json','["山險驚摧輈，水險能覆舟。奈何平地不肯立，", "爾今輕命重黃金，忠孝兩虧徒爾誇。始以險技悅君目，", "險竿兒，聽我語，更有險徒險於汝。重于權者失君恩，", "上得不下下不得，我謂此輩險于險竿兒。"]'),
('yuding-24','琵琶行','牛殳','唐','御定全唐诗','yuding','','[]','何人劚得一片木，三尺春冰五音足。一彈決破真珠囊，',164,'御定全唐詩/json/776.json','["何人劚得一片木，三尺春冰五音足。一彈決破真珠囊，", "秋鴻叫侶代雲黑，猩猩夜啼蠻月明。潏潏汩汩聲不定，", "青山飛起不壓物，野水流來欲濕人。傷心憶得陳後主，", "二妃哭處山重重，二妃沒後雲溶溶。夜深霜露鎖空廟，", "當時二十四友人，手把金杯聽不足。又似賈客蜀道間，", "引之於山，獸不能走。吹之于水，魚不能遊。", "方知此藝不可有，人間萬事憑雙手。若何為我再三彈，"]'),
('yuding-25','方響歌','牛殳','唐','御定全唐诗','yuding','','[]','樂中何樂偏堪賞，無過夜深聽方響。緩擊急擊曲未終，',72,'御定全唐詩/json/776.json','["樂中何樂偏堪賞，無過夜深聽方響。緩擊急擊曲未終，", "高樓漏滴金壺水，碎電打著山寺鐘。又似公卿入朝去，", "長短參差十六片，敲擊宮商無不遍。此樂不教外人聞，"]'),
('yuding-26','經太華','衛光一','唐','御定全唐诗','yuding','','[]','太華五千尋，重岩合遝起。勢飛白雲外，影倒黃河裏。',48,'御定全唐詩/json/776.json','["太華五千尋，重岩合遝起。勢飛白雲外，影倒黃河裏。", "上有千蓮葉，服之久不死。山高采難得，歎息徒仰止。"]'),
('yuding-27','季夏入北山','林璠','唐','御定全唐诗','yuding','','[]','整駕俟明發，逶迤歷險途。天形逼峰盡，地勢入溪無。',48,'御定全唐詩/json/776.json','["整駕俟明發，逶迤歷險途。天形逼峰盡，地勢入溪無。", "樹繞圓潭密，雲橫疊障孤。誰憐後時者，六月未南圖。"]'),
('yuding-28','適思','顏胄','唐','御定全唐诗','yuding','','[]','芳歲不我與，颯然涼風生。繁華掃地歇，蟋蟀充堂鳴。',204,'御定全唐詩/json/776.json','["芳歲不我與，颯然涼風生。繁華掃地歇，蟋蟀充堂鳴。", "感物增憂思，奮衣出遊行。行值古墓林，白骨下縱橫。", "田豎鞭髑髏，村童掃精靈。精靈無奈何，像設安所榮。", "石人徒瞑目，表柱燒無聲。試讀碑上文，乃是昔時英。", "位極君詔葬，勳高盈忠貞。寵終禁樵采，立嗣修墳塋。", "運否前政缺，群盜多蚊虻。即此丘壟壞，鐵心為沾纓。", "當其崇樹日，豈意侵奪並。冥漠生變故，淒涼結幽明。", "悲端豈自我，外物紛相縈。所適非所見，前登江上城。", "倚樓臨綠水，一望解傷情。"]'),
('yuding-0','古意','邢象玉','唐','御定全唐诗','yuding','','[]','家中酒新熟，園裏葉初榮。佇杯欲取醉，悒然思友生。',96,'御定全唐詩/json/777.json','["家中酒新熟，園裏葉初榮。佇杯欲取醉，悒然思友生。", "忽聞有奇客，何姓複何名。嗜酒陶彭澤，能琴阮步兵。", "何須問寒暑，徑共坐山亭。舉袂祛啼鳥，揚巾掃落英。", "心神無俗累，歌詠有新聲。新聲是何曲，滄浪之水清。"]'),
('yuding-1','採蓮曲','張敬徽','唐','御定全唐诗','yuding','','[]','游女泛江晴，蓮紅水複清。競多愁日暮，爭疾畏船傾。',48,'御定全唐詩/json/777.json','["游女泛江晴，蓮紅水複清。競多愁日暮，爭疾畏船傾。", "波動疑釵落，風生覺袖輕。相看未盡意，歸浦棹歌聲。"]'),
('yuding-2','採蓮','徐玄之','唐','御定全唐诗','yuding','','[]','越豔荊姝慣採蓮，蘭橈畫楫滿長川。秋來江上澄如練，',48,'御定全唐詩/json/777.json','["越豔荊姝慣採蓮，蘭橈畫楫滿長川。秋來江上澄如練，", "纖手周遊不暫息，紅英爛熳殊未極。夕鳥棲林人欲稀，"]'),
('yuding-3','同崔員外溫泉宮即事','郭汭','唐','御定全唐诗','yuding','','[]','輦輅移雙闕，宸游整六師。天回紫微座，日轉羽林旗。',72,'御定全唐詩/json/777.json','["輦輅移雙闕，宸游整六師。天回紫微座，日轉羽林旗。", "雷氣寒戈戟，軍容壯武貔。弓鳴射雁處，泉暖躍龍時。", "惠化成觀俗，謳謠入賦詩。同歡王道盛，相與詠雍熙。"]'),
('yuding-4','題沈黎城','權徹','唐','御定全唐诗','yuding','','[]','蘇子臥北海，馬翁渡南洲。跡恨事乃立，功達名遂休。',84,'御定全唐詩/json/777.json','["蘇子臥北海，馬翁渡南洲。跡恨事乃立，功達名遂休。", "夜聞羽書至，召募此邊州。鐵騎耀楚甲，玉匣橫吳鉤。", "雪厚群山凍，蓬飛荒塞秋。久戍曷辭苦，數戰期封侯。", "不學豎儒輩，談經空白頭。"]'),
('yuding-5','登樂游原懷古','豆盧回','唐','御定全唐诗','yuding','','[]','緬惟漢宣帝，初謂皇曾孫。雖在繈褓中，亦遭巫蠱冤。',181,'御定全唐詩/json/777.json','["緬惟漢宣帝，初謂皇曾孫。雖在繈褓中，亦遭巫蠱冤。", "至哉丙廷尉，感激義彌敦。馳逐蓮勺道，出入諸陵門。", "一朝風雲會，竟登天位尊。握符升寶曆，負扆禦華軒。", "赫奕文物備，葳蕤休瑞繁。卒為中興主，垂名於後昆。", "雄圖奄已謝，餘址空複存。昔為樂游苑，今為狐兔園。", "朝見牧豎集，夕聞棲鳥喧。蕭條灞亭岸，寂寞杜陵原。", "冪zx野煙起，蒼茫嵐氣昏。二曜屢回薄，四時更涼溫。", "天道尚如此，人理安可論。"]'),
('yuding-6','靜女歌','張南容','唐','御定全唐诗','yuding','','[]','靜女樂於靜，動合古人則。妙年工詩書，弱歲勤組織。',96,'御定全唐詩/json/777.json','["靜女樂於靜，動合古人則。妙年工詩書，弱歲勤組織。", "端居愁若癡，誰複理容色。十五坐幽閨，四鄰不相識。", "夭夭鄰家子，百花裝首飾。日月淇上游，笑人不逾閾。", "河水自濁濟自清，仙台蛾眉秦鏡明。為照齊王門下醜，"]'),
('yuding-7','古興二首','沈徽','唐','御定全唐诗','yuding','','[]','蔓草自細微，女蘿始夭夭。夤緣至百尺，榮耀非一朝。',144,'御定全唐詩/json/777.json','["蔓草自細微，女蘿始夭夭。夤緣至百尺，榮耀非一朝。", "敷色高碧嶺，流芳薄丹霄。如何摧秀木，正為餘波漂。", "莖葉落岩跡，英蕤從風飆。洪柯不足恃，況乃托陵苕。", "長安富豪右，信是天下樞。戚裏笙歌發，禁門冠蓋趨。", "攀雲無醜士，唾地盡成珠。日晏下雙闕，煙花亂九衢。", "恩榮在片言，零落亦須臾。何意還自及，曲池今已蕪。"]'),
('yuding-8','晚望','林琨','唐','御定全唐诗','yuding','','[]','清晨孤亭裏，極目對前岑。遠與天水合，長霞生夕林。',72,'御定全唐詩/json/777.json','["清晨孤亭裏，極目對前岑。遠與天水合，長霞生夕林。", "蒼然平楚意，杳靄半秋陰。落日川上盡，關城雲外深。", "方予事岩壑，及此欲抽簪。詩就蓬山道，還茲契宿心。"]'),
('yuding-9','陽春歌','吳象之','唐','御定全唐诗','yuding','','[]','簾低曉露濕，簾卷鶯聲急。欲起把箜篌，如凝彩弦澀。',48,'御定全唐詩/json/777.json','["簾低曉露濕，簾卷鶯聲急。欲起把箜篌，如凝彩弦澀。", "孤眠愁不轉，點淚聲相及。淨掃階上花，風來更吹入。"]'),
('yuding-10','少年行','吳象之','唐','御定全唐诗','yuding','','[]','承恩借獵小平津，使氣常游中貴人。',32,'御定全唐詩/json/777.json','["承恩借獵小平津，使氣常游中貴人。", "一擲千金渾是膽，家無四壁不知貧。"]'),
('yuding-11','晚至鄉亭','鄭德玄','唐','御定全唐诗','yuding','','[]','長亭日已暮，駐馬暫盤桓。山川杳不極，徒侶默相看。',48,'御定全唐詩/json/777.json','["長亭日已暮，駐馬暫盤桓。山川杳不極，徒侶默相看。", "雲夕荊台暗，風秋郢路寒。客心一如此，誰複采芳蘭。"]'),
('yuding-12','舟行旦發','張軫','唐','御定全唐诗','yuding','','[]','夜帆時未發，同侶暗相催。山曉月初下，江鳴潮欲來。',48,'御定全唐詩/json/777.json','["夜帆時未發，同侶暗相催。山曉月初下，江鳴潮欲來。", "稍分揚子岸，不辨越王台。自客水鄉裏，舟行知幾回。"]'),
('yuding-13','奉和夏日遊山應制','蔡文恭','唐','御定全唐诗','yuding','','[]','首夏林壑清，薄暮煙霞上。連岩聳百仞，絕壑臨千丈。',72,'御定全唐詩/json/777.json','["首夏林壑清，薄暮煙霞上。連岩聳百仞，絕壑臨千丈。", "照灼晚花鮮，潺湲夕流響。悠然動睿思，息駕尋真賞。", "掞彼渦川作，懷茲洛濱想。竊吹等齊竽，何用承恩獎。"]'),
('yuding-14','旅泊江津言懷','賈宗','唐','御定全唐诗','yuding','','[]','征途幾迢遞，客子倦西東。乘流如泛梗，逐吹似驚蓬。',72,'御定全唐詩/json/777.json','["征途幾迢遞，客子倦西東。乘流如泛梗，逐吹似驚蓬。", "飄颻萬里外，辛苦百年中。異縣心期阻，他鄉風月同。", "雲歸全嶺暗，日落半江紅。自然堪迸淚，非是泣途窮。"]'),
('yuding-15','大樑行','唐堯客','唐','御定全唐诗','yuding','','[]','客有成都來，為我彈鳴琴。前彈別鶴操，後奏大樑吟。',192,'御定全唐詩/json/777.json','["客有成都來，為我彈鳴琴。前彈別鶴操，後奏大樑吟。", "大樑傷客情，荒台對古城。版築有陳跡，歌吹無遺聲。", "雄哉魏公子，疇日好羅英。秀士三千人，煌煌列眾星。", "金槌奪晉鄙，白刃刎侯嬴。邯鄲救趙北，函谷走秦兵。", "君子榮且昧，忠信莫之明。間諜忽來及，雄圖靡克成。", "千齡萬化盡，但見汴水清。舊國多孤壘，夷門荊棘生。", "蒼梧彩雲沒，湘浦綠池平。聞有東山去，蕭蕭班馬鳴。", "河洲搴宿莽，日夕淚沾纓。因之唁公子，慷慨此歌行。"]'),
('yuding-16','秋日送別','朱晦','唐','御定全唐诗','yuding','','[]','荒郊古陌時時斷，野水浮雲處處秋。',32,'御定全唐詩/json/777.json','["荒郊古陌時時斷，野水浮雲處處秋。", "唯有河邊衰柳樹，蟬聲相送到揚州。"]'),
('yuding-17','送人歸山','石召','唐','御定全唐诗','yuding','','[]','相逢唯道在，誰不共知貧。歸路分殘雨，停舟別故人。',48,'御定全唐詩/json/777.json','["相逢唯道在，誰不共知貧。歸路分殘雨，停舟別故人。", "霜明松嶺曉，花暗竹房春。亦有棲閑意，何年可寄身。"]'),
('yuding-18','早行遇雪','石召','唐','御定全唐诗','yuding','','[]','荒郊昨夜雪，羸馬又須行。四顧無人跡，雞鳴第一聲。',24,'御定全唐詩/json/777.json','["荒郊昨夜雪，羸馬又須行。四顧無人跡，雞鳴第一聲。"]'),
('yuding-19','送安養閻主簿還竹寺','林珝','唐','御定全唐诗','yuding','','[]','分手怨河梁，南征曆漢陽。江山追宋玉，雲雨夢襄王。',48,'御定全唐詩/json/777.json','["分手怨河梁，南征曆漢陽。江山追宋玉，雲雨夢襄王。", "醉裏宜城近，歌中郢路長。更尋棲枳處，猶是念仇香。"]'),
('yuding-20','晚投南村','衛葉','唐','御定全唐诗','yuding','','[]','客行逢日暮，原野散秋暉。南陌人初斷，西林鳥盡歸。',48,'御定全唐詩/json/777.json','["客行逢日暮，原野散秋暉。南陌人初斷，西林鳥盡歸。", "暗蓬沙上轉，寒葉月中飛。村落無多在，聲聲近擣衣。"]'),
('yuding-0','題季子廟','李季華','唐','御定全唐诗','yuding','','[]','季子讓社稷，又能聽國風。寧知千載後，蘋藻冷祠宮。',24,'御定全唐詩/json/778.json','["季子讓社稷，又能聽國風。寧知千載後，蘋藻冷祠宮。"]'),
('yuding-1','聽琴','王玄','唐','御定全唐诗','yuding','','[]','拂塵開按匣，何事獨顰眉。古調俗不樂，正聲君自知。',24,'御定全唐詩/json/778.json','["拂塵開按匣，何事獨顰眉。古調俗不樂，正聲君自知。"]'),
('yuding-2','失鷺鶿','李歸唐','唐','御定全唐诗','yuding','','[]','惜養來來歲月深，籠開不見意沈吟。',32,'御定全唐詩/json/778.json','["惜養來來歲月深，籠開不見意沈吟。", "也知只在秋江上，明月蘆花何處尋。"]'),
('yuding-3','銅雀妓','朱光弼','唐','御定全唐诗','yuding','','[]','魏王銅雀妓，日暮管弦清。一見西陵樹，心悲舞不成。',24,'御定全唐詩/json/778.json','["魏王銅雀妓，日暮管弦清。一見西陵樹，心悲舞不成。"]'),
('yuding-4','宮詞','朱光弼','唐','御定全唐诗','yuding','','[]','夢裏君王近，宮中河漢高。秋風能再熱，團扇不辭勞。',24,'御定全唐詩/json/778.json','["夢裏君王近，宮中河漢高。秋風能再熱，團扇不辭勞。"]'),
('yuding-5','惆悵詩九首','顧甄遠','唐','御定全唐诗','yuding','','[]','魂黯黯兮情脈脈，簾風清兮窗月白。',288,'御定全唐詩/json/778.json','["魂黯黯兮情脈脈，簾風清兮窗月白。", "夢驚枕上爐燼銷，不見蕊珠宮裏客。", "禁漏聲稀蟾魄冷，紗廚筠簟波光淨。", "獨坐愁吟暗斷魂，滿窗風動芭蕉影。", "別恨離腸空惻惻，風動虛軒池水白。", "莫言靈圃步難尋，有心終效偷桃客。", "愁遇人間好風景，焦桐韻滿華堂靜。", "鑒鸞釵燕恨何窮，忍向銀床空抱影。", "綠槐影裏傍青樓，陌上行人空舉頭。", "煙水露花無處問，搖鞭凝睇不勝愁。", "役盡心神銷盡骨，恩情未斷忽分離。", "平生此恨無言處，只有衣襟淚得知。", "濃醪豔唱愁難破，骨瘦魂消病已成。", "若為多羅年少死，始甘人道有風情。", "淚滿羅衣酒滿卮，一聲歌斷怨傷離。", "如今兩地心中事，直是瞿曇也不知。", "橫泥杯觴醉複醒，愁牽時有小詩成。", "早知惹得千般恨，悔不天生解薄情。"]'),
('yuding-6','登清居台','魏巒','唐','御定全唐诗','yuding','','[]','迤邐清居台，連延白雲外。側聆天上語，下視飛鳥背。',24,'御定全唐詩/json/778.json','["迤邐清居台，連延白雲外。側聆天上語，下視飛鳥背。"]'),
('yuding-7','遊昌化精舍','柳明獻','唐','御定全唐诗','yuding','','[]','寶台侵漢遠，金地接霞高。何必遊天外，忻此契盧敖。',24,'御定全唐詩/json/778.json','["寶台侵漢遠，金地接霞高。何必遊天外，忻此契盧敖。"]'),
('yuding-8','善卷先生壇','蔡昆','唐','御定全唐诗','yuding','','[]','幾到壇邊登閣望，因思遺跡詠今朝。',32,'御定全唐詩/json/778.json','["幾到壇邊登閣望，因思遺跡詠今朝。", "當時為有重華出，不是先生傲帝堯。"]'),
('yuding-9','句','蔡昆','唐','御定全唐诗','yuding','','[]','飄飄隨暮雨，颯颯落秋山。',12,'御定全唐詩/json/778.json','["飄飄隨暮雨，颯颯落秋山。"]'),
('yuding-10','題鄜州相思鋪','令狐挺','唐','御定全唐诗','yuding','','[]','誰把相思號此河，塞垣車馬往來多。',32,'御定全唐詩/json/778.json','["誰把相思號此河，塞垣車馬往來多。", "只應自古征人淚，灑向空川作逝波。"]'),
('yuding-11','鳳歸雲二首','滕潛','唐','御定全唐诗','yuding','','[]','金井欄邊見羽儀，梧桐枝上宿寒枝。',64,'御定全唐詩/json/778.json','["金井欄邊見羽儀，梧桐枝上宿寒枝。", "五陵公子憐文彩，畫與佳人刺繡衣。", "飲啄蓬山最上頭，和煙飛下禁城秋。", "曾將弄玉歸雲去，金翿斜開十二樓。"]'),
('yuding-12','藥圃','夏侯子雲','唐','御定全唐诗','yuding','','[]','綠葉紅英遍，仙經自討論。偶移岩畔菊，鋤斷白雲根。',24,'御定全唐詩/json/778.json','["綠葉紅英遍，仙經自討論。偶移岩畔菊，鋤斷白雲根。"]'),
('yuding-13','讀孝經','方愚','唐','御定全唐诗','yuding','','[]','星彩滿天朝北極，源流是處赴東溟。',32,'御定全唐詩/json/778.json','["星彩滿天朝北極，源流是處赴東溟。", "為臣為子不忠孝，辜負宣尼一卷經。"]'),
('yuding-14','贈葛氏小娘子','潘雍','唐','御定全唐诗','yuding','','[]','曾聞仙子住天臺，欲結靈姻愧短才。',32,'御定全唐詩/json/778.json','["曾聞仙子住天臺，欲結靈姻愧短才。", "若許隨君洞中住，不同劉阮卻歸來。"]'),
('yuding-15','送孫舍人歸湘州','梁陟','唐','御定全唐诗','yuding','','[]','盛才傾世重，清論滿朝歸。作隼他年計，為鴛此日飛。',48,'御定全唐詩/json/778.json','["盛才傾世重，清論滿朝歸。作隼他年計，為鴛此日飛。", "比肩移日近，抗首出郊畿。為報清漳水，分明照錦衣。"]'),
('yuding-16','再登河陽城懷古','朱延','唐','御定全唐诗','yuding','','[]','客遊倦旅思，憩駕陟崇墉。元凱標奇跡，安仁擅美蹤。',48,'御定全唐詩/json/778.json','["客遊倦旅思，憩駕陟崇墉。元凱標奇跡，安仁擅美蹤。", "遠近濁河流，出沒青山峰。佇想空不極，懷古悵無從。"]'),
('yuding-17','題瑩上人院','寇埴','唐','御定全唐诗','yuding','','[]','舍筏求香偈，因泉演妙音。是明捐俗網，何獨在山林。',48,'御定全唐詩/json/778.json','["舍筏求香偈，因泉演妙音。是明捐俗網，何獨在山林。", "繚繞藤軒密，逶迤竹徑深。為傳同學志，茲宇可清心。"]'),
('yuding-18','燕銜泥','馮渚','唐','御定全唐诗','yuding','','[]','雙燕碌碌飛入屋，屋中老人喜燕歸，裴回繞我床頭飛。',65,'御定全唐詩/json/778.json','["雙燕碌碌飛入屋，屋中老人喜燕歸，裴回繞我床頭飛。", "去年為爾逐黃雀，雨多屋漏泥土落。爾莫厭老翁茅屋低，", "井旁寫水泥自足，銜泥上屋隨爾欲。"]'),
('yuding-0','日暖萬年枝','王約','唐','御定全唐诗','yuding','','[]','靄靄彤庭裏，沉沉玉砌陲。初升九華日，潛暖萬年枝。',72,'御定全唐詩/json/779.json','["靄靄彤庭裏，沉沉玉砌陲。初升九華日，潛暖萬年枝。", "煦嫗光偏好，青蔥色轉宜。每因韶景麗，長沐惠風吹。", "隱映當龍闕，氛氳隔鳳池。朝陽光照處，唯有近臣知。"]'),
('yuding-1','日暖萬年枝','郭求','唐','御定全唐诗','yuding','','[]','旭日升溟海，芳枝散曙煙。溫仁臨樹久，煦嫗在條偏。',72,'御定全唐詩/json/779.json','["旭日升溟海，芳枝散曙煙。溫仁臨樹久，煦嫗在條偏。", "陽德符君惠，嘉名表聖年。若承恩渥厚，常屬棟樑賢。", "生植雖依地，光華只信天。不才堪仄陋，徒望向榮先。"]'),
('yuding-2','日暖萬年枝','鄭師貞','唐','御定全唐诗','yuding','','[]','禁樹敷榮早，偏將麗日宜。光搖連北闕，影泛滿南枝。',72,'御定全唐詩/json/779.json','["禁樹敷榮早，偏將麗日宜。光搖連北闕，影泛滿南枝。", "得地方知照，逢時異赫曦。葉和盈數積，根是永年移。", "宵露猶殘潤，熏風更共吹。餘暉誠可托，況近鳳凰池。"]'),
('yuding-3','日華川上動','石殷士','唐','御定全唐诗','yuding','','[]','曙霞攢旭日，浮景弄晴川。晃曜層潭上，悠揚極浦前。',72,'御定全唐詩/json/779.json','["曙霞攢旭日，浮景弄晴川。晃曜層潭上，悠揚極浦前。", "岸高時擁媚，波遠漸澄鮮。萍實空隨浪，珠胎不照淵。", "早暄依曲渚，微動觸輕漣。孰假咸池望，幽情得古篇。"]'),
('yuding-4','聞擊壤','石殷士','唐','御定全唐诗','yuding','','[]','堯年聽野老，擊壤複何雲。自謂歡由己，寧知德在君。',72,'御定全唐詩/json/779.json','["堯年聽野老，擊壤複何雲。自謂歡由己，寧知德在君。", "氣平閑易暢，聲賀作難分。耕鑿方隨日，恩威比望雲。", "簣桴均下調，和木等南熏。無落於吾事，誰將帝力聞。"]'),
('yuding-5','初日照華清宮','柴宿','唐','御定全唐诗','yuding','','[]','靈山初照澤，遠近見離宮。影動參差裏，光分縹緲中。',73,'御定全唐詩/json/779.json','["靈山初照澤，遠近見離宮。影動參差裏，光分縹緲中。", "鮮飆收晚翠，佳氣滿晴空。林潤溫泉入，樓深複道通。", "璿題生炯晃，珠綴引xz朧。鳳輦何時幸，朝朝此望同。"]'),
('yuding-6','瑜不掩瑕','柴宿','唐','御定全唐诗','yuding','','[]','朗玉微瑕在，分明異璞瑜。堅貞寧可雜，美惡自能殊。',72,'御定全唐詩/json/779.json','["朗玉微瑕在，分明異璞瑜。堅貞寧可雜，美惡自能殊。", "待價知彌久，稱忠定不誣。光輝今見黜，毫髮外呈符。", "豈假良工指，堪為達士模。他山儻磨琢，慕愛是洪爐。"]'),
('yuding-7','秋日懸清光','陶拱','唐','御定全唐诗','yuding','','[]','秋至雲容斂，天中日景清。懸空寒色淨，委照曙光盈。',72,'御定全唐詩/json/779.json','["秋至雲容斂，天中日景清。懸空寒色淨，委照曙光盈。", "泫泫看彌上，輝輝望最明。煙霞輪乍透，葵藿影初生。", "鑒下應無極，升高自有程。何當回盛彩，一為表精誠。"]'),
('yuding-8','三讓月成魄','劉gL','唐','御定全唐诗','yuding','','[]','為禮依天象，周旋逐月成。教人三讓美，為客一宵生。',48,'御定全唐詩/json/779.json','["為禮依天象，周旋逐月成。教人三讓美，為客一宵生。", "初進輪猶暗，終辭影漸明。幸陪賓主位，取捨任虧盈。"]'),
('yuding-9','海上生明月','朱華','唐','御定全唐诗','yuding','','[]','皎皎秋中月，團圓海上生。影開金鏡滿，輪抱玉壺清。',72,'御定全唐詩/json/779.json','["皎皎秋中月，團圓海上生。影開金鏡滿，輪抱玉壺清。", "漸出三山岊，將淩一漢橫。素娥嘗藥去，烏鵲繞枝驚。", "照水光偏白，浮雲色最明。此時堯砌下，蓂莢自將榮。"]'),
('yuding-10','月夜梧桐葉上見寒露','戴察','唐','御定全唐诗','yuding','','[]','蕭疏桐葉上，月白露初團。滴瀝清光滿，熒煌素彩寒。',72,'御定全唐詩/json/779.json','["蕭疏桐葉上，月白露初團。滴瀝清光滿，熒煌素彩寒。", "風搖愁玉墜，枝動惜珠幹。氣冷疑秋晚，聲微覺夜闌。", "凝空流欲遍，潤物淨宜看。莫厭窺臨倦，將晞聚更難。"]'),
('yuding-11','清露被皋蘭','孫顧','唐','御定全唐诗','yuding','','[]','九皋蘭葉茂，八月露華清。稍與秋陰合，還將曉色並。',72,'御定全唐詩/json/779.json','["九皋蘭葉茂，八月露華清。稍與秋陰合，還將曉色並。", "向空羅細影，臨水泫微明。的皪添幽興，芊綿動遠情。", "夕芳人未采，初降鶴先驚。為感生成惠，心同葵藿傾。"]'),
('yuding-12','宿煙含白露','孫頠','唐','御定全唐诗','yuding','','[]','析析有新意，微微曙色幽。露含疏月淨，光與曉煙浮。',72,'御定全唐詩/json/779.json','["析析有新意，微微曙色幽。露含疏月淨，光與曉煙浮。", "迥野遙凝素，空林望已秋。著霜寒未結，凝葉滴還流。", "比玉偏清潔，如珠詎可收。裴回阡陌上，瞻想但淹留。"]'),
('yuding-13','送薛大夫和蕃','孫頠','唐','御定全唐诗','yuding','','[]','亞相獨推賢，乘軺向遠邊。一心傾漢日，萬里望胡天。',72,'御定全唐詩/json/779.json','["亞相獨推賢，乘軺向遠邊。一心傾漢日，萬里望胡天。", "忠信皇恩重，要荒聖德傳。戎人方屈膝，塞月複嬋娟。", "別思流鶯晚，歸朝候雁先。當書外垣傳，回奏赤墀前。"]'),
('yuding-14','風光草際浮','陳璀','唐','御定全唐诗','yuding','','[]','春風泛搖草，旭日遍神州。已向花間積，還來葉上浮。',72,'御定全唐詩/json/779.json','["春風泛搖草，旭日遍神州。已向花間積，還來葉上浮。", "曉光緣圃麗，芳氣滿街流。澹蕩依朱萼，颻颺帶玉溝。", "向空看轉媚，臨水見彌幽。況被崇蘭色，王孫正可游。"]'),
('yuding-15','風光草際浮','裴杞','唐','御定全唐诗','yuding','','[]','澹蕩和風至，芊綿碧草長。徐吹遙撲翠，半偃乍浮光。',72,'御定全唐詩/json/779.json','["澹蕩和風至，芊綿碧草長。徐吹遙撲翠，半偃乍浮光。", "葉似翻宵露，叢疑扇夕陽。逶迤明曲渚，照耀滿回塘。", "白芷生還暮，崇蘭泛更香。誰知攬結處，含思向餘芳。"]'),
('yuding-16','風光草際浮','陳祜','唐','御定全唐诗','yuding','','[]','香發王孫草，春生君子風。光搖低偃處，影散豔陽中。',72,'御定全唐詩/json/779.json','["香發王孫草，春生君子風。光搖低偃處，影散豔陽中。", "稍稍移蘋末，微微轉蕙叢。浮煙傾綠野，遠色澹晴空。", "泛彩池塘媚，含芳景氣融。清暉誰不挹，幾許賞心同。"]'),
('yuding-17','風光草際浮','吳秘','唐','御定全唐诗','yuding','','[]','草色春沙裏，風光曉正幽。輕明搖不散，鬱昱麗仍浮。',72,'御定全唐詩/json/779.json','["草色春沙裏，風光曉正幽。輕明搖不散，鬱昱麗仍浮。", "吹緩苗難轉，暉閑葉本柔。碧凝煙彩入，紅是日華流。", "耐可披襟對，誰應滿掬收。恭聞掇芳客，為此尚淹留。"]'),
('yuding-18','風光草際浮','張複元','唐','御定全唐诗','yuding','','[]','纖纖春草長，遲日度風光。靃靡含新彩，霏微籠遠芳。',72,'御定全唐詩/json/779.json','["纖纖春草長，遲日度風光。靃靡含新彩，霏微籠遠芳。", "殊姿媚原野，佳色滿池塘。最好垂清露，偏宜帶豔陽。", "淺深浮嫩綠，輕麗拂餘香。好助鶯遷勢，乘時冀便翔。"]'),
('yuding-19','冬至日祥風應候','穆寂','唐','御定全唐诗','yuding','','[]','節逢清景至，占氣二儀中。獨喜登臺日，先知應候風。',72,'御定全唐詩/json/779.json','["節逢清景至，占氣二儀中。獨喜登臺日，先知應候風。", "呈祥光舜化，表慶感堯聰。既與乘時葉，還將入律同。", "微微萬井遍，習習九門通。更繞爐煙起，殷勤報歲功。"]'),
('yuding-20','清風戒寒','穆寂','唐','御定全唐诗','yuding','','[]','風清物候殘，蕭灑報將寒。掃得天衢靜，吹來眼界寬。',72,'御定全唐詩/json/779.json','["風清物候殘，蕭灑報將寒。掃得天衢靜，吹來眼界寬。", "條鳴方有異，蟲思亂無端。就樹收鮮膩，沖池起澀瀾。", "過山嵐可掬，度月色宜看。華實從茲始，何嗟歲序殫。"]'),
('yuding-21','風草不留霜','王景中','唐','御定全唐诗','yuding','','[]','繁霜當永夜，寒草正驚風。飄素衰蘋末，流光晚蕙叢。',72,'御定全唐詩/json/779.json','["繁霜當永夜，寒草正驚風。飄素衰蘋末，流光晚蕙叢。", "悠揚方泛影，皎潔卻飛空。不定離披際，難凝蘙薈中。", "低昂閒散質，肅殺想成功。獨感玄暉詠，依依此夕同。"]'),
('yuding-22','春雲','鄧倚','唐','御定全唐诗','yuding','','[]','搖曳自西東，依林又逐風。勢移青道裏，影泛綠波中。',72,'御定全唐詩/json/779.json','["搖曳自西東，依林又逐風。勢移青道裏，影泛綠波中。", "夕霽方明日，朝陽複蔽空。度關隨去馬，出塞引歸鴻。", "色任寒暄變，光將遠近同。為霖如見用，還得助成功。"]'),
('yuding-23','登雲梯','湯洙','唐','御定全唐诗','yuding','','[]','謝客常遊處，層巒枕碧溪。經過殊俗境，登陟象雲梯。',72,'御定全唐詩/json/779.json','["謝客常遊處，層巒枕碧溪。經過殊俗境，登陟象雲梯。", "步步勞山屐，行行躡澗霓。迥臨天路廣，俯眺夕陽低。", "賞詠情彌愜，風塵事已睽。前修如可慕，投足固思齊。"]'),
('yuding-24','登雲梯','殷琮','唐','御定全唐诗','yuding','','[]','碧落遠澄澄，青山路可升。身輕疑易蹋，步獨覺難憑。',72,'御定全唐詩/json/779.json','["碧落遠澄澄，青山路可升。身輕疑易蹋，步獨覺難憑。", "邐迤排將近，回翔勢漸登。上甯愁屈曲，高更喜超騰。", "江樹遙分藹，山嵐宛若凝。赤城容許到，敢憚百千層。"]'),
('yuding-25','秋山極天淨','朱延齡','唐','御定全唐诗','yuding','','[]','雨洗高秋淨，天臨大野閑。蔥蘢清萬象，繚繞出層山。',72,'御定全唐詩/json/779.json','["雨洗高秋淨，天臨大野閑。蔥蘢清萬象，繚繞出層山。", "日落千峰上，雲銷萬壑間。綠蘿霜後翠，紅葉雨來殷。", "散彩輝吳甸，分形壓楚關。欲尋霄漢路，延首願登攀。"]'),
('yuding-0','春台晴望','鄭蕡','唐','御定全唐诗','yuding','','[]','追賞層台迥，登臨四望頻。熙熙山雨霽，處處柳條新。',72,'御定全唐詩/json/780.json','["追賞層台迥，登臨四望頻。熙熙山雨霽，處處柳條新。", "草長秦城夕，花明漢苑春。晴林翻去鳥，紫陌閱行人。", "旅客風塵厭，山家夢寐親。遷鶯思出穀，鶱翥待芳辰。"]'),
('yuding-1','天驥呈材','鄭蕡','唐','御定全唐诗','yuding','','[]','毛骨合天經，拳奇步驟輕。曾邀於闐駕，新出貳師營。',72,'御定全唐詩/json/780.json','["毛骨合天經，拳奇步驟輕。曾邀於闐駕，新出貳師營。", "噴勒金鈴響，追風汗血生。酒亭留去跡，吳阪認嘶聲。", "力可通衢試，材堪聖代呈。王良如顧盻，垂耳欲長鳴。"]'),
('yuding-2','律中應鐘','裴元','唐','御定全唐诗','yuding','','[]','律窮方數寸，室暗在三重。伶管灰先動，秦正節已逢。',72,'御定全唐詩/json/780.json','["律窮方數寸，室暗在三重。伶管灰先動，秦正節已逢。", "商聲辭玉笛，羽調入金鐘。密葉翻霜彩，輕冰斂水容。", "望鴻南去絕，迎氣北來濃。願托無凋性，寒林自比松。"]'),
('yuding-3','閏月定四時','杜周士','唐','御定全唐诗','yuding','','[]','得閏因貞歲，吾君敬授時。體元承夏道，推曆法堯咨。',72,'御定全唐詩/json/780.json','["得閏因貞歲，吾君敬授時。體元承夏道，推曆法堯咨。", "直取歸餘改，非如再失欺。葭灰初變律，斗柄正當離。", "寒暑功前定，春秋氣可推。更憐幽谷羽，鳴躍尚須期。"]'),
('yuding-4','閏月定四時','樂伸','唐','御定全唐诗','yuding','','[]','聖代承堯曆，恒將閏正時。六旬餘可借，四序應如期。',72,'御定全唐詩/json/780.json','["聖代承堯曆，恒將閏正時。六旬餘可借，四序應如期。", "分至寧愆素，盈虛信不欺。鬥杓重指甲，灰管再推離。", "羲氏兼和氏，行之又則之。願言符大化，永永作元龜。"]'),
('yuding-5','閏月定四時','徐至','唐','御定全唐诗','yuding','','[]','積數歸成閏，羲和職舊司。分銖標鬥建，盈縮正人時。',72,'御定全唐詩/json/780.json','["積數歸成閏，羲和職舊司。分銖標鬥建，盈縮正人時。", "節候潛相應，星辰自合期。寸陰寧越度，長曆信無欺。", "定向銅壺辨，還從玉律推。高明終不謬，委鑒本無私。"]'),
('yuding-6','新陽改故陰','紇幹諷','唐','御定全唐诗','yuding','','[]','律管才推候，寒郊忽變陰。微和方應節，積慘已辭林。',72,'御定全唐詩/json/780.json','["律管才推候，寒郊忽變陰。微和方應節，積慘已辭林。", "暗覺餘澌斷，潛驚麗景侵。禁城佳氣換，北陸翠煙深。", "有截知遐布，無私荷照臨。韶光如可及，鶯谷免幽沈。"]'),
('yuding-7','春水綠波','朱休','唐','御定全唐诗','yuding','','[]','芳時淑氣和，春水澹煙波。滉漾滋蘭杜，淪漣長芰荷。',72,'御定全唐詩/json/780.json','["芳時淑氣和，春水澹煙波。滉漾滋蘭杜，淪漣長芰荷。", "晚光扶翠瀲，潭影寫青莎。歸雁追飛盡，纖鱗游泳多。", "朝宗終到海，潤下每盈科。願假中流便，從茲發棹歌。"]'),
('yuding-8','海水不揚波','李沛','唐','御定全唐诗','yuding','','[]','明朝崇大道，寰海免波揚。既合千年聖，能安百谷王。',72,'御定全唐詩/json/780.json','["明朝崇大道，寰海免波揚。既合千年聖，能安百谷王。", "天心隨澤廣，水德共靈長。不撓魚彌樂，無瀾葦可航。", "化流沾率土，恩浸及殊方。豈只朝宗國，惟聞有越裳。"]'),
('yuding-9','四水合流','李沛','唐','御定全唐诗','yuding','','[]','禹鑿山川地，因通四水流。縈回過鳳闕，會合出皇州。',72,'御定全唐詩/json/780.json','["禹鑿山川地，因通四水流。縈回過鳳闕，會合出皇州。", "天影長波裏，寒聲古度頭。入河無晝夜，歸海有謙柔。", "順物宜投石，逢時可載舟。羨魚猶未已，臨水欲垂鉤。"]'),
('yuding-10','登聖善寺閣望龍門','成崿','唐','御定全唐诗','yuding','','[]','高閣聊登望，遙分禹鑿門。刹連多寶塔，樹滿給孤園。',72,'御定全唐詩/json/780.json','["高閣聊登望，遙分禹鑿門。刹連多寶塔，樹滿給孤園。", "香境超三界，清流振陸渾。報慈弘孝理，行道得真源。", "空淨祥煙霽，時光受日溫。願從初地起，長奉下生尊。"]'),
('yuding-11','秋霽望廬山瀑布','夏侯楚','唐','御定全唐诗','yuding','','[]','常思瀑布幽，晴晀喜逢秋。一帶連青嶂，千尋倒碧流。',72,'御定全唐詩/json/780.json','["常思瀑布幽，晴晀喜逢秋。一帶連青嶂，千尋倒碧流。", "濕雲應誤鶴，翻浪定驚鷗。星浦虹初下，爐峰煙未收。", "岩高時褭褭，天淨起悠悠。儻見朝宗日，還須濟巨舟。"]'),
('yuding-12','濟川用舟楫','胡權','唐','御定全唐诗','yuding','','[]','渺渺水連天，歸程想幾千。孤舟辭曲岸，輕楫濟長川。',72,'御定全唐詩/json/780.json','["渺渺水連天，歸程想幾千。孤舟辭曲岸，輕楫濟長川。", "迥指波濤雪，回瞻島嶼煙。心迷滄海上，目斷白雲邊。", "氾濫雖無定，維持且自專。還如聖明代，理國用英賢。"]'),
('yuding-13','洛出書','郭邕','唐','御定全唐诗','yuding','','[]','德合天貺呈，龍飛聖人作。光宅被寰區，圖書薦河洛。',72,'御定全唐詩/json/780.json','["德合天貺呈，龍飛聖人作。光宅被寰區，圖書薦河洛。", "象登四氣順，文辟九疇錯。氤氳瑞彩浮，左右靈儀廓。", "微造功不宰，神行利攸博。一見皇家慶，方知禹功薄。"]'),
('yuding-14','洛出書','張欽敬','唐','御定全唐诗','yuding','','[]','浮空九洛水，瑞聖千年質。奇象八卦分，圖書九疇出。',72,'御定全唐詩/json/780.json','["浮空九洛水，瑞聖千年質。奇象八卦分，圖書九疇出。", "含微蔔筮遠，抱數陰陽密。中得天地心，傍探鬼神吉。", "昔聞夏禹代，今獻唐堯日。謬此敘彝倫，寰宇賀清謐。"]'),
('yuding-15','洛出書','叔孫玄觀','唐','御定全唐诗','yuding','','[]','清洛含溫溜，玄龜薦寶書。波開綠字出，瑞應紫宸居。',72,'御定全唐詩/json/780.json','["清洛含溫溜，玄龜薦寶書。波開綠字出，瑞應紫宸居。", "物著群靈首，文成列卦初。美珍翔閣鳳，慶邁躍舟魚。", "俾姒惟何遠，休皇複在諸。東都主人意，歌頌望乘輿。"]'),
('yuding-16','玉壺冰','王季友2','唐','御定全唐诗','yuding','','[]','玉壺知素結，止水複中澄。堅白能虛受，清寒得自凝。',72,'御定全唐詩/json/780.json','["玉壺知素結，止水複中澄。堅白能虛受，清寒得自凝。", "分形同曉鏡，照物掩宵燈。璧映圓光入，人驚爽氣淩。", "金罍何足貴，瑤席幾回升。正值求珪瓚，提攜共飲冰。"]'),
('yuding-17','美玉','南巨川','唐','御定全唐诗','yuding','','[]','抱玉將何適，良工正在斯。有瑕寧自掩，匪石幸君知。',72,'御定全唐詩/json/780.json','["抱玉將何適，良工正在斯。有瑕寧自掩，匪石幸君知。", "雕琢嗟成器，緇磷志不移。飾樽光宴賞，入佩奉威儀。", "象德曾留記，如虹竊可奇。終希逢善價，還得桂林枝。"]'),
('yuding-18','琢玉','丁居晦','唐','御定全唐诗','yuding','','[]','卞玉何時獻，初疑尚在荊。琢來聞制器，價衒勝連城。',72,'御定全唐詩/json/780.json','["卞玉何時獻，初疑尚在荊。琢來聞制器，價衒勝連城。", "虹氣沖天白，雲浮入信貞。佩為廉節德，杯作侈奢名。", "露璞方期辨，雕文幸既成。他山豈無石，寧及此時呈。"]'),
('yuding-19','白珪無玷','辛宏','唐','御定全唐诗','yuding','','[]','片玉表堅貞，逢時寶自呈。色鮮同雪白，光潤奪冰清。',72,'御定全唐詩/json/780.json','["片玉表堅貞，逢時寶自呈。色鮮同雪白，光潤奪冰清。", "皎皎無瑕玷，鏘鏘有佩聲。昆山標重價，垂棘振香名。", "抱璞心常苦，全真道未行。琢磨忻大匠，還冀動連城。"]'),
('yuding-20','鮫人潛織','康翊仁','唐','御定全唐诗','yuding','','[]','珠館馮夷室，靈鮫信所潛。幽閒雲碧牖，滉漾水精簾。',72,'御定全唐詩/json/780.json','["珠館馮夷室，靈鮫信所潛。幽閒雲碧牖，滉漾水精簾。", "機動龍梭躍，絲縈藕淬添。七襄牛女恨，三日大人嫌。", "透手擊吳練，凝冰笑越縑。無因聽劄劄，空想濯纖纖。"]'),
('yuding-21','瑕瑜不相掩','陳中師','唐','御定全唐诗','yuding','','[]','出石溫然玉，瑕瑜素在中。妍媸因異彩，音韻信殊風。',72,'御定全唐詩/json/780.json','["出石溫然玉，瑕瑜素在中。妍媸因異彩，音韻信殊風。", "讓美心方並，求疵意本同。光華開縝密，清潤仰磨礱。", "秀質非攘善，貞姿肯廢忠。今來儻成器，分別在良工。"]'),
('yuding-22','戛玉有餘聲','管雄甫','唐','御定全唐诗','yuding','','[]','戛玉音難盡，凝人思轉清。依稀流戶牖，仿佛在簷楹。',72,'御定全唐詩/json/780.json','["戛玉音難盡，凝人思轉清。依稀流戶牖，仿佛在簷楹。", "更逐松風起，還將澗水並。樂中和舊曲，天際轉餘聲。", "漂渺浮煙遠，溫柔入耳輕。想如君子佩，時得上堂鳴。"]'),
('yuding-23','珠還合浦','鄧陟','唐','御定全唐诗','yuding','','[]','至寶含沖粹，清虛映浦灣。素輝明蕩漾，圓彩色玢ge。',73,'御定全唐詩/json/780.json','["至寶含沖粹，清虛映浦灣。素輝明蕩漾，圓彩色玢ge。", "昔逐諸侯去，今隨太守還。影搖波里月，光動水中山。", "魚目徒相比，驪龍乍可攀。願將車飾用，長得耀君顏。"]'),
('yuding-24','濁水求珠','呂價','唐','御定全唐诗','yuding','','[]','至寶誠難得，潛光在濁流。深沈當處晦，皎潔庶來求。',72,'御定全唐詩/json/780.json','["至寶誠難得，潛光在濁流。深沈當處晦，皎潔庶來求。", "綴履將還用，褰裳必更收。蚌胎應自別，魚目豈能儔。", "日彩逢高鑒，星光詎暗投。不因今日取，泥滓出無由。"]'),
('yuding-25','暗投明珠','苑gT','唐','御定全唐诗','yuding','','[]','至寶欣懷日，良茲豈可儔。神光非易鑒，夜色信難投。',72,'御定全唐詩/json/780.json','["至寶欣懷日，良茲豈可儔。神光非易鑒，夜色信難投。", "錯落珍寰宇，圓明隔淺流。精靈辭合浦，素彩耀神州。", "抱影希人識，承時望帝求。誰言按劍者，猜忌卻生讎。"]'),
('yuding-26','暗投明珠','羅泰','唐','御定全唐诗','yuding','','[]','媚川時未識，在掌共傳名。報德能欺暗，投人自欲明。',72,'御定全唐詩/json/780.json','["媚川時未識，在掌共傳名。報德能欺暗，投人自欲明。", "月臨幽室朗，星沒曉河傾。的皪驪龍頷，熒煌彩鳳呈。", "守恩辭合浦，擅美掩連城。魚目應難近，誰知按劍情。"]'),
('yuding-27','暗投明珠','崔藩','唐','御定全唐诗','yuding','','[]','至寶看懷袖，明珠出後收。向人光不定，離掌勢難留。',72,'御定全唐詩/json/780.json','["至寶看懷袖，明珠出後收。向人光不定，離掌勢難留。", "皎澈虛臨夜，孤圓冷瑩秋。乍來驚月落，疾轉怕星流。", "有淚甘瑕棄，無媒自暗投。今朝感恩處，將欲報隋侯。"]'),
('yuding-28','泗濱得石磬','李勳','唐','御定全唐诗','yuding','','[]','浮磬潛清深，依依呈碧潯。出水見貞質，在懸含玉音。',72,'御定全唐詩/json/780.json','["浮磬潛清深，依依呈碧潯。出水見貞質，在懸含玉音。", "對此喜還歎，幾秋還到今。器古契良覿，韻和諧宿心。", "何為值明鑒，適得離幽沈。自茲入清廟，無複泥沙侵。"]'),
('yuding-0','玄元皇帝應見賀聖祚無疆','趙鐸','唐','御定全唐诗','yuding','','[]','聖主今司契，神功格上玄。豈唯求傅野，更有葉鈞天。',96,'御定全唐詩/json/781.json','["聖主今司契，神功格上玄。豈唯求傅野，更有葉鈞天。", "審夢西山下，焚香北闕前。道光尊聖日，福應集靈年。", "咫尺真容近，巍峨大象懸。觴從百寮獻，形為萬方傳。", "聲教唯皇矣，英威固邈然。慚無美周頌，徒上祝堯篇。"]'),
('yuding-1','太常寺觀舞聖壽樂','徐元鼎','唐','御定全唐诗','yuding','','[]','舞字傳新慶，人文邁舊章。沖融和氣洽，悠遠聖功長。',72,'御定全唐詩/json/781.json','["舞字傳新慶，人文邁舊章。沖融和氣洽，悠遠聖功長。", "盛德流無外，明時樂未央。日華增顧眄，風物助低昂。", "翥鳳方齊首，高鴻忽斷行。雲門與茲曲，同是奉陶唐。"]'),
('yuding-2','太清宮聞滴漏','嚴巨川','唐','御定全唐诗','yuding','','[]','玉漏移中禁，齊車入太清。漸知催辨色，複聽續餘聲。',72,'御定全唐詩/json/781.json','["玉漏移中禁，齊車入太清。漸知催辨色，複聽續餘聲。", "乍逐微風轉，時因雜佩輕。青樓人罷夢，紫陌騎將行。", "殘魄棲初盡，餘寒滴更生。慚非朝謁客，空有振衣情。"]'),
('yuding-3','仲秋太常寺觀公卿輅車拜陵','嚴巨川','唐','御定全唐诗','yuding','','[]','南呂初開律，金風已戒涼。拜陵將展敬，車輅儼成行。',72,'御定全唐詩/json/781.json','["南呂初開律，金風已戒涼。拜陵將展敬，車輅儼成行。", "士庶觀祠禮，公卿習舊章。郊原佳氣引，園寢瑞煙長。", "鹵簿辭丹闕，威儀列太常。聖心何所寄，惟德在無忘。"]'),
('yuding-4','貢舉人謁先師聞雅樂','呂炅','唐','御定全唐诗','yuding','','[]','禮聖來群彥，觀光在此時。聞歌音乍遠，合樂和還遲。',72,'御定全唐詩/json/781.json','["禮聖來群彥，觀光在此時。聞歌音乍遠，合樂和還遲。", "調朗能諧竹，聲微又契絲。輕泠流簨簴，繚繞動纓緌。", "九變將隨節，三終必盡儀。國風由是正，王化自雍熙。"]'),
('yuding-5','望淩煙閣','劉公興','唐','御定全唐诗','yuding','','[]','畫閣淩虛構，遙瞻在九天。丹楹崇壯麗，素壁繪勳賢。',72,'御定全唐詩/json/781.json','["畫閣淩虛構，遙瞻在九天。丹楹崇壯麗，素壁繪勳賢。", "靄靄浮元氣，亭亭出瑞煙。近看分百辟，遠揖誤群仙。", "圖列青雲外，儀刑紫禁前。望中空霽景，驤首幾留連。"]'),
('yuding-6','觀北番謁廟','王卓','唐','御定全唐诗','yuding','','[]','肅肅層城裏，巍巍祖廟清。聖恩覃布濩，異域獻精誠。',96,'御定全唐詩/json/781.json','["肅肅層城裏，巍巍祖廟清。聖恩覃布濩，異域獻精誠。", "冠蓋分行列，戎夷變姓名。禮終齊百拜，心潔盡忠貞。", "瑞氣千重色，簫韶九奏聲。仗移迎日轉，旆動逐風輕。", "休運威儀盛，豐年俎豆盈。不堪慚頌德，空此望簪纓。"]'),
('yuding-7','舞幹羽兩階','石倚','唐','御定全唐诗','yuding','','[]','幹羽能柔遠，前階舞正陳。欲稱文德盛，先表樂聲新。',72,'御定全唐詩/json/781.json','["幹羽能柔遠，前階舞正陳。欲稱文德盛，先表樂聲新。", "肅肅行初列，森森氣益振。動容和律呂，變曲靜風塵。", "化美超千古，恩波及七旬。已知天下服，不獨有苗人。"]'),
('yuding-8','禦制段太尉碑','葉元良','唐','御定全唐诗','yuding','','[]','多難全高節，時清軫聖君。園塋標石篆，雨露降天文。',72,'御定全唐詩/json/781.json','["多難全高節，時清軫聖君。園塋標石篆，雨露降天文。", "義激忠貞沒，詞傷蘭蕙焚。國人皆墮淚，王府已銘勳。", "揭出臨新陌，長留對古墳。睿情幽感處，應使九泉聞。"]'),
('yuding-9','恩賜魏文貞公諸孫舊第，以導直臣','裴大章','唐','御定全唐诗','yuding','','[]','邢茅雖舊錫，邸第是初榮。跡往傷遺事，恩深感直聲。',72,'御定全唐詩/json/781.json','["邢茅雖舊錫，邸第是初榮。跡往傷遺事，恩深感直聲。", "雲孫方慶襲，池館忽春生。古甃開泉井，新禽繞畫楹。", "自然垂帶礪，況複激忠貞。必使千年後，長書竹帛名。"]'),
('yuding-10','恩賜耆老布帛','崔宗','唐','御定全唐诗','yuding','','[]','渙汗中天發，殊私海外存。衰顏逢聖代，華髮受皇恩。',72,'御定全唐詩/json/781.json','["渙汗中天發，殊私海外存。衰顏逢聖代，華髮受皇恩。", "燭物明堯日，垂衣辟禹門。惜時悲落景，賜帛慰餘魂。", "厚澤沾祥詠，微生保子孫。盛明今尚齒，歡洽九衢樽。"]'),
('yuding-11','東都父老望幸','鄭馥','唐','御定全唐诗','yuding','','[]','鸞輿秦地久，羽衛洛陽空。彼土雖憑固，茲川乃得中。',96,'御定全唐詩/json/781.json','["鸞輿秦地久，羽衛洛陽空。彼土雖憑固，茲川乃得中。", "龍顏覲白日，鶴發仰清風。望幸誠逾邈，懷來意不窮。", "昔因封泰嶽，今佇躡維嵩。天地心無異，神祇理亦同。", "翠華翔渭北，玉檢候關東。眾願其難阻，明君早勒功。"]'),
('yuding-12','言行相顧','吳叔達','唐','御定全唐诗','yuding','','[]','聖人垂政教，萬古請常傳。立志言為本，修身行乃先。',72,'御定全唐詩/json/781.json','["聖人垂政教，萬古請常傳。立志言為本，修身行乃先。", "相須甯得闕，相顧在無偏。榮辱當于己，忠貞必動天。", "大名如副寶，至道亦通玄。千里猶能應，何雲邇者焉。"]'),
('yuding-13','言行相顧','孟翱','唐','御定全唐诗','yuding','','[]','將使言堪複，常聞行欲先。比珪斯不玷，修己直如弦。',72,'御定全唐詩/json/781.json','["將使言堪複，常聞行欲先。比珪斯不玷，修己直如弦。", "跬步非全進，吹噓稟自然。當令夫子察，無宿仲由賢。", "正遇興邦際，因懷入署年。坐知清監下，相顧有人焉。"]'),
('yuding-14','人不易知','鄭昉','唐','御定全唐诗','yuding','','[]','如面誠非一，深心豈易知。入秦書十上，投楚歲三移。',96,'御定全唐詩/json/781.json','["如面誠非一，深心豈易知。入秦書十上，投楚歲三移。", "和玉翻為泣，齊竽或濫吹。周行雖有寘，殷鑒在前規。", "寅亮推多士，清通固賞奇。病諸方號哲，敢相反成疵。", "冬日承餘愛，霜雲喜暫披。無令見瞻後，回照複雲疲。"]'),
('yuding-15','早春送郎官出宰','袁求賢','唐','御定全唐诗','yuding','','[]','仙郎今出宰，聖主下憂民。紫陌軒車送，丹墀雨露新。',72,'御定全唐詩/json/781.json','["仙郎今出宰，聖主下憂民。紫陌軒車送，丹墀雨露新。", "趨程猶犯雪，行縣正逢春。粉署時回首，銅章已在身。", "鳴琴化欲展，起草戀空頻。今日都門外，悠悠別漢臣。"]'),
('yuding-16','餞王將軍赴雲中','孟匡明','唐','御定全唐诗','yuding','','[]','一師憑廟略，分閫佐元戎。勢亞彤弓寵，時推金印雄。',72,'御定全唐詩/json/781.json','["一師憑廟略，分閫佐元戎。勢亞彤弓寵，時推金印雄。", "關山橫代北，旌節壯河東。日轉前茅影，春生細柳風。", "飲冰君命速，揮涕餞筵空。佇聽陰山靜，誰爭萬里功。"]'),
('yuding-17','西戎即敘','李子昂','唐','御定全唐诗','yuding','','[]','懸首槁街中，天兵破犬戎。營收低隴月，旗偃度湟風。',96,'御定全唐詩/json/781.json','["懸首槁街中，天兵破犬戎。營收低隴月，旗偃度湟風。", "肅殺三邊勁，蕭條萬里空。元戎咸服罪，餘孽盡輸忠。", "聖理符軒化，仁恩契禹功。降逾洞庭險，梟擬郅支窮。", "已散軍容捷，還資廟算通。今朝觀即敘，非與獻獒同。"]'),
('yuding-0','禁中春松','員南溟','唐','御定全唐诗','yuding','','[]','鬱鬱貞松樹，陰陰在紫宸。蔥蘢偏近日，青翠更宜春。',72,'御定全唐詩/json/782.json','["鬱鬱貞松樹，陰陰在紫宸。蔥蘢偏近日，青翠更宜春。", "雅韻風來起，輕煙霽後新。葉深棲語鶴，枝亞拂朝臣。", "全節長依地，淩雲欲致身。山苗蔭不得，生植荷陶鈞。"]'),
('yuding-1','玉燭','員南溟','唐','御定全唐诗','yuding','','[]','曆象璿璣正，休征玉燭明。四時佳氣滿，五緯太階平。',72,'御定全唐詩/json/782.json','["曆象璿璣正，休征玉燭明。四時佳氣滿，五緯太階平。", "律呂風光至，煙雲瑞色呈。年和知歲稔，道泰喜秋成。", "寰海皇恩被，乾坤至化清。自憐同野老，帝力詎能名。"]'),
('yuding-2','文宣王廟古松','李胄','唐','御定全唐诗','yuding','','[]','列植成均裏，分行古廟前。陰森非一日，蒼翠自何年。',72,'御定全唐詩/json/782.json','["列植成均裏，分行古廟前。陰森非一日，蒼翠自何年。", "寒影煙霜暗，晨光枝葉妍。近簷陰更靜，臨砌色相鮮。", "每愧聞鐘磬，多慚接豆籩。更宜教胄子，於此學貞堅。"]'),
('yuding-3','華林園早梅','鄭述誠','唐','御定全唐诗','yuding','','[]','曉日東樓路，林端見早梅。獨淩寒氣發，不逐眾花開。',72,'御定全唐詩/json/782.json','["曉日東樓路，林端見早梅。獨淩寒氣發，不逐眾花開。", "素彩風前豔，韶光雪後催。蕊香沾紫陌，枝亞拂青苔。", "止渴曾為用，和羹舊有才。含情欲攀折，瞻望幾裴回。"]'),
('yuding-4','龍池春草','宋迪','唐','御定全唐诗','yuding','','[]','鳳闕韶光遍，龍池草色勻。煙波全讓綠，堤柳不爭新。',72,'御定全唐詩/json/782.json','["鳳闕韶光遍，龍池草色勻。煙波全讓綠，堤柳不爭新。", "翻葉迎紅日，飄香借白蘋。幽姿偏占暮，芳意欲留春。", "已勝生金埒，長思藉玉輪。翠華如見幸，正好及茲辰。"]'),
('yuding-5','龍池春草','萬俟造','唐','御定全唐诗','yuding','','[]','暖積龍池綠，晴連御苑春。迎風莖未偃，裛露色猶新。',72,'御定全唐詩/json/782.json','["暖積龍池綠，晴連御苑春。迎風莖未偃，裛露色猶新。", "苒苒分階砌，離離雜荇蘋。細叢依遠渚，疏影落輕淪。", "遲引縈花蝶，偏宜拾翠人。那憐獻賦者，惆悵惜茲辰。"]'),
('yuding-6','貢院樓北新栽小松','錢眾仲','唐','御定全唐诗','yuding','','[]','愛此淩霜操，移來獨佔春。貞心初得地，勁節始依人。',72,'御定全唐詩/json/782.json','["愛此淩霜操，移來獨佔春。貞心初得地，勁節始依人。", "籠月煙猶薄，當軒色轉新。枝低無宿羽，葉靜不留塵。", "每與芝蘭近，常慚雨露均。幸因逢顧盼，生植及茲辰。"]'),
('yuding-7','玉壺冰','錢眾仲','唐','御定全唐诗','yuding','','[]','冬律初陰結，寒冰貯玉壺。霜姿雖異稟，虹氣亦相符。',72,'御定全唐詩/json/782.json','["冬律初陰結，寒冰貯玉壺。霜姿雖異稟，虹氣亦相符。", "對月光宜並，臨池影不孤。貞堅方共濟，同處豈殊途。", "色瑩連城璧，形分照乘珠。提攜今在此，抱素節寧渝。"]'),
('yuding-8','潘安仁戴星看河陽花發','呂敞','唐','御定全唐诗','yuding','','[]','行春潘令至，勤恤戴星光。為政宵忘寢，臨人俗冀康。',72,'御定全唐詩/json/782.json','["行春潘令至，勤恤戴星光。為政宵忘寢，臨人俗冀康。", "曉花迎徑發，新蕊滿城香。秀色沾輕露，鮮輝麗早陽。", "津橋見來往，空霧拂衣裳。桃李今無數，從茲願比方。"]'),
('yuding-9','龜茲聞鶯','呂敞','唐','御定全唐诗','yuding','','[]','邊樹正參差，新鶯複陸離。嬌非胡俗變，啼是漢音移。',72,'御定全唐詩/json/782.json','["邊樹正參差，新鶯複陸離。嬌非胡俗變，啼是漢音移。", "繡羽花間覆，繁聲風外吹。人言曾不辨，鳥語卻相知。", "出谷情何寄，遷喬義取斯。今朝鄉陌伴，幾處坐高枝。"]'),
('yuding-10','好鳥鳴高枝','鄭袞','唐','御定全唐诗','yuding','','[]','養翮非無待，遷喬信自卑。影高遲日度，聲遠好風隨。',72,'御定全唐詩/json/782.json','["養翮非無待，遷喬信自卑。影高遲日度，聲遠好風隨。", "雲拂千尋直，花催百囀奇。驚人時向晚，求友聽應知。", "委質經三歲，先鳴在一枝。上林如可托，弱羽願差池。"]'),
('yuding-11','金穀園花發懷古','張公乂','唐','御定全唐诗','yuding','','[]','今日春風至，花開石氏園。未全紅豔折，半與素光翻。',72,'御定全唐詩/json/782.json','["今日春風至，花開石氏園。未全紅豔折，半與素光翻。", "點綴疏林遍，微明古徑繁。窺臨鶯欲語，寂寞李無言。", "穀變迷鋪錦，台餘認樹萱。川流人事共，千載竟誰論。"]'),
('yuding-12','織鳥','張何','唐','御定全唐诗','yuding','','[]','季春三月裏，戴勝下桑來。映日華冠動，迎風繡羽開。',72,'御定全唐詩/json/782.json','["季春三月裏，戴勝下桑來。映日華冠動，迎風繡羽開。", "候驚蠶事晚，織向女工裁。旅宿依花定，輕飛繞樹回。", "欲過高閣柳，更拂小庭梅。所寄一枝在，寧憂弋者猜。"]'),
('yuding-13','出籠鶻','濮陽瓘','唐','御定全唐诗','yuding','','[]','玉鏃分花袖，金鈴出彩籠。搖心長捧日，逸翰鎮生風。',72,'御定全唐詩/json/782.json','["玉鏃分花袖，金鈴出彩籠。搖心長捧日，逸翰鎮生風。", "一點青霄裏，千聲碧落中。星眸隨狡兔，霜爪落飛鴻。", "每念提攜力，常懷搏擊功。以君能惠好，不敢沒遙空。"]'),
('yuding-14','試越裳貢白雉','王若岩','唐','御定全唐诗','yuding','','[]','素翟宛昭彰，遙遙自越裳。冰晴朝映日，玉羽夜含霜。',72,'御定全唐詩/json/782.json','["素翟宛昭彰，遙遙自越裳。冰晴朝映日，玉羽夜含霜。", "歲月三年遠，山川九澤長。來從碧海路，入見白雲鄉。", "作瑞興周後，登歌美漢皇。朝天資孝理，惠化且無疆。"]'),
('yuding-15','敕賜三相馬','張隨','唐','御定全唐诗','yuding','','[]','上苑驊騮出，中宮詔命傳。九天班錫禮，三相代勞年。',72,'御定全唐詩/json/782.json','["上苑驊騮出，中宮詔命傳。九天班錫禮，三相代勞年。", "顧主聲猶發，追風力正全。鳴珂龍闕下，噴玉鳳池前。", "四足疑雲滅，雙瞳比鏡懸。為因能致遠，今日表求賢。"]'),
('yuding-16','河中獻捷','張隨','唐','御定全唐诗','yuding','','[]','叛將忘恩久，王師不戰通。凱歌千里內，喜氣二儀中。',72,'御定全唐詩/json/782.json','["叛將忘恩久，王師不戰通。凱歌千里內，喜氣二儀中。", "寇盡條山下，兵回漢苑東。將軍初執訊，明主欲論功。", "落日煙塵靜，寒郊壁壘空。蒼生幸無事，自此樂堯風。"]'),
('yuding-17','天驥呈材','徐仁嗣','唐','御定全唐诗','yuding','','[]','至德符天道，龍媒應聖明。追風奇質異，噴玉彩毛輕。',72,'御定全唐詩/json/782.json','["至德符天道，龍媒應聖明。追風奇質異，噴玉彩毛輕。", "躞蹀形難狀，連拳勢乍呈。效材矜逸態，絕影表殊名。", "岐路寧辭遠，關山豈憚行。鹽車雖不駕，今日亦長鳴。"]'),
('yuding-18','天驥呈材','盧征','唐','御定全唐诗','yuding','','[]','異產應堯年，龍媒順制牽。權奇初得地，躞蹀欲行天。',72,'御定全唐詩/json/782.json','["異產應堯年，龍媒順制牽。權奇初得地，躞蹀欲行天。", "詎假調金埒，寧須動玉鞭。嘶風深有戀，逐日定無前。", "周滿誇常馭，燕昭恨不傳。應知流赭汗，來自海西偏。"]'),
('yuding-19','雪夜聽猿吟','顧偉','唐','御定全唐诗','yuding','','[]','寒岩飛暮雪，絕壁夜猿吟。歷歷和群雁，寥寥思客心。',72,'御定全唐詩/json/782.json','["寒岩飛暮雪，絕壁夜猿吟。歷歷和群雁，寥寥思客心。", "繞枝猶避箭，過嶺卻投林。風冷聲偏苦，山寒響更深。", "聽時無有定，靜裏固難尋。一宿扶桑月，聊看懷好音。"]'),
('yuding-20','寒蟬樹','沈鵬','唐','御定全唐诗','yuding','','[]','一葉初飛日，寒蟬益易驚。入林慚織細，依樹愧身輕。',72,'御定全唐詩/json/782.json','["一葉初飛日，寒蟬益易驚。入林慚織細，依樹愧身輕。", "大幹時容息，喬枝或借鳴。心由飲露靜，響為逐風清。", "忝有翩翾分，應憐嘒唳聲。不知微薄影，早晚掛緌纓。"]'),
('yuding-21','臨川羨魚','薛少殷','唐','御定全唐诗','yuding','','[]','曾是歸家客，今年且未旋。游鱗方有待，織網豈能捐。',72,'御定全唐詩/json/782.json','["曾是歸家客，今年且未旋。游鱗方有待，織網豈能捐。", "向水煙波夕，吟風歲月遷。莓苔生古岸，葭菼變清川。", "不逐滄波叟，還宗內外篇。良辰難自擲，此日願忘筌。"]'),
('yuding-22','臨川羨魚','張元正','唐','御定全唐诗','yuding','','[]','有客百愁侵，求魚正在今。廣川何渺漫，高岸幾登臨。',72,'御定全唐詩/json/782.json','["有客百愁侵，求魚正在今。廣川何渺漫，高岸幾登臨。", "風水甯相阻，煙霞豈憚深。不應同逐鹿，詎肯比從禽。", "結網非無力，忘筌自有心。永存芳餌在，佇立思沉沉。"]'),
('yuding-0','答王無功入長安詠秋蓬見示','辛學士','唐','御定全唐诗','yuding','','[]','托根雖異所，飄葉早相依。因風若有便，更共入雲飛。',24,'御定全唐詩/json/783.json','["托根雖異所，飄葉早相依。因風若有便，更共入雲飛。"]'),
('yuding-1','哭李遠','盧尚書','唐','御定全唐诗','yuding','','[]','昨日舟還浙水湄，今朝丹旐欲何為。才收北浦一竿釣，',40,'御定全唐詩/json/783.json','["昨日舟還浙水湄，今朝丹旐欲何為。才收北浦一竿釣，", "不堪舊裏經行處，風木蕭蕭鄰笛悲。"]'),
('yuding-2','湘中怨諷','鄭僕射','唐','御定全唐诗','yuding','','[]','青鷁苦幽獨，隔江相對稀。夜寒蘆葉雨，空作一聲歸。',24,'御定全唐詩/json/783.json','["青鷁苦幽獨，隔江相對稀。夜寒蘆葉雨，空作一聲歸。"]'),
('yuding-3','登汾上閣','鄭中丞','唐','御定全唐诗','yuding','','[]','汾桂秋水闊，宛似到閶門。惆悵江湖思，惟將南客論。',24,'御定全唐詩/json/783.json','["汾桂秋水闊，宛似到閶門。惆悵江湖思，惟將南客論。"]'),
('yuding-4','為禦史銜命出關讞獄，道中看華山有詩','韓常侍','唐','御定全唐诗','yuding','','[]','野麋蒙象暫如犀，心不驚鷗角駭雞。',32,'御定全唐詩/json/783.json','["野麋蒙象暫如犀，心不驚鷗角駭雞。", "一路好山無伴看，斷腸煙景寄猿啼。"]'),
('yuding-5','寄織錦篇與薛郎中','韓常侍','唐','御定全唐诗','yuding','','[]','錦字龍梭織錦篇，鳳凰文采間非煙。',32,'御定全唐詩/json/783.json','["錦字龍梭織錦篇，鳳凰文采間非煙。", "並他時世新花樣，虛費工夫不直錢。"]'),
('yuding-6','和人憶鶴','韓常侍','唐','御定全唐诗','yuding','','[]','拂拂雲衣冠紫煙，已為丁令一千年。',32,'御定全唐詩/json/783.json','["拂拂雲衣冠紫煙，已為丁令一千年。", "留君且伴居山客，幸有松梢明月天。"]'),
('yuding-7','句','韓常侍','唐','御定全唐诗','yuding','','[]','情多不似家山水，夜夜聲聲旁枕流。（《憶山泉》，',23,'御定全唐詩/json/783.json','["情多不似家山水，夜夜聲聲旁枕流。（《憶山泉》，"]'),
('yuding-8','贈米都知','梁補闕','唐','御定全唐诗','yuding','','[]','供奉三朝四十年，聖時流落發衰殘。',32,'御定全唐詩/json/783.json','["供奉三朝四十年，聖時流落發衰殘。", "貪將樂府歌明代，不把清吟換好官。"]'),
('yuding-9','題安國觀','盧尚書','唐','御定全唐诗','yuding','','[]','夕照紗窗起暗塵，青松繞殿不知春。',32,'御定全唐詩/json/783.json','["夕照紗窗起暗塵，青松繞殿不知春。", "君看白首誦經者，半是宮中歌舞人。"]'),
('yuding-10','自商山宿隱居','蘇廣文','唐','御定全唐诗','yuding','','[]','聞道桃源堪避秦，尋幽數日不逢人。煙霞洞裏無雞犬，',40,'御定全唐詩/json/783.json','["聞道桃源堪避秦，尋幽數日不逢人。煙霞洞裏無雞犬，", "醉臥白雲閑入夢，不知何物是吾身。"]'),
('yuding-11','夜歸華川因寄幕府','蘇廣文','唐','御定全唐诗','yuding','','[]','山村寥落野人稀，竹裏衡門掩翠微。溪路夜隨明月入，',40,'御定全唐詩/json/783.json','["山村寥落野人稀，竹裏衡門掩翠微。溪路夜隨明月入，", "汀畔數鷗閑不起，只應知我已忘機。"]'),
('yuding-12','春日過田明府遇焦山人','蘇廣文','唐','御定全唐诗','yuding','','[]','陶公歸隱白雲溪，買得春泉溉藥畦。夜靜林間風虎嘯，',40,'御定全唐詩/json/783.json','["陶公歸隱白雲溪，買得春泉溉藥畦。夜靜林間風虎嘯，", "相見只言秦漢事，武陵溪裏草萋萋。"]'),
('yuding-13','題升山','任生','唐','御定全唐诗','yuding','','[]','城外升山寺，城中望宛然。及登無半日，欲到已經年。',24,'御定全唐詩/json/783.json','["城外升山寺，城中望宛然。及登無半日，欲到已經年。"]'),
('yuding-14','投曹文姬詩','任生','唐','御定全唐诗','yuding','','[]','玉皇前殿掌書仙，一染塵心下九天。',32,'御定全唐詩/json/783.json','["玉皇前殿掌書仙，一染塵心下九天。", "莫怪濃香熏骨膩，雲衣曾惹禦爐煙。"]'),
('yuding-15','絕句','吳公','唐','御定全唐诗','yuding','','[]','去國投茲土，編茅隱舊蹤。年年秋水上，獨對數株松。',24,'御定全唐詩/json/783.json','["去國投茲土，編茅隱舊蹤。年年秋水上，獨對數株松。"]'),
('yuding-16','獻盧常侍','曹生','唐','御定全唐诗','yuding','','[]','拜玉亭前閑送客，此時孤恨感離鄉。',32,'御定全唐詩/json/783.json','["拜玉亭前閑送客，此時孤恨感離鄉。", "尋思往歲絕纓事，肯向朱門泣夜長。"]'),
('yuding-17','賦新月','繆氏子','唐','御定全唐诗','yuding','','[]','初月如弓未上弦，分明掛在碧霄邊。',32,'御定全唐詩/json/783.json','["初月如弓未上弦，分明掛在碧霄邊。", "時人莫道蛾眉小，三五團圓照滿天。"]'),
('yuding-18','悼妓詩','京兆韋氏子','唐','御定全唐诗','yuding','','[]','惆悵金泥簇蝶裙，春來猶見伴行雲。',32,'御定全唐詩/json/783.json','["惆悵金泥簇蝶裙，春來猶見伴行雲。", "不教佈施剛留得，渾似初逢李少君。"]'),
('yuding-0','長寧公主宅流杯','景龍文館士','唐','御定全唐诗','yuding','','[]','憑高瞰迥足怡心，菌閣桃源不暇尋。',32,'御定全唐詩/json/784.json','["憑高瞰迥足怡心，菌閣桃源不暇尋。", "餘雪依林成玉樹，殘霙點岫即瑤岑。"]'),
('yuding-1','侍宴桃花園詠桃花應制','神龍從臣','唐','御定全唐诗','yuding','','[]','源水叢花無數開，丹跗紅萼間青梅。',32,'御定全唐詩/json/784.json','["源水叢花無數開，丹跗紅萼間青梅。", "從今結子三千歲，預喜仙遊複摘來。"]'),
('yuding-2','玉龍子詩','天寶時人','唐','御定全唐诗','yuding','','[]','聖運潛符瑞玉龍，自興雲雨更無蹤。',32,'御定全唐詩/json/784.json','["聖運潛符瑞玉龍，自興雲雨更無蹤。", "不如渭水沙中得，爭保鑾輿複九重。"]'),
('yuding-3','寄兄','僖宗北省官','唐','御定全唐诗','yuding','','[]','涉江今日恨偏多，援筆長籲欲奈何。',32,'御定全唐詩/json/784.json','["涉江今日恨偏多，援筆長籲欲奈何。", "倘使淚流西去得，便應添作錦江波。"]'),
('yuding-4','題屈原祠','洪州將軍','唐','御定全唐诗','yuding','','[]','蒼藤古木幾經春，舊祀祠堂小水濱。',32,'御定全唐詩/json/784.json','["蒼藤古木幾經春，舊祀祠堂小水濱。", "行客謾陳三酎酒，大夫元是獨醒人。"]'),
('yuding-5','題端正樹','貞元文士','唐','御定全唐诗','yuding','','[]','昔日偏沾雨露榮，德皇西幸賜嘉名。',32,'御定全唐詩/json/784.json','["昔日偏沾雨露榮，德皇西幸賜嘉名。", "馬嵬此去無多地，合向楊妃塚上生。"]'),
('yuding-6','寄內詩','河北士人','唐','御定全唐诗','yuding','','[]','握筆題詩易，荷戈征戍難。慣從鴛被暖，怯向雁門寒。',48,'御定全唐詩/json/784.json','["握筆題詩易，荷戈征戍難。慣從鴛被暖，怯向雁門寒。", "瘦盡寬衣帶，啼多漬枕檀。試留青黛著，回日畫眉看。"]'),
('yuding-7','代妻答詩','河北士人','唐','御定全唐诗','yuding','','[]','蓬鬢荊釵世所稀，布裙猶是嫁時衣。',32,'御定全唐詩/json/784.json','["蓬鬢荊釵世所稀，布裙猶是嫁時衣。", "胡麻好種無人種，合是歸時底不歸。"]'),
('yuding-8','丙申歲詩','元和舉子','唐','御定全唐诗','yuding','','[]','元和天子丙申年，三十三人同得仙。',32,'御定全唐詩/json/784.json','["元和天子丙申年，三十三人同得仙。", "袍似爛銀文似錦，相將白日上青天。"]'),
('yuding-9','刺安南事詩','懿宗朝舉子','唐','御定全唐诗','yuding','','[]','南荒不擇吏，致我交趾覆。聯綿三四年，致我交趾辱。',132,'御定全唐詩/json/784.json','["南荒不擇吏，致我交趾覆。聯綿三四年，致我交趾辱。", "懦者鬥則退，武者兵益黷。軍容滿天下，戰將多金玉。", "刮得齊民瘡，分為猛士祿。雄雄許昌師，忠武冠其族。", "去為萬騎風，住為一川肉。時有殘卒回，千門萬戶哭。", "哀聲動閭裏，怨氣成山谷。誰能聽鼓聲，不忍看金鏃。", "念此堪淚流，悠悠潁川綠。"]'),
('yuding-10','歌','白衫舉子','唐','御定全唐诗','yuding','','[]','執板狂歌乞個錢，塵中流浪且隨緣。',32,'御定全唐詩/json/784.json','["執板狂歌乞個錢，塵中流浪且隨緣。", "直饒到老常如此，猶勝危時弄化權。"]'),
('yuding-11','睹野花思京師舊游','唐末朝士','唐','御定全唐诗','yuding','','[]','曾過街西看牡丹，牡丹才謝便心闌。',32,'御定全唐詩/json/784.json','["曾過街西看牡丹，牡丹才謝便心闌。", "如今變作村園眼，鼓子花開也喜歡。"]'),
('yuding-12','哥舒歌','西鄙人','唐','御定全唐诗','yuding','','[]','北斗七星高，哥舒夜帶刀。至今窺牧馬，不敢過臨洮。',24,'御定全唐詩/json/784.json','["北斗七星高，哥舒夜帶刀。至今窺牧馬，不敢過臨洮。"]'),
('yuding-13','答人','太上隱者','唐','御定全唐诗','yuding','','[]','偶來松樹下，高枕石頭眠。山中無曆日，寒盡不知年。',24,'御定全唐詩/json/784.json','["偶來松樹下，高枕石頭眠。山中無曆日，寒盡不知年。"]'),
('yuding-14','向竹吟','黃山隱','唐','御定全唐诗','yuding','','[]','積塵為太山，掬水成東海。富貴有時乖，希夷無日改。',48,'御定全唐詩/json/784.json','["積塵為太山，掬水成東海。富貴有時乖，希夷無日改。", "絳節出崆峒，霓衣發光彩。古者有七賢，六個今何在。"]'),
('yuding-15','歌','婺州山中人','唐','御定全唐诗','yuding','','[]','靜居青嶂裏，高嘯紫煙中。塵世連仙界，瓊田前路通。',24,'御定全唐詩/json/784.json','["靜居青嶂裏，高嘯紫煙中。塵世連仙界，瓊田前路通。"]'),
('yuding-16','五子之歌','同穀子','唐','御定全唐诗','yuding','','[]','邦惟固本自安寧，臨下常須馭朽驚。',160,'御定全唐詩/json/784.json','["邦惟固本自安寧，臨下常須馭朽驚。", "何事十旬遊不返，禍胎從此召殷兵。", "酒色聲禽號四荒，那堪峻宇又雕牆。", "靜思今古為君者，未或因茲不滅亡。", "唯彼陶唐有冀方，少年都不解思量。", "如今算得當時事，首為盤游亂紀綱。", "明明我祖萬邦君，典則貽將示子孫。", "惆悵太康荒墜後，覆宗絕祀滅其門。", "仇讎萬姓遂無依，顏厚何曾解忸怩。", "五子既歌邦已失，一場前事悔難追。"]'),
('yuding-17','獻公佐詩','崔公佐客','唐','御定全唐诗','yuding','','[]','破額襆頭衫也穿，使君猶許對華筵。',32,'御定全唐詩/json/784.json','["破額襆頭衫也穿，使君猶許對華筵。", "今朝幸倚文章守，遮莫青蛾笑揭天。"]'),
('yuding-18','贈妓茂英','洛中舉子','唐','御定全唐诗','yuding','','[]','憶昔當初過柳樓，茂英年小尚嬌羞。隔窗未省聞高語，',40,'御定全唐詩/json/784.json','["憶昔當初過柳樓，茂英年小尚嬌羞。隔窗未省聞高語，", "彈弦酌酒話前事，零落碧雲生暮愁。"]'),
('yuding-19','又贈','洛中舉子','唐','御定全唐诗','yuding','','[]','少插花枝少下籌，須防女伴妒風流。',32,'御定全唐詩/json/784.json','["少插花枝少下籌，須防女伴妒風流。", "坐中若打占相令，除卻尚書莫點頭。"]'),
('yuding-20','寄故姬','江陵士子','唐','御定全唐诗','yuding','','[]','陰雲冪冪下陽臺，惹著襄王更不回。五度看花空有淚，',40,'御定全唐詩/json/784.json','["陰雲冪冪下陽臺，惹著襄王更不回。五度看花空有淚，", "惆悵高麗坡底宅，春光無複下山來。"]'),
('yuding-21','吟','織錦人','唐','御定全唐诗','yuding','','[]','學織繚綾功未多，亂拈機杼錯拋梭。',32,'御定全唐詩/json/784.json','["學織繚綾功未多，亂拈機杼錯拋梭。", "莫教官錦行家見，把此文章笑殺他。"]'),
('yuding-22','句','織錦人','唐','御定全唐诗','yuding','','[]','如今不重文章士，莫把文章誇向人。',16,'御定全唐詩/json/784.json','["如今不重文章士，莫把文章誇向人。"]'),
('yuding-23','送南中尉','吏部選人','唐','御定全唐诗','yuding','','[]','羨君初拜職，嗟我獨無名。且是正員尉，全勝兼試卿。',24,'御定全唐詩/json/784.json','["羨君初拜職，嗟我獨無名。且是正員尉，全勝兼試卿。"]'),
('yuding-24','題紫微觀','建業蔔者','唐','御定全唐诗','yuding','','[]','昨日朝天過紫微，醮壇風冷杏花稀。',32,'御定全唐詩/json/784.json','["昨日朝天過紫微，醮壇風冷杏花稀。", "碧桃泥我傳消息，何事人間更不歸。"]'),
('yuding-25','題鄧仙客墓','天嶠遊人','唐','御定全唐诗','yuding','','[]','鶴老芝田雞在籠，上清那與俗塵同。',32,'御定全唐詩/json/784.json','["鶴老芝田雞在籠，上清那與俗塵同。", "既言白日升仙去，何事人間有殯宮。"]'),
('yuding-26','題故翠微宮','驪山遊人','唐','御定全唐诗','yuding','','[]','翠微寺本翠微宮，樓閣亭台幾十重。',32,'御定全唐詩/json/784.json','["翠微寺本翠微宮，樓閣亭台幾十重。", "天子不來僧又去，樵夫時倒一株松。"]'),
('yuding-27','吟','衡州舟子','唐','御定全唐诗','yuding','','[]','野鵲灘西一棹孤，月光遙接洞庭湖。',32,'御定全唐詩/json/784.json','["野鵲灘西一棹孤，月光遙接洞庭湖。", "堪嗟回雁峰前過，望斷家山一字無。"]'),
('yuding-28','月夜','華山老人','唐','御定全唐诗','yuding','','[]','澗水泠泠聲不絕，溪流茫茫野花發。',32,'御定全唐詩/json/784.json','["澗水泠泠聲不絕，溪流茫茫野花發。", "自去自來人不知，歸時常對空山月。"]'),
('yuding-29','終南','終南山翁','唐','御定全唐诗','yuding','','[]','霜鶴鳴時夕風急，亂鴉又向寒林集。',32,'御定全唐詩/json/784.json','["霜鶴鳴時夕風急，亂鴉又向寒林集。", "此君輟棹悲且吟，獨對蓮花一峰立。"]'),
('yuding-30','大慶堂賜宴元璫有詩呈吳越王','吳越人','唐','御定全唐诗','yuding','','[]','非為親賢展綺筵，恒常甯敢恣遊盤。綠搓楊柳綿初軟，',40,'御定全唐詩/json/784.json','["非為親賢展綺筵，恒常甯敢恣遊盤。綠搓楊柳綿初軟，", "笙歌風緊人酣醉，卻繞珍叢爛熳看。"]'),
('yuding-31','又和','吳越人','唐','御定全唐诗','yuding','','[]','櫻桃花下會親賢，風遠銅壺轉露盤。蝶下粉牆梅乍折，',40,'御定全唐詩/json/784.json','["櫻桃花下會親賢，風遠銅壺轉露盤。蝶下粉牆梅乍折，", "狂簡斐然吟詠足，卻邀群彥重吟看。"]'),
('yuding-32','再和','吳越人','唐','御定全唐诗','yuding','','[]','我有嘉賓宴乍歡，畫簾紋細鳳雙盤。影籠沼沚修篁密，',40,'御定全唐詩/json/784.json','["我有嘉賓宴乍歡，畫簾紋細鳳雙盤。影籠沼沚修篁密，", "櫻桃零落紅桃媚，更俟旬餘共醉看。"]'),
('yuding-33','重和','吳越人','唐','御定全唐诗','yuding','','[]','冷宴殷勤展小園，舞鞇柔軟彩虯盤。篸花盡日疑頭重，',40,'御定全唐詩/json/784.json','["冷宴殷勤展小園，舞鞇柔軟彩虯盤。篸花盡日疑頭重，", "文章天子文章別，八采盧郎未可看。"]'),
('yuding-34','禦制春遊長句','吳越人','唐','御定全唐诗','yuding','','[]','天意分明道已光，春遊嘉景勝仙鄉。玉爐煙直風初靜，',72,'御定全唐詩/json/784.json','["天意分明道已光，春遊嘉景勝仙鄉。玉爐煙直風初靜，", "黃鶯歷歷啼紅樹，紫燕關關語畫梁。低檻晚晴籠翡翠，", "比屋管弦呈妙曲，連營羅綺鬥時妝。全吳霸越千年後，"]'),
('yuding-0','明月湖醉後薔薇花歌','無名氏','唐','御定全唐诗','yuding','','[]','萬朵當軒紅灼灼，晚陰照水塵不著。西施醉後情不禁，',136,'御定全唐詩/json/785.json','["萬朵當軒紅灼灼，晚陰照水塵不著。西施醉後情不禁，", "深紅淺綠狀不得，日斜池畔香風來。紅能柔，綠能軟，", "白髮使君思帝鄉，驅妻領女游花傍。持杯憶著曲江事，", "笙歌日日征教坊，傾國名倡盡佳麗。我曾此處同諸生，", "一朝失勢當如此，萬事如灰壯心死。誰知奏禦數萬言，", "莫思身外窮通事，且醉花前一百壺。"]'),
('yuding-1','春二首','無名氏','唐','御定全唐诗','yuding','','[]','褭褭東風吹水國，金鴉影暖南山北。蒲抽小劍割湘波，',80,'御定全唐詩/json/785.json','["褭褭東風吹水國，金鴉影暖南山北。蒲抽小劍割湘波，", "綠桑枝下見桃葉，回看青雲空斷腸。", "烏足遲遲日宮裏，天門擊鼓龍蛇起。風師剪翠換枯條，", "繡衣白馬不歸來，雙成倚檻春心醉。"]'),
('yuding-2','夏','無名氏','唐','御定全唐诗','yuding','','[]','赤帝旗迎火雲起，南山石裂吳牛死。繡楹夜夜箔蝦須，',40,'御定全唐詩/json/785.json','["赤帝旗迎火雲起，南山石裂吳牛死。繡楹夜夜箔蝦須，", "漢帝高堂汗若珠，班姬明月無停影。"]'),
('yuding-3','秋','無名氏','唐','御定全唐诗','yuding','','[]','月色驅秋下穹昊，梁間燕語辭巢早。古苔凝紫貼瑤階，',40,'御定全唐詩/json/785.json','["月色驅秋下穹昊，梁間燕語辭巢早。古苔凝紫貼瑤階，", "粉娥恨骨不勝衣，映門楚碧蟬聲老。"]'),
('yuding-4','冬','無名氏','唐','御定全唐诗','yuding','','[]','蒼茫枯磧陰雲滿，古木號空晝光短。雲擁三峰嶽色低，',40,'御定全唐詩/json/785.json','["蒼茫枯磧陰雲滿，古木號空晝光短。雲擁三峰嶽色低，", "澤國龍蛇凍不伸，南山瘦柏銷殘翠。"]'),
('yuding-5','雞頭','無名氏','唐','御定全唐诗','yuding','','[]','湖浪參差疊寒玉，水仙曉展缽盤綠。淡黃根老栗皺圓，',40,'御定全唐詩/json/785.json','["湖浪參差疊寒玉，水仙曉展缽盤綠。淡黃根老栗皺圓，", "叢叢引觜傍蓮洲，滿川恐作天雞哭。"]'),
('yuding-6','紅薔薇','無名氏','唐','御定全唐诗','yuding','','[]','九天碎霞明澤國，造化工夫潛剪刻。淺碧眉長約細枝，',40,'御定全唐詩/json/785.json','["九天碎霞明澤國，造化工夫潛剪刻。淺碧眉長約細枝，", "謝豹聲催麥隴秋，春風吹落猩猩血。"]'),
('yuding-7','斑竹簟','無名氏','唐','御定全唐诗','yuding','','[]','龍鱗滿床波浪濕，血光點點湘娥泣。一片晴霞凍不飛，',40,'御定全唐詩/json/785.json','["龍鱗滿床波浪濕，血光點點湘娥泣。一片晴霞凍不飛，", "閑窗獨臥曉不起，冷浸羈魂錦江裏。"]'),
('yuding-8','聽琴','無名氏','唐','御定全唐诗','yuding','','[]','六律鏗鏘間宮征，伶倫寫入梧桐尾。七條瘦玉叩寒星，',40,'御定全唐詩/json/785.json','["六律鏗鏘間宮征，伶倫寫入梧桐尾。七條瘦玉叩寒星，", "田文墮淚曲未終，子規啼血哀猿死。"]'),
('yuding-9','石榴','無名氏','唐','御定全唐诗','yuding','','[]','蟬嘯秋雲槐葉齊，石榴香老庭枝低。流霞色染紫罌粟，',40,'御定全唐詩/json/785.json','["蟬嘯秋雲槐葉齊，石榴香老庭枝低。流霞色染紫罌粟，", "蕭娘初嫁嗜甘酸，嚼破水精千萬粒。"]'),
('yuding-10','秦家行','無名氏','唐','御定全唐诗','yuding','','[]','彗孛飛光照天地，九天瓦裂屯冤氣。鬼哭聲聲怨趙高，',40,'御定全唐詩/json/785.json','["彗孛飛光照天地，九天瓦裂屯冤氣。鬼哭聲聲怨趙高，", "劍上忠臣血未幹，沛公已向函關入。"]'),
('yuding-11','小蘇家','無名氏','唐','御定全唐诗','yuding','','[]','雙月謳cA輾秋碧，細風斜掩神仙宅。麥門冬長馬鬣青，',41,'御定全唐詩/json/785.json','["雙月謳cA輾秋碧，細風斜掩神仙宅。麥門冬長馬鬣青，", "堂內月娥橫剪波，倚門腸斷蝦須隔。"]'),
('yuding-12','斑竹','無名氏','唐','御定全唐诗','yuding','','[]','濃綠疏莖繞湘水，春風抽出蛟龍尾。色抱霜花粉黛光，',48,'御定全唐詩/json/785.json','["濃綠疏莖繞湘水，春風抽出蛟龍尾。色抱霜花粉黛光，", "殷痕苦雨洗不落，猶帶湘娥淚血腥。嫋娜梢頭掃秋月，"]'),
('yuding-13','天竺國胡僧水晶念珠','無名氏','唐','御定全唐诗','yuding','','[]','天竺胡僧踏雲立，紅精素貫鮫人泣。細影疑隨焰火銷，',48,'御定全唐詩/json/785.json','["天竺胡僧踏雲立，紅精素貫鮫人泣。細影疑隨焰火銷，", "若非葉下滴秋露，則是井底圓春冰。淒清妙麗應難並，"]'),
('yuding-14','白雪歌','無名氏','唐','御定全唐诗','yuding','','[]','皇穹何處飛瓊屑，散下人間作春雪。五花馬踏白雲衢，',72,'御定全唐詩/json/785.json','["皇穹何處飛瓊屑，散下人間作春雪。五花馬踏白雲衢，", "寒郊複疊鋪柳絮，古磧爛熳吹蘆花。流泉不下孤汀咽，", "拂戶初疑粉蝶飛，看山又訝白鷗歸。孫康凍死讀書闈，"]'),
('yuding-15','琵琶','無名氏','唐','御定全唐诗','yuding','','[]','粉胸繡臆誰家女，香撥星星共春語。七盤嶺上走鸞鈴，',72,'御定全唐詩/json/785.json','["粉胸繡臆誰家女，香撥星星共春語。七盤嶺上走鸞鈴，", "山僧撲破琉璃缽，壯士擊折珊瑚鞭。珊瑚鞭折聲交戛，", "滿坐紅妝盡淚垂，望鄉之客不勝悲。曲終調絕忽飛去，"]'),
('yuding-16','傷哉行','無名氏','唐','御定全唐诗','yuding','','[]','兔走烏飛不相見，人事依稀速如電。王母夭桃一度開，',48,'御定全唐詩/json/785.json','["兔走烏飛不相見，人事依稀速如電。王母夭桃一度開，", "秋雨無情不惜花，芙蓉一一驚顛倒。勸君莫謾栽荊棘，"]'),
('yuding-17','留贈偃師主人','無名氏','唐','御定全唐诗','yuding','','[]','孤城漏未殘，徒侶拂征鞍。洛北去愁遠，淮南歸夢闌。',48,'御定全唐詩/json/785.json','["孤城漏未殘，徒侶拂征鞍。洛北去愁遠，淮南歸夢闌。", "曉燈回壁暗，晴雪捲簾寒。更盡主人酒，出門行路難。"]'),
('yuding-18','長門','無名氏','唐','御定全唐诗','yuding','','[]','悵望黃金屋，恩衰似越逃。花生針眼刺，月送剪腸刀。',48,'御定全唐詩/json/785.json','["悵望黃金屋，恩衰似越逃。花生針眼刺，月送剪腸刀。", "地近歡娛遠，天低雨露高。時看回輦處，淚臉濕夭桃。"]'),
('yuding-19','宴李家宅','無名氏','唐','御定全唐诗','yuding','','[]','畫屏深掩瑞雲光，羅綺花飛白玉堂。銀榼酒傾魚尾倒，',40,'御定全唐詩/json/785.json','["畫屏深掩瑞雲光，羅綺花飛白玉堂。銀榼酒傾魚尾倒，", "今日恩榮許同聽，不辭沈醉一千觴。"]'),
('yuding-20','長信宮','無名氏','唐','御定全唐诗','yuding','','[]','細草侵階亂碧鮮，宮門深鎖綠楊天。珠簾欲卷抬秋水，',40,'御定全唐詩/json/785.json','["細草侵階亂碧鮮，宮門深鎖綠楊天。珠簾欲卷抬秋水，", "獨挑殘燭魂堪斷，卻恨青蛾誤少年。"]'),
('yuding-21','驪山感懷','無名氏','唐','御定全唐诗','yuding','','[]','武帝尋仙駕海遊，禁門高閉水空流。深宮帶日年年色，',40,'御定全唐詩/json/785.json','["武帝尋仙駕海遊，禁門高閉水空流。深宮帶日年年色，", "晚來惆悵無人會，雲雨能飛傍玉樓。"]'),
('yuding-22','絕句','無名氏','唐','御定全唐诗','yuding','','[]','石沈遼海闊，劍別楚山長。會合知無日，離心滿夕陽。',24,'御定全唐詩/json/785.json','["石沈遼海闊，劍別楚山長。會合知無日，離心滿夕陽。"]'),
('yuding-23','聽唱鷓鴣','無名氏','唐','御定全唐诗','yuding','','[]','金穀歌傳第一流，鷓鴣清怨碧雲愁。',32,'御定全唐詩/json/785.json','["金穀歌傳第一流，鷓鴣清怨碧雲愁。", "夜來省得曾聞處，萬里月明湘水流。"]'),
('yuding-24','雜詩','無名氏','唐','御定全唐诗','yuding','','[]','勸君莫惜金縷衣，勸君須惜少年時。',384,'御定全唐詩/json/785.json','["勸君莫惜金縷衣，勸君須惜少年時。", "有花堪折直須折，莫待無花空折枝。", "青天無雲月如燭，露泣梨花白如玉。", "子規一夜啼到明，美人獨在空房宿。", "空賜羅衣不賜恩，一熏香後一銷魂。", "雖然舞袖何曾舞，常對春風裛淚痕。", "不洗殘妝憑繡床，也同女伴繡鴛鴦。", "回針刺到雙飛處，憶著征夫淚數行。", "眼想心思夢裏驚，無人知我此時情。", "不如池上鴛鴦鳥，雙宿雙飛過一生。", "一去遼陽系夢魂，忽傳征騎到中門。", "紗窗不肯施紅粉，徒遣蕭郎問淚痕。", "鶯啼露冷酒初醒，罨畫樓西曉角鳴。", "翠羽帳中人夢覺，寶釵斜墜枕函聲。", "行人南北分征路，流水東西接禦溝。", "終日坡前怨離別，謾名長樂是長愁。", "偏倚繡床愁不起，雙垂玉箸翠鬟低。", "捲簾相待無消息，夜合花前日又西。", "悔將淚眼向東開，特地愁從望裏來。", "三十六峰猶不見，況伊如燕這身材。", "滿目笙歌一段空，萬般離恨總隨風。", "多情為謝殘陽意，與展晴霞片片紅。", "兩心不語暗知情，燈下裁縫月下行。", "行到階前知未睡，夜深聞放剪刀聲。"]'),
('yuding-25','初過漢江','無名氏','唐','御定全唐诗','yuding','','[]','襄陽好向峴亭看，人物蕭條值歲闌。',32,'御定全唐詩/json/785.json','["襄陽好向峴亭看，人物蕭條值歲闌。", "為報習家多置酒，夜來風雪過江寒。"]'),
('yuding-26','讀庾信集','無名氏','唐','御定全唐诗','yuding','','[]','四朝十帝盡風流，建業長安兩醉遊。',32,'御定全唐詩/json/785.json','["四朝十帝盡風流，建業長安兩醉遊。", "惟有一篇楊柳曲，江南江北為君愁。"]'),
('yuding-0','題長樂驛壁','無名氏','唐','御定全唐诗','yuding','','[]','三十驊騮一烘塵，來時不鎖杏園春。',32,'御定全唐詩/json/786.json','["三十驊騮一烘塵，來時不鎖杏園春。", "楊花滿地如飛雪，應有偷遊曲水人。"]'),
('yuding-1','絕句','無名氏','唐','御定全唐诗','yuding','','[]','傳聞天子訪沈淪，萬里懷書西入秦。',32,'御定全唐詩/json/786.json','["傳聞天子訪沈淪，萬里懷書西入秦。", "早知不用無媒客，恨別江南楊柳春。"]'),
('yuding-2','《題取經詩','無名氏','唐','御定全唐诗','yuding','','[]','晉宋齊梁唐代間，高僧求法離長安。去人成百歸無十，',40,'御定全唐詩/json/786.json','["晉宋齊梁唐代間，高僧求法離長安。去人成百歸無十，", "後賢如未諳斯旨，往往將經容易看。"]'),
('yuding-3','題水心寺水軒','無名氏','唐','御定全唐诗','yuding','','[]','分飛南渡春風晚，卻返家林事業空。',32,'御定全唐詩/json/786.json','["分飛南渡春風晚，卻返家林事業空。", "無限離情似楊柳，萬條垂向楚江東。"]'),
('yuding-4','王昭君','無名氏','唐','御定全唐诗','yuding','','[]','猗蘭恩寵歇，昭陽幸禦稀。朝辭漢闕去，夕見胡塵飛。',36,'御定全唐詩/json/786.json','["猗蘭恩寵歇，昭陽幸禦稀。朝辭漢闕去，夕見胡塵飛。", "寄信秦樓下，因書秋雁歸。"]'),
('yuding-5','王昭君','無名氏','唐','御定全唐诗','yuding','','[]','一回望月一回悲，望月月移人不移。',32,'御定全唐詩/json/786.json','["一回望月一回悲，望月月移人不移。", "何時得見漢朝使，為妾傳書斬畫師。"]'),
('yuding-6','粉箋題詩','無名氏','唐','御定全唐诗','yuding','','[]','三月江南花滿枝，風輕簾幕燕爭飛。',32,'御定全唐詩/json/786.json','["三月江南花滿枝，風輕簾幕燕爭飛。", "遊人休惜夜秉燭，楊柳陰濃春欲歸。"]'),
('yuding-7','詠美人騎馬','無名氏','唐','御定全唐诗','yuding','','[]','駿馬嬌仍穩，春風灞岸晴。促來金鐙短，扶上玉人輕。',48,'御定全唐詩/json/786.json','["駿馬嬌仍穩，春風灞岸晴。促來金鐙短，扶上玉人輕。", "帽束雲鬟亂，鞭籠翠袖明。不知從此去，何處更傾城。"]'),
('yuding-8','六言詩','無名氏','唐','御定全唐诗','yuding','','[]','把酒留君聽琴，那堪歲暮離心。霜葉無風自落，',35,'御定全唐詩/json/786.json','["把酒留君聽琴，那堪歲暮離心。霜葉無風自落，", "望盡青山猶在，不知何處相尋。"]'),
('yuding-9','胡笳曲','無名氏','唐','御定全唐诗','yuding','','[]','月明星稀霜滿野，氈車夜宿陰山下。',32,'御定全唐詩/json/786.json','["月明星稀霜滿野，氈車夜宿陰山下。", "漢家自失李將軍，單于公然來牧馬。"]'),
('yuding-10','桃源行送友人','無名氏','唐','御定全唐诗','yuding','','[]','武陵川徑入幽遐，中有雞犬秦人家，家傍流水多桃花。',96,'御定全唐詩/json/786.json','["武陵川徑入幽遐，中有雞犬秦人家，家傍流水多桃花。", "桃花兩邊種來久，流水一道何時有。垂條落蕊暗春風，", "時有仙鳥來銜花，曾無世人此攜手。可憐不知若為名，", "相見維舟登覽處，紅堤綠岸宛然成。多君此去從仙隱，"]'),
('yuding-11','唐衢墓','無名氏','唐','御定全唐诗','yuding','','[]','京洛先生三尺墳，陰風慘慘土和雲。',32,'御定全唐詩/json/786.json','["京洛先生三尺墳，陰風慘慘土和雲。", "從來有感君皆哭，今日無君誰哭君。"]'),
('yuding-12','宮詞','無名氏','唐','御定全唐诗','yuding','','[]','花萼樓前春正濃，濛濛柳絮舞晴空。',32,'御定全唐詩/json/786.json','["花萼樓前春正濃，濛濛柳絮舞晴空。", "金錢擲罷嬌無力，笑倚欄幹屈曲中。"]'),
('yuding-13','拋球詩','無名氏','唐','御定全唐诗','yuding','','[]','侍宴黃昏未肯休，玉階夜色月如流。',32,'御定全唐詩/json/786.json','["侍宴黃昏未肯休，玉階夜色月如流。", "朝來自詫承恩最，笑倩傍人認繡球。"]'),
('yuding-14','豔歌','無名氏','唐','御定全唐诗','yuding','','[]','月裏嫦娥不畫眉，只將雲霧作羅衣。',32,'御定全唐詩/json/786.json','["月裏嫦娥不畫眉，只將雲霧作羅衣。", "不知夢逐青鸞去，猶把花枝蓋面歸。"]'),
('yuding-15','楊柳枝','無名氏','唐','御定全唐诗','yuding','','[]','萬里長江一帶開，岸邊楊柳幾千栽。',32,'御定全唐詩/json/786.json','["萬里長江一帶開，岸邊楊柳幾千栽。", "錦帆未落西風起，惆悵龍舟去不回。"]'),
('yuding-16','河中石刻','無名氏','唐','御定全唐诗','yuding','','[]','雨滴空階曉，無心換夕香。井梧花落盡，一半在銀床。',24,'御定全唐詩/json/786.json','["雨滴空階曉，無心換夕香。井梧花落盡，一半在銀床。"]'),
('yuding-17','古硯','無名氏','唐','御定全唐诗','yuding','','[]','癖性愛古物，終歲求不得。昨朝得古硯，蘭河灘之側。',48,'御定全唐詩/json/786.json','["癖性愛古物，終歲求不得。昨朝得古硯，蘭河灘之側。", "波濤所擊觸，背面生隟隙。質狀樸且醜，令人作不得。"]'),
('yuding-18','絕句','無名氏','唐','御定全唐诗','yuding','','[]','釣罷孤舟系葦梢，酒開新甕鮓開包。',32,'御定全唐詩/json/786.json','["釣罷孤舟系葦梢，酒開新甕鮓開包。", "自從江浙為漁父，二十餘年手不叉。"]'),
('yuding-19','題童氏畫','無名氏','唐','御定全唐诗','yuding','','[]','林下材華雖可尚，筆端人物更清妍。',32,'御定全唐詩/json/786.json','["林下材華雖可尚，筆端人物更清妍。", "如何不出深閨裏，能以丹青寫外邊。"]'),
('yuding-20','失題','無名氏','唐','御定全唐诗','yuding','','[]','春朝散微雨，庭樹開芸綠。上有懷春鳥，間關斷複續。',60,'御定全唐詩/json/786.json','["春朝散微雨，庭樹開芸綠。上有懷春鳥，間關斷複續。", "謂言□野中，定是珠城曲。我自牽時幸，以慚羈旅束。", "爾不鳴幽林，來此將何欲。"]'),
('yuding-21','姜宣彈小胡笳引歌','無名氏','唐','御定全唐诗','yuding','','[]','雷氏金徽琴，王君寶重輕千金。三峽流中將得來，',94,'御定全唐詩/json/786.json','["雷氏金徽琴，王君寶重輕千金。三峽流中將得來，", "哀笳慢指董家本，姜宣得之妙思忖。泛徽胡雁咽蕭蕭，", "潺湲疑是舞鸊鵜，砉騞如聞發鳴鏑。流宮變征漸幽咽，", "哀弦已罷春恨長，恨長何如懷我鄉。我鄉安在長城窟，"]'),
('yuding-22','羅浮山','無名氏','唐','御定全唐诗','yuding','','[]','四百餘峰海上排，根連蓬島蔭天臺。',32,'御定全唐詩/json/786.json','["四百餘峰海上排，根連蓬島蔭天臺。", "百靈若為移中土，蒿華都為一小堆。"]'),
('yuding-23','湯周山','無名氏','唐','御定全唐诗','yuding','','[]','湯週二大仙，廬此得升天。風俗因興廟，春秋不記年。',48,'御定全唐詩/json/786.json','["湯週二大仙，廬此得升天。風俗因興廟，春秋不記年。", "錦雲張紫蓋，琴溜瀉鳴泉。丹灶猶存鼎，仙花發故園。"]'),
('yuding-24','永州舜廟詩','無名氏','唐','御定全唐诗','yuding','','[]','遊湘有餘怨，豈是聖人心。行路猿啼古，祠宮夢草深。',60,'御定全唐詩/json/786.json','["遊湘有餘怨，豈是聖人心。行路猿啼古，祠宮夢草深。", "素風傳舊俗，異跡閉荒林。巡狩去不返，煙雲愁至今。", "九嶷天一半，山盡海沉沉。"]'),
('yuding-25','絕句','無名氏','唐','御定全唐诗','yuding','','[]','綠楊陰轉畫橋斜，舟有笙歌岸有花。',32,'御定全唐詩/json/786.json','["綠楊陰轉畫橋斜，舟有笙歌岸有花。", "盡日會稽山色裏，蓬萊清淺水仙家。"]'),
('yuding-26','三學山盤陀石上刻詩','無名氏','唐','御定全唐诗','yuding','','[]','拔地山巒秀，排空殿閣斜。雲供數州雨，樹獻九天花。',48,'御定全唐詩/json/786.json','["拔地山巒秀，排空殿閣斜。雲供數州雨，樹獻九天花。", "夜月摩峰頂，秋鐘徹海涯。長松拂星漢，一一是仙槎。"]'),
('yuding-27','合水縣玉泉石崖刻','無名氏','唐','御定全唐诗','yuding','','[]','山脈逗飛泉，泓澄傍岩石。亂垂寒玉筱，碎灑珍珠滴。',48,'御定全唐詩/json/786.json','["山脈逗飛泉，泓澄傍岩石。亂垂寒玉筱，碎灑珍珠滴。", "澄波涵萬象，明鏡瀉天色。有時乘月來，賞詠還自適。"]'),
('yuding-28','紀遊東觀山','無名氏','唐','御定全唐诗','yuding','','[]','瑰奇恣搜討，貝闕青瑤房。才隘疑永巷，俄敞如華堂。',144,'御定全唐詩/json/786.json','["瑰奇恣搜討，貝闕青瑤房。才隘疑永巷，俄敞如華堂。", "玉梁窈浮溪，瓊戶正當窗。仙佛肖仿佛，鐘鼓鍧擊撞。", "贔贔左顧龜，狺狺欲吠尨。丹灶儼亡恙，芝田靄生香。", "搏噬千怪聚，絢爛五色光。更無一塵涴，但覺六月涼。", "玲瓏穿屢折，詰曲通三湘。神鬼若剜刻，乾坤真混茫。", "入如深夜暗，出喜皦日光。隔世驚瞬息，異境難揣量。"]'),
('yuding-29','題焚經台','無名氏','唐','御定全唐诗','yuding','','[]','門徑蕭蕭長綠苔，一回登此一徘徊。青牛謾說函關去，',40,'御定全唐詩/json/786.json','["門徑蕭蕭長綠苔，一回登此一徘徊。青牛謾說函關去，", "春風也解嫌狼藉，吹盡當年道教灰。"]'),
('yuding-0','日暮山河清','無名氏','唐','御定全唐诗','yuding','','[]','天高爽氣晶，馳景忽西傾。山列千重靜，河流一帶明。',72,'御定全唐詩/json/787.json','["天高爽氣晶，馳景忽西傾。山列千重靜，河流一帶明。", "想同金鏡澈，寧讓玉壺清。纖翳無由出，浮埃不復生。", "榮紆分漢苑，表裏見秦城。逸興終難系，抽毫仰此情。"]'),
('yuding-1','秋日懸清光','無名氏','唐','御定全唐诗','yuding','','[]','寥廓涼天靜，晶明白日秋。圓光含萬象，碎影入閑流。',72,'御定全唐詩/json/787.json','["寥廓涼天靜，晶明白日秋。圓光含萬象，碎影入閑流。", "迥與青冥合，遙同江甸浮。晝陰殊眾木，斜影下危樓。", "宋玉登高怨，張衡望遠愁。餘輝如可托，雲路豈悠悠。"]'),
('yuding-2','落日山照曜','無名氏','唐','御定全唐诗','yuding','','[]','裴回空山下，晼晚殘陽落。圓影過峰巒，半規入林薄。',72,'御定全唐詩/json/787.json','["裴回空山下，晼晚殘陽落。圓影過峰巒，半規入林薄。", "餘光澈群岫，亂彩分重壑。石鏡共澄明，岩光同照灼。", "棲禽去杳杳，夕煙生漠漠。此境誰複知，獨懷謝康樂。"]'),
('yuding-3','月映清淮流','無名氏','唐','御定全唐诗','yuding','','[]','淮月秋偏靜，含虛夜轉明。桂花窺鏡發，蟾影映波生。',72,'御定全唐詩/json/787.json','["淮月秋偏靜，含虛夜轉明。桂花窺鏡發，蟾影映波生。", "澹灩輪初上，裴回魄正盈。遙塘分草樹，近浦寫山城。", "桐柏流光逐，蠙珠濯景清。孤舟方利涉，更喜照前程。"]'),
('yuding-4','壽星見','無名氏','唐','御定全唐诗','yuding','','[]','玄象今何應，時和政亦平。祥為一人壽，色映九霄明。',72,'御定全唐詩/json/787.json','["玄象今何應，時和政亦平。祥為一人壽，色映九霄明。", "皎潔垂銀漢，光芒近鬥城。合規同月滿，表瑞得天清。", "甘露盈條降，祥煙向日生。無如此嘉祉，率土荷秋成。"]'),
('yuding-5','華山慶雲見','無名氏','唐','御定全唐诗','yuding','','[]','聖主祠名岳，高風發慶雲。金柯初繚繞，玉葉漸氛氳。',72,'御定全唐詩/json/787.json','["聖主祠名岳，高風發慶雲。金柯初繚繞，玉葉漸氛氳。", "氣色含珠日，光明吐翠雰。依稀來鶴態，仿佛列仙群。", "萬樹流光影，千潭寫錦文。蒼生忻有望，祥瑞在吾君。"]'),
('yuding-6','清風戒寒','無名氏','唐','御定全唐诗','yuding','','[]','蕭颯清風至，悠然發思端。入林翻別葉，繞樹敗紅蘭。',72,'御定全唐詩/json/787.json','["蕭颯清風至，悠然發思端。入林翻別葉，繞樹敗紅蘭。", "曉拂輕霜度，宵分遠籟攢。稍依簾隙靜，遍覺座隅寒。", "乍逐驚蓬振，偏催急漏殘。遙知洞庭水，此夕起波瀾。"]'),
('yuding-7','空水共澄鮮','無名氏','唐','御定全唐诗','yuding','','[]','悠然四望通，渺渺水無窮。海鶴飛天際，煙林出鏡中。',72,'御定全唐詩/json/787.json','["悠然四望通，渺渺水無窮。海鶴飛天際，煙林出鏡中。", "雲消澄遍碧，霞起澹微紅。落日浮光滿，遙山翠色同。", "樵聲喧竹嶼，棹唱入蓮叢。遠客舟中興，煩襟暫一空。"]'),
('yuding-8','寒流聚細文','無名氏','唐','御定全唐诗','yuding','','[]','曉野方閑眺，橫溪賞亂流。寒文趨浦急，圓折逐煙浮。',72,'御定全唐詩/json/787.json','["曉野方閑眺，橫溪賞亂流。寒文趨浦急，圓折逐煙浮。", "不謂飄疏雨，非關浴遠鷗。觀魚鱗共細，間石影疑稠。", "獵獵風泠夕，潺潺瀨響秋。仙槎如共泛，天漢適淹留。"]'),
('yuding-9','長安早春','無名氏','唐','御定全唐诗','yuding','','[]','杳靄三春色，先從帝裏芳。折楊猶恨短，測景已忻長。',72,'御定全唐詩/json/787.json','["杳靄三春色，先從帝裏芳。折楊猶恨短，測景已忻長。", "鶯和紅樓樂，花連紫禁香。躍魚驚太液，佳氣接溫湯。", "風送飛珂響，塵蒙翠輦光。熙熙晴煦遠，徒欲奉堯觴。"]'),
('yuding-10','嘉禾合穎','無名氏','唐','御定全唐诗','yuding','','[]','天祚皇王德，神呈瑞穀嘉。感時苗特秀，證道葉方華。',72,'御定全唐詩/json/787.json','["天祚皇王德，神呈瑞穀嘉。感時苗特秀，證道葉方華。", "氣轉騰佳色，雲披映早霞。熏風浮合穎，湛露淨祥花。", "六穗垂兼倒，孤莖嫋複斜。影同唐叔獻，稱慶比周家。"]'),
('yuding-11','膏澤多豐年','無名氏','唐','御定全唐诗','yuding','','[]','帝德方多澤，莓莓井徑同。八方甘雨布，四遠報年豐。',72,'御定全唐詩/json/787.json','["帝德方多澤，莓莓井徑同。八方甘雨布，四遠報年豐。", "廒慶千廂在，山流萬壑通。候時勤稼穡，擊壤樂農功。", "畎畝人無惰，田廬歲不空。何須憂伏臘，千載賀堯風。"]'),
('yuding-12','玉壺冰','無名氏','唐','御定全唐诗','yuding','','[]','玄律陰風勁，堅冰在玉壺。暗中花更出，曉後色全無。',72,'御定全唐詩/json/787.json','["玄律陰風勁，堅冰在玉壺。暗中花更出，曉後色全無。", "涸冱誰能伴，淒清詎可渝。任圓空似璧，照物不成珠。", "素質情方契，孤明道豈殊。幽人若相比，還得詠生芻。"]'),
('yuding-13','望禁苑祥光','無名氏','唐','御定全唐诗','yuding','','[]','佳氣生天苑，蔥蘢幾效祥。樹遙三殿際，日映九城傍。',72,'御定全唐詩/json/787.json','["佳氣生天苑，蔥蘢幾效祥。樹遙三殿際，日映九城傍。", "山霧寧同色，卿雲未可彰。眺汾疑鼎氣，臨渭想榮光。", "當並舂陵發，應開聖曆長。微臣時一望，短羽欲飛翔。"]'),
('yuding-14','晨光動翠華','無名氏','唐','御定全唐诗','yuding','','[]','早朝開紫殿，佳氣逐清晨。北闕華旌在，東方曙景新。',72,'御定全唐詩/json/787.json','["早朝開紫殿，佳氣逐清晨。北闕華旌在，東方曙景新。", "影連香霧合，光媚慶雲頻。鳥羽飄初定，龍文照轉真。", "直疑冠佩入，長愛冕旒親。搖動祥雲裏，朝朝映侍臣。"]'),
('yuding-15','觀南郊回仗','無名氏','唐','御定全唐诗','yuding','','[]','傳警千門寂，南效彩仗回。但驚龍再見，誰識日雙開。',72,'御定全唐詩/json/787.json','["傳警千門寂，南效彩仗回。但驚龍再見，誰識日雙開。", "德澤施雲雨，恩光變燼灰。閱兵貔武振，聽樂鳳凰來。", "候刻移宸輦，尊時集觀台。多慚遠臣賤，不得禮容陪。"]'),
('yuding-16','謁見日將至雙闕','無名氏','唐','御定全唐诗','yuding','','[]','曉色臨雙闕，微臣禮位陪。遠驚龍鳳睹，誰識冕旒開。',72,'御定全唐詩/json/787.json','["曉色臨雙闕，微臣禮位陪。遠驚龍鳳睹，誰識冕旒開。", "藹藹千年盛，顒顒萬國來。天文標日月，時令布雲雷。", "迥出黃金殿，全分白玉台。雕蟲意何取，瞻戀不知回。"]'),
('yuding-17','尚書郎上直聞春漏','無名氏','唐','御定全唐诗','yuding','','[]','地即尚書省，人惟鴛鷺行。審時傳玉漏，直夜遞星郎。',72,'御定全唐詩/json/787.json','["地即尚書省，人惟鴛鷺行。審時傳玉漏，直夜遞星郎。", "歷歷聞仙署，泠泠出建章。自空來斷續，隨月散淒鏘。", "物靜知聲遠，寒輕覺夜長。聽餘殘月落，曙色滿東方。"]'),
('yuding-18','華清宮望幸','無名氏','唐','御定全唐诗','yuding','','[]','驪岫接新豐，岧嶢駕碧空。鑿山開秘殿，隱霧蔽仙宮。',72,'御定全唐詩/json/787.json','["驪岫接新豐，岧嶢駕碧空。鑿山開秘殿，隱霧蔽仙宮。", "絳闕猶棲鳳，雕梁尚帶虹。溫泉曾浴日，華館舊迎風。", "肅穆瞻雲輦，深沈閉綺櫳。東郊望幸處，瑞氣靄濛濛。"]'),
('yuding-19','禦題國子監','無名氏','唐','御定全唐诗','yuding','','[]','宸翰符玄造，榮題國子門。筆鋒回日月，字勢動乾坤。',72,'御定全唐詩/json/787.json','["宸翰符玄造，榮題國子門。筆鋒回日月，字勢動乾坤。", "簷下雲光繞，梁間鵲影翻。張英聖莫擬，索靖妙難言。", "為著盤龍跡，能彰舞鳳蹲。更隨垂露像，常以沐皇恩。"]'),
('yuding-20','郊壇聽雅樂','無名氏','唐','御定全唐诗','yuding','','[]','泰壇恭祀事，彩仗下寒坰。展禮陳嘉樂，齋心動眾靈。',72,'御定全唐詩/json/787.json','["泰壇恭祀事，彩仗下寒坰。展禮陳嘉樂，齋心動眾靈。", "韻長飄更遠，曲度靜宜聽。泛響何清越，隨風散杳冥。", "徹懸和氣聚，旋退曉山青。本自鈞天降，還疑列洞庭。"]'),
('yuding-21','冊上公太常奏雅樂','無名氏','唐','御定全唐诗','yuding','','[]','司樂陳金石，逶迤引上公。奏音人語絕，清韻佩聲通。',72,'御定全唐詩/json/787.json','["司樂陳金石，逶迤引上公。奏音人語絕，清韻佩聲通。", "應律煙雲改，來儀鳥獸同。得賢因舉頌，修禮便觀風。", "聖壽三稱內，天歡九奏中。寂寥高曲盡，猶自滿宸聰。"]'),
('yuding-22','聽霜鐘','無名氏','唐','御定全唐诗','yuding','','[]','渺渺飛霜夜，寥寥遠岫鐘。出雲疑斷續，入戶乍舂容。',72,'御定全唐詩/json/787.json','["渺渺飛霜夜，寥寥遠岫鐘。出雲疑斷續，入戶乍舂容。", "度枕頻驚夢，隨風幾韻松。悠揚來不已，杳靄去何從。", "仿佛煙嵐隔，依俙岩嶠重。此時聊一聽，餘響繞千峰。"]'),
('yuding-23','聽霜鐘','無名氏','唐','御定全唐诗','yuding','','[]','寥亮來豐嶺，分明辨古鐘。應霜如自擊，中節每相從。',72,'御定全唐詩/json/787.json','["寥亮來豐嶺，分明辨古鐘。應霜如自擊，中節每相從。", "靜聽非閑扣，潛應蘊聖蹤。風間時斷續，雲外更舂容。", "虛警和清籟，雄鳴隔亂峰。因之論知己，感激更難逢。"]'),
('yuding-24','笙磬同音','無名氏','唐','御定全唐诗','yuding','','[]','笙磬聞何處，淒鏘宛在東。激揚音自徹，高下曲宜同。',72,'御定全唐詩/json/787.json','["笙磬聞何處，淒鏘宛在東。激揚音自徹，高下曲宜同。", "歷歷俱盈耳，泠泠遞散空。獸因繁奏舞，人感至和通。", "詎間洪纖韻，能齊搏拊功。四懸今盡美，一聽辨移風。"]'),
('yuding-25','玉卮無當','無名氏','唐','御定全唐诗','yuding','','[]','共惜連城寶，翻為無當卮。詎慚君子貴，深訝拙工隳。',72,'御定全唐詩/json/787.json','["共惜連城寶，翻為無當卮。詎慚君子貴，深訝拙工隳。", "泛蟻功全少，如虹色不移。可憐珍礫石，何計辨糟醨。", "江海誠難滿，盤筵莫妄施。縱乖斟酌意，猶得奉光儀。"]'),
('yuding-26','府試古鏡','無名氏','唐','御定全唐诗','yuding','','[]','舊是秦時鏡，今來古匣中。龍盤初掛月，鳳舞欲生風。',72,'御定全唐詩/json/787.json','["舊是秦時鏡，今來古匣中。龍盤初掛月，鳳舞欲生風。", "石黛曾留殿，朱光適在宮。應祥知道泰，監物覺神通。", "肝膽誠難隱，妍媸信易窮。幸居君子室，長願免塵蒙。"]'),
('yuding-27','焚裘','無名氏','唐','御定全唐诗','yuding','','[]','今主臨前殿，懲奢爇異裘。忽看陽焰發，如睹吉光流。',72,'御定全唐詩/json/787.json','["今主臨前殿，懲奢爇異裘。忽看陽焰發，如睹吉光流。", "麗彩辭宸扆，餘香在禦樓。火隨餘燼滅，氣逐遠煙浮。", "素樸回風變，雕華逐志休。永垂恭儉德，千古揖皇猷。"]'),
('yuding-28','送薛大夫和蕃','無名氏','唐','御定全唐诗','yuding','','[]','戎王歸漢命，魏絳諭皇恩。旌旆辭雙闕，風沙上五原。',72,'御定全唐詩/json/787.json','["戎王歸漢命，魏絳諭皇恩。旌旆辭雙闕，風沙上五原。", "往途遵塞道，出祖耀都門。策令天文盛，宣威使者尊。", "澄波看四海，入貢佇諸蕃。秋杪迎回騎，無勞枉夢魂。"]'),
('yuding-29','觀劍南獻捷','無名氏','唐','御定全唐诗','yuding','','[]','遐圻新破虜，名將舊登壇。戎馘西南至，氈裘長幼觀。',72,'御定全唐詩/json/787.json','["遐圻新破虜，名將舊登壇。戎馘西南至，氈裘長幼觀。", "邊疆氛已息，矛戟血猶殘。紫陌歡聲動，丹墀喜氣盤。", "唐虞方德易，衛霍比功難。共睹俘囚入，賡歌萬國安。"]'),
('yuding-30','雲母屏風隔坐','無名氏','唐','御定全唐诗','yuding','','[]','彩障成雲母，丹墀隔上公。才彰二紀盛，榮播一朝同。',72,'御定全唐詩/json/787.json','["彩障成雲母，丹墀隔上公。才彰二紀盛，榮播一朝同。", "近玉初齊白，臨花乍散紅。凝姿分縹緲，轉佩辨玲瓏。", "意愜恩偏厚，名新寵更崇。誰知曆千古，猶自仰清風。"]'),
('yuding-31','白受采','無名氏','唐','御定全唐诗','yuding','','[]','皛皛金方色，遷移妙不窮。輕衣塵跡化，淨壁繢文通。',72,'御定全唐詩/json/787.json','["皛皛金方色，遷移妙不窮。輕衣塵跡化，淨壁繢文通。", "沙變藍溪漬，冰渝墨沼空。似甘言受和，由禮學資忠。", "皎潔形無定，玄黃用莫同。素心如可教，願染古人風。"]'),
('yuding-32','人不易知','無名氏','唐','御定全唐诗','yuding','','[]','權衡諒匪易，愚智信難移。九德皆殊進，三端豈易施。',96,'御定全唐詩/json/787.json','["權衡諒匪易，愚智信難移。九德皆殊進，三端豈易施。", "同稱昆岫寶，共握桂林枝。鄭鼠今奚別，齊竽或濫吹。", "瑤台有光鑒，屢照不應疲。片善當無掩，先鳴貴在斯。", "龍門峻且極，驥足庶來馳。太息李元禮，期君幸一知。"]'),
('yuding-33','晦日同志昆明池泛舟','無名氏','唐','御定全唐诗','yuding','','[]','靈沼疑河漢，蕭條見鬥牛。煙生知岸近，水淨覺天秋。',72,'御定全唐詩/json/787.json','["靈沼疑河漢，蕭條見鬥牛。煙生知岸近，水淨覺天秋。", "落月低前樹，清輝滿去舟。興因孤嶼起，心為白蘋留。", "曉吹兼漁笛，閑雲伴客愁。龍津如可上，長嘯且乘流。"]'),
('yuding-34','禮闈階前春草生','無名氏','唐','御定全唐诗','yuding','','[]','河畔雖同色，南宮淑景先。微開曳履處，常對講經前。',72,'御定全唐詩/json/787.json','["河畔雖同色，南宮淑景先。微開曳履處，常對講經前。", "得地風塵隔，依林雨露偏。已逢霜候改，初寄日華妍。", "影與叢蘭雜，榮將眾卉連。哲人如不薙，生意在芳年。"]'),
('yuding-35','秋風生桂枝','無名氏','唐','御定全唐诗','yuding','','[]','寒桂秋風動，蕭蕭自一枝。方將擊林變，不假舞松移。',72,'御定全唐詩/json/787.json','["寒桂秋風動，蕭蕭自一枝。方將擊林變，不假舞松移。", "散翠幽花落，搖青密葉離。哀猿驚助褭，花露滴爭垂。", "遺韻連波聚，流音萬木隨。常聞小山裏，逋客最先知。"]'),
('yuding-36','幽人折芳桂','無名氏','唐','御定全唐诗','yuding','','[]','厚地生芳桂，遙林聳幹長。葉開風裏色，花吐月中光。',72,'御定全唐詩/json/787.json','["厚地生芳桂，遙林聳幹長。葉開風裏色，花吐月中光。", "曙鳥啼餘翠，幽人愛早芳。動時垂露滴，攀處拂衣香。", "古調聲猶苦，孤高力自強。一枝終是折，榮耀在東堂。"]'),
('yuding-37','霜菊','無名氏','唐','御定全唐诗','yuding','','[]','秋盡北風去，律移寒氣肅。淅瀝降繁霜，離披委殘菊。',72,'御定全唐詩/json/787.json','["秋盡北風去，律移寒氣肅。淅瀝降繁霜，離披委殘菊。", "華滋尚照灼，幽氣含紛鬱。的的冒空園，萋萋被幽谷。", "騷人有遺詠，陶令曾盈掬。儻使懷袖中，猶堪襲餘馥。"]'),
('yuding-38','金穀園花發懷古','無名氏','唐','御定全唐诗','yuding','','[]','春風生梓澤，遲景映花林。欲問當時事，因傷此日心。',72,'御定全唐詩/json/787.json','["春風生梓澤，遲景映花林。欲問當時事，因傷此日心。", "繁華人已歿，桃李意何深。澗咽歌聲在，雲歸蓋影沈。", "地形同萬古，笑價失千金。遺跡應無限，芳菲不可尋。"]'),
('yuding-39','驪龍','無名氏','唐','御定全唐诗','yuding','','[]','有美為鱗族，潛蟠得所從。標奇初韞寶，表智即稱龍。',72,'御定全唐詩/json/787.json','["有美為鱗族，潛蟠得所從。標奇初韞寶，表智即稱龍。", "大壑長千里，深泉固九重。奮髯雲乍起，矯首浪還沖。", "荀氏傳高譽，莊生冀絕蹤。仍知流淚在，何幸此相逢。"]'),
('yuding-40','鶴鳴九皋','無名氏','唐','御定全唐诗','yuding','','[]','胎化呈仙質，長鳴在九皋。排空散清唳，映日委霜毛。',72,'御定全唐詩/json/787.json','["胎化呈仙質，長鳴在九皋。排空散清唳，映日委霜毛。", "萬里思寥廓，千山望郁陶。香凝光不見，風積韻彌高。", "鳳侶攀何及，雞群思忽勞。升天如有應，飛舞出蓬蒿。"]'),
('yuding-41','霜隼下晴皋','無名氏','唐','御定全唐诗','yuding','','[]','九皋霜氣勁，翔隼下初晴。風動閑雲卷，星馳白草平。',72,'御定全唐詩/json/787.json','["九皋霜氣勁，翔隼下初晴。風動閑雲卷，星馳白草平。", "棱棱方厲疾，肅肅自縱橫。掠地秋毫迥，投身逸翮輕。", "高墉全失影，逐雀作飛聲。薄暮寒郊外，悠悠萬里情。"]'),
('yuding-42','河鯉登龍門','無名氏','唐','御定全唐诗','yuding','','[]','年久還求變，今來有所從。得名當是鯉，無點可成龍。',72,'御定全唐詩/json/787.json','["年久還求變，今來有所從。得名當是鯉，無點可成龍。", "備曆艱難遍，因期造化容。泥沙甯不阻，釣餌莫相逢。", "擊浪因成勢，纖鱗莫繼蹤。若令搖尾去，雨露此時濃。"]'),
('yuding-0','改九子山為九華山聯句','李白','唐','御定全唐诗','yuding','','[]','妙有分二氣，靈山開九華。——李白',65,'御定全唐詩/json/788.json','["妙有分二氣，靈山開九華。——李白", "層標遏遲日，半壁明朝霞。——高霽", "積雪曜陰壑，飛流噴陽崖。——韋權輿", "青瑩玉樹色，縹緲羽人家。——李白"]'),
('yuding-1','夏夜李尚書筵送宇文石首赴縣聯句','杜甫','唐','御定全唐诗','yuding','','[]','愛客尚書貴，之官宅相賢。——杜甫',131,'御定全唐詩/json/788.json','["愛客尚書貴，之官宅相賢。——杜甫", "酒香傾坐側，帆影駐江邊。——李之芳", "翟表郎官瑞，鳧看令宰仙。——崔彧", "雨稀雲葉斷，夜久燭花偏。——杜甫", "數語欹紗帽，高文擲彩箋。——李之芳", "興饒行處樂，離惜醉中眠。——崔彧", "單父長多暇，河陽實少年。——杜甫", "客居逢自出，為別幾淒然。——李之芳"]'),
('yuding-2','登峴山觀李左相石尊聯句','顏真卿','唐','御定全唐诗','yuding','','[]','李公登飲處，因石為窪尊。——顏真卿',393,'御定全唐詩/json/788.json','["李公登飲處，因石為窪尊。——顏真卿", "人事歲年改，峴山今古存。——劉全白", "榛蕪掩前跡，苔蘚餘舊痕。——裴循", "叔子尚遺德，山公此回軒。——張薦", "維舟陪高興，感昔情彌敦。——吳筠", "藹藹賢哲事，依依離別言。——強蒙", "嶇嶔橫道周，迢遞連山根。——範縉", "餘烈曖林野，眾芳揖蘭蓀。——王純", "德暉映岩足，勝賞延高原。——魏理", "遠水明匹練，因晴見吳門。——王修甫", "陪游追盛美，揆德欣討論。——顏峴", "器有成形用，功資造化元。——左輔元", "流霞方泔淡，別鶴遽翩翻。——劉茂", "舊規傾逸賞，新興麗初暾。——顏渾", "醉後接z5倒，歸時騶騎喧。——楊德元", "遲回向遺跡，離別益傷魂。——韋介", "覽事古興屬，送人歸思繁。——皎然", "懷賢久徂謝，贈遠空攀援。——崔弘", "八座欽懿躅，高名播幹抻。——史仲宣", "松深引閒步，葛弱供險捫。——陸羽", "花氣酒中馥，雲華衣上屯。——權器", "森沈列湖樹，牢落望效園。——陸士修", "白日半岩岫，清風滿丘樊。——裴幼清", "旌麾間翠幄，簫鼓來朱轓。——柳淡"]'),
('yuding-3','水堂送諸文士戲贈潘丞聯句','顏真卿','唐','御定全唐诗','yuding','','[]','居人未可散，上客須留著。莫唱阿嚲回，應雲夜半樂。——顏真卿',197,'御定全唐詩/json/788.json','["居人未可散，上客須留著。莫唱阿嚲回，應雲夜半樂。——顏真卿", "詩教刻燭賦，酒任連盤酌。從他白眼看，終戀青山郭。——潘述", "林棲非姓許，寺住那名約。會異永和年，才同建安作。——陸羽", "何煩問更漏，但遣催弦索。共說長句能，皆言早歸惡。——權器", "那知殊出處，還得同笑謔。雅韻雖暫歡，禪心肯拋卻。——皎然", "一宿同高會，幾人歸下若。簾開北陸風，燭焯南枝鵲。——李崿", "文場苦叨竊，釣渚甘漂泊。弱質幸見容，菲才誠重諾。——潘述"]'),
('yuding-4','與耿湋水亭詠風聯句','顏真卿','唐','御定全唐诗','yuding','','[]','清風何處起，拂檻複縈洲。——裴幼清',195,'御定全唐詩/json/788.json','["清風何處起，拂檻複縈洲。——裴幼清", "回入飄華幕，輕來疊晚流。——楊憑", "桃竹今已展，羽翣且從收。——楊凝", "經竹吹彌切，過松韻更幽。——左輔元", "直散青蘋末，偏隨白浪頭。——陸士修", "山山催雨過，浦浦發行舟。——權器", "動樹蟬爭噪，開簾客罷愁。——陸羽", "度弦方解慍，臨水已迎秋。——顏真卿", "涼為開襟至，清因作頌留。——皎然", "周回隨遠夢，騷屑滿離憂。——耿湋", "豈獨銷繁暑，偏能入迥樓。——喬", "王風今若此，誰不荷明休。——陸涓"]'),
('yuding-5','又溪館聽蟬聯句','顏真卿','唐','御定全唐诗','yuding','','[]','高樹多涼吹，疏蟬足斷聲。——楊憑',161,'御定全唐詩/json/788.json','["高樹多涼吹，疏蟬足斷聲。——楊憑", "已催居客感，更使別人驚。——楊凝", "晚夏猶知急，新秋別有情。——權器", "危湍和不似，細管學難成。——陸羽", "當斅附金重，無貪曜火明。——顏真卿", "青松四面落，白髮一重生。——耿湋", "向夕音彌厲，迎風翼更輕。——喬", "單嘶出迥樹，餘響思空城。——裴幼清", "嘒唳松間坐，蕭寥竹裏行。——伯成", "如何長飲露，高潔未能名。——皎然"]'),
('yuding-6','送耿湋拾遺聯句','顏真卿','唐','御定全唐诗','yuding','','[]','堯舜逢明主，嚴徐得侍臣。分行接三事，高興柏梁新。——顏真卿',114,'御定全唐詩/json/788.json','["堯舜逢明主，嚴徐得侍臣。分行接三事，高興柏梁新。——顏真卿", "楚國千山道，秦城萬里人。鏡中看齒發，河上有煙塵。——耿湋", "望闕飛青翰，朝天憶紫宸。喜來歡宴洽，愁去詠歌頻。——顏真卿", "顧盼情非一，睽攜處亦頻。吳興賢太守，臨水最殷勤。——耿湋"]'),
('yuding-7','五言月夜啜茶聯句','顏真卿','唐','御定全唐诗','yuding','','[]','泛花邀坐客，代飲引情言。——陸士修',115,'御定全唐詩/json/788.json','["泛花邀坐客，代飲引情言。——陸士修", "醒酒宜華席，留僧想獨園。——張薦", "不須攀月桂，何假樹庭萱。——李崿", "禦史秋風勁，尚書北斗尊。——崔萬", "流華淨肌骨，疏瀹滌心原。——顏真卿", "不似春醪醉，何辭綠菽繁。——皎然", "素瓷傳靜夜，芳氣清閒軒。——陸士修"]'),
('yuding-8','五言夜宴詠燈聯句','顏真卿','唐','御定全唐诗','yuding','','[]','桂酒牽詩興，蘭釭照客情。——陸士修',82,'御定全唐詩/json/788.json','["桂酒牽詩興，蘭釭照客情。——陸士修", "詎慚珠乘朗，不讓月輪明。——張薦", "破暗光初白，浮雲色轉清。——顏真卿", "帶花疑在樹，比燎欲分庭。——皎然", "顧己慚微照，開簾識近汀。——袁高"]'),
('yuding-9','三言喜皇甫曾侍禦見過南樓玩月','顏真卿','唐','御定全唐诗','yuding','','[]','喜嘉客，辟前軒。天月淨，水雲昏。——顏真卿',115,'御定全唐詩/json/788.json','["喜嘉客，辟前軒。天月淨，水雲昏。——顏真卿", "雁聲苦，蟾影寒。聞裛浥，滴檀欒。——陸羽", "歡宴處，江湖間。——皇甫曾", "卷翠幕，吟嘉句。恨清光，留不住。——李崿", "高駕動，清角催。惜歸去，重裴回。——皎然", "露欲晞，客將醉。猶宛轉，照深意。——陸士修"]'),
('yuding-10','七言重聯句','顏真卿','唐','御定全唐诗','yuding','','[]','頃持憲簡推高步，獨佔詩流橫素波。——顏真卿',204,'御定全唐詩/json/788.json','["頃持憲簡推高步，獨佔詩流橫素波。——顏真卿", "不是中情深惠好，誰能千里遠經過。——顏真卿", "詩書宛似陪康樂，少長還同宴永和。——皇甫曾", "夜酌此時看碾玉，晨趨幾日重鳴珂。——皇甫曾", "萬井更深空寂寞，千方霧起隱嵯峨。——李崿", "熒熒遠火分漁浦，歷歷寒枝露鳥窠。——李崿", "漢朝舊學君公隱，魯國今從弟子科。——陸羽", "只自傾心慚煦濡，何曾將口恨蹉跎。——陸羽", "獨賞謝吟山照耀，共知殷歎樹婆娑。——皎然", "華轂苦嫌雲路隔，衲衣長向雪峰何。——皎然"]'),
('yuding-11','五言送李侍禦聯句','顏真卿','唐','御定全唐诗','yuding','','[]','吾友駐行輪，遲遲惜上春。——顏真卿',65,'御定全唐詩/json/788.json','["吾友駐行輪，遲遲惜上春。——顏真卿", "東西出餞路，惆悵獨歸人。——皎然", "歡會期他日。驅馳恨此身。——張薦", "須知貢公望，從此願相因。——李崿"]'),
('yuding-12','五言玩初月重遊聯句','顏真卿','唐','御定全唐诗','yuding','','[]','春溪與岸平，初月出溪明。——張薦',65,'御定全唐詩/json/788.json','["春溪與岸平，初月出溪明。——張薦", "璧彩寒仍潔，金波夜轉清。——李崿", "孤光遠近滿，練色往來輕。——顏真卿", "望望隨蘭棹，依依出柳城。——皎然"]'),
('yuding-13','五言重送橫飛聯句','顏真卿','唐','御定全唐诗','yuding','','[]','春田草未齊，春水滿長溪。——李崿',49,'御定全唐詩/json/788.json','["春田草未齊，春水滿長溪。——李崿", "出餞風初暖，攀光日漸西。——顏真卿", "歸期江上遠，別思月中迷。——皎然"]'),
('yuding-14','五言夜集聯句','顏真卿','唐','御定全唐诗','yuding','','[]','寒花護月色，墜葉占風音。——皎然',33,'御定全唐詩/json/788.json','["寒花護月色，墜葉占風音。——皎然", "茲夕無塵慮，高雲共片心。——顏真卿"]'),
('yuding-15','三言擬五雜組聯句','顏真卿','唐','御定全唐诗','yuding','','[]','五雜組，盤上菹。往復還，頭懶梳。不得已，罾裏魚。——李崿',171,'御定全唐詩/json/788.json','["五雜組，盤上菹。往復還，頭懶梳。不得已，罾裏魚。——李崿", "五雜組，郊外蕪。往復還，櫪上駒。不得已，穀中愚。——殷佐明", "五雜組，繡與錦。往復還，興又寢。不得已，病伏枕。——顏真卿", "五雜組，酒與肉。往復還，東籬菊。不得已，醉便宿。——袁高", "五雜組，闤闠間。往復還，門上關。不得已，鬢毛斑。——陸士修", "五雜組，繡紋線。往復還，春來燕。不得已，入征戰。——蔣志"]'),
('yuding-16','三言重擬五雜組聯句','顏真卿','唐','御定全唐诗','yuding','','[]','五雜組，四豪客。往復還，阡與陌。不得已，長沙謫。——張薦',113,'御定全唐詩/json/788.json','["五雜組，四豪客。往復還，阡與陌。不得已，長沙謫。——張薦", "五雜組，五辛盤。往復還，馬上鞍。不得已，左降官。——李崿", "五雜組，甘鹹醋。往復還，烏與兔。不得已，韶光度。——顏真卿", "五雜組，五色絲。往復還，回文詩。不得已，失喜期。——皎然"]'),
('yuding-17','七言大言聯句','顏真卿','唐','御定全唐诗','yuding','','[]','高歌閬風步瀛洲，——皎然',49,'御定全唐詩/json/788.json','["高歌閬風步瀛洲，——皎然", "燂鵬爚鯤餐未休。——顏真卿", "四方上下無外頭，——李崿", "一啜頓涸滄溟流。——張薦"]'),
('yuding-18','七言小言聯句','顏真卿','唐','御定全唐诗','yuding','','[]','長路迢遙吞吐絲。——顏真卿',25,'御定全唐詩/json/788.json','["長路迢遙吞吐絲。——顏真卿", "蟭螟蚊睫察難知。——皎然"]'),
('yuding-19','七言樂語聯句','顏真卿','唐','御定全唐诗','yuding','','[]','苦河既濟真僧喜，——李崿',49,'御定全唐詩/json/788.json','["苦河既濟真僧喜，——李崿", "新知滿座笑相視。——顏真卿", "戍客歸來見妻子，——皎然", "學生放假偷向市。——張薦"]'),
('yuding-20','七言嚵語聯句','顏真卿','唐','御定全唐诗','yuding','','[]','拈z2舐指不知休，——李崿',50,'御定全唐詩/json/788.json','["拈z2舐指不知休，——李崿", "欲炙侍立涎交流。——顏真卿", "過屠大嚼肯知羞，——皎然", "食店門外強淹留。——張薦"]'),
('yuding-21','七言滑語聯句','顏真卿','唐','御定全唐诗','yuding','','[]','雨裏下山蹋榆皮，——顏真卿',62,'御定全唐詩/json/788.json','["雨裏下山蹋榆皮，——顏真卿", "莓苔石橋步難移。——皎然", "蕪荑醬醋吃煮葵，——劉全白", "縫靴蠟線油塗錐。——李崿", "急逢龍背須且騎。——李益"]'),
('yuding-22','七言醉語聯句','顏真卿','唐','御定全唐诗','yuding','','[]','逢糟遇曲便酩酊，——劉全白',51,'御定全唐詩/json/788.json','["逢糟遇曲便酩酊，——劉全白", "覆車墜馬皆不醒。——顏真卿", "倒著接z5發垂領，——皎然", "狂心亂語無人並。——陸羽"]'),
('yuding-0','建元寺晝公與崔秀才見過聯句，與鄭奉禮說同作','皇甫曾','唐','御定全唐诗','yuding','','[]','人閑宜歲晚，道者訪幽期。獨與寒山別，行當暮雪時。——皇甫曾',143,'御定全唐詩/json/789.json','["人閑宜歲晚，道者訪幽期。獨與寒山別，行當暮雪時。——皇甫曾", "柏台辭漢主，竹寺寄潛師。荷策知君待，開門笑我遲。——皎然", "暮階縣雨足，寒吹繞松枝，理辯塵心妄，經分梵字疑。——鄭說", "久承黃紙詔，曾賦碧雲詩。然諾驚相許，風流話所思。——崔子向", "筌忘心己默，磬發夜何其。願結求羊侶，名山從所之。——皇甫曾"]'),
('yuding-1','建元寺西院寄李員外縱聯句','皇甫曾','唐','御定全唐诗','yuding','','[]','寄隱霜台客，相思粉署人。——崔子向',165,'御定全唐詩/json/789.json','["寄隱霜台客，相思粉署人。——崔子向", "誠知阡陌近，無奈別離頻。——皇甫曾", "夜色迷雙樹，鐘聲警四鄰。——鄭說", "散才徒仰鮑，歸夢遠知秦。——臺上", "雨帶清笳發，花驚夕漏春。——皎然", "招搖隨步錫，仿佛聽行輪。——崔子向", "要路推高足，空林寄一身。——皇甫曾", "盛名知獨擅，良會憶相親。——鄭說", "稍滌心中垢，都遺陌上塵。——崔子向", "今宵此堂集，何事少遺民。——皎然"]'),
('yuding-2','中元日鮑端公宅遇吳天師聯句','嚴維','唐','御定全唐诗','yuding','','[]','道流為柱史，教戒下真仙。——嚴維',227,'御定全唐詩/json/789.json','["道流為柱史，教戒下真仙。——嚴維", "共契中元會，初修內景篇。——鮑防", "游方依地僻，蔔室喜牆連。——謝良輔", "寶笥開金籙，華池漱玉泉。——杜弈", "怪龍隨羽翼，青節降雲煙。——李清", "昔去遺丹灶，今來變海田。——劉蕃", "養形奔二景，煉骨度千年。——謝良弼", "騎竹投陂裏，攜壺掛牖邊。——鄭概", "洞中嘗入靜，河上舊談玄。——陳元初", "伊洛笙歌遠，蓬壺日月偏。——樊珣", "青騾薊訓引，白犬伯陽牽。——丘丹", "法受相君後，心存象帝先。——呂渭", "道成能縮地，功滿欲升天。——范淹", "何意迷孤性，含情戀數賢。——吳筠"]'),
('yuding-3','酒語聯句，各分一字','嚴維','唐','御定全唐诗','yuding','','[]','山簡酣歌倒接z5，——劉蕃',135,'御定全唐詩/json/789.json','["山簡酣歌倒接z5，——劉蕃", "看朱成碧無所知。——鮑防", "耳鳴目眩駟馬馳，——謝良輔", "口稱童羖腹鴟夷。——嚴維", "兀然落帽灌酒卮，——沈仲昌", "太常吏部相對時。——嚴維", "藉糟枕麹浮酒池，——丘丹", "甕間籬下臥不移。——呂渭", "叫呼不應無事悲，——鄭概", "千日一醒知是誰。——陳元初", "左傾右倒人避之。——迥"]'),
('yuding-4','一字至九字詩聯句','嚴維','唐','御定全唐诗','yuding','','[]','東，西，——鮑防',147,'御定全唐詩/json/789.json','["東，西，——鮑防", "步月，尋溪。——嚴維", "鳥已宿，猿又啼。——鄭概", "狂流礙石，迸筍穿溪。——成用", "望望人煙遠，行行蘿徑迷。——陳元初", "探題只應盡墨，持贈更欲封泥。——陳元初", "松下流時何歲月，雲中幽處屢攀躋。——張叔政", "乘興不知山路遠近，緣情莫問日過高低。——賈弇", "靜聽林下潺潺足湍瀨，厭問城中喧喧多鼓鼙。——周頌"]'),
('yuding-5','宣上人病中相尋聯句','李益','唐','御定全唐诗','yuding','','[]','策杖迎詩客，歸房理病身。閑收無效藥，遍寄有情人。——廣宣',56,'御定全唐詩/json/789.json','["策杖迎詩客，歸房理病身。閑收無效藥，遍寄有情人。——廣宣", "草木分千品，方書問六陳。還知一室內，我爾即天親。——李益"]'),
('yuding-6','八月十五夜宣上人獨游安國寺山庭院步人遲…乘興聯句','李益','唐','御定全唐诗','yuding','','[]','九重城接天花界，三五秋生一夜風。——廣宣',80,'御定全唐詩/json/789.json','["九重城接天花界，三五秋生一夜風。——廣宣", "行聽漏聲雲散後，遙聞天語月明中。——廣宣", "含涼閣迥通仙掖，承露盤高出上宮。——李益", "誰問獨愁門外客，清談不與此宵同。——李益"]'),
('yuding-7','重陽夜集蘭陵居與宣上人聯句','李益','唐','御定全唐诗','yuding','','[]','蟋蟀催寒服，茱萸滴露房。酒巡明刻燭，籬菊暗尋芳。——李益',56,'御定全唐詩/json/789.json','["蟋蟀催寒服，茱萸滴露房。酒巡明刻燭，籬菊暗尋芳。——李益", "新月和秋露，繁星混夜霜。登高今夕事，九九是天長。——廣宣"]'),
('yuding-8','與宣供奉攜癭尊歸杏溪園聯句','李益','唐','御定全唐诗','yuding','','[]','千畦抱甕園，一酌癭尊酒。唯有沃洲僧，時過杏溪臾。——李益',56,'御定全唐詩/json/789.json','["千畦抱甕園，一酌癭尊酒。唯有沃洲僧，時過杏溪臾。——李益", "追歡君適性，獨飲我空口。儒釋事雖殊，文章意多偶。——廣宣"]'),
('yuding-9','蘭陵僻居聯句','李益','唐','御定全唐诗','yuding','','[]','潘嶽閒居賦，陶潛獨酌謠。二賢成往事，三徑是今朝。——廣宣',84,'御定全唐詩/json/789.json','["潘嶽閒居賦，陶潛獨酌謠。二賢成往事，三徑是今朝。——廣宣", "生幸逢唐運，昌時奉帝堯。進思諧啟沃，退混即漁樵。——李益", "蠹簡封延閣，雕闌閟上霄。相從清曠地，秋露挹蘭苕。——杜羔"]'),
('yuding-10','天津橋南山中各題一句','李益','唐','御定全唐诗','yuding','','[]','野坐分苔席，——李益',42,'御定全唐詩/json/789.json','["野坐分苔席，——李益", "山行繞菊叢。——韋執中", "雲衣惹不破，——諸葛覺", "秋色望來空。——賈島"]'),
('yuding-11','紅樓下聯句','李益','唐','御定全唐诗','yuding','','[]','佛刹接重城，紅樓切太清。紫雲連照耀，丹檻郁崢嶸。——廣宣',84,'御定全唐詩/json/789.json','["佛刹接重城，紅樓切太清。紫雲連照耀，丹檻郁崢嶸。——廣宣", "榱棟煙虹入，軒窗日月平。參差五陵晚，分背八川明。——李益", "松韻風初過，蓮陂浪欲傾。敬瞻疑湧見，圍繞學無生。——杜羔"]'),
('yuding-12','賦應門照綠苔','李益','唐','御定全唐诗','yuding','','[]','宮闕何年月，應門何歲苔。清光一以照，白露共裴回。——李益',56,'御定全唐詩/json/789.json','["宮闕何年月，應門何歲苔。清光一以照，白露共裴回。——李益", "珠履久行絕，玉房重未開。妾心正如此，昭陽歌吹來。——法振"]'),
('yuding-13','寄司空曙李端聯句','耿湋','唐','御定全唐诗','yuding','','[]','長安一分首，萬里隔煙波。——王早',160,'御定全唐詩/json/789.json','["長安一分首，萬里隔煙波。——王早", "海上青山暮，天涯白髮多。——耿湋", "尋僧因看竹，訪道或求鵝。——辛晃", "雲樹無猿鳥，陰崖足薜蘿。——耿湋", "醉中留越客，興裏眄庭柯。——辛晃", "黃葉身仍逐，丹霄背未摩。——耿湋", "別愁連旦暮，歸夢繞關河。——辛晃", "高柳寒蟬對，空階夜雨和。——耿湋", "年華空荏苒，名宦轉蹉跎。——辛晃", "南陌東城路，春來幾度過。——耿湋"]'),
('yuding-14','連句多暇贈陸三山人','耿湋','唐','御定全唐诗','yuding','','[]','一生為墨客，幾世作茶仙。——耿湋',192,'御定全唐詩/json/789.json','["一生為墨客，幾世作茶仙。——耿湋", "喜是攀闌者，慚非負鼎賢。——陸羽", "禁門聞曙漏，顧渚入晨煙。——耿湋", "拜井孤城裏，攜籠萬壑前。——陸羽", "閑喧悲異趣，語默取同年。——耿湋", "曆落驚相偶，衰羸猥見憐。——陸羽", "詩書聞講誦，文雅接蘭荃。——耿湋", "未敢重芳席，焉能弄彩箋。——陸羽", "黑池流研水，徑石澀苔錢。——耿湋", "何事親香案，無端狎釣船。——陸羽", "野中求逸禮，江上訪遺編。——耿湋", "莫發搜歌意，予心或不然。——陸羽"]'),
('yuding-15','道州春日感興','李景儉','唐','御定全唐诗','yuding','','[]','始見花滿枝，又看花滿地。——李景儉',66,'御定全唐詩/json/789.json','["始見花滿枝，又看花滿地。——李景儉", "且持增氣酒，莫滴傷心淚。——呂溫", "深誠長鬱結，芳晨自妍媚。——呂恭", "嘯歌聊永日，誰知此時意。——李景儉"]'),
('yuding-16','中秋夜聽歌聯句','武元衡','唐','御定全唐诗','yuding','','[]','此夕來奔月，何時去上天。——崔備',99,'御定全唐詩/json/789.json','["此夕來奔月，何時去上天。——崔備", "雲鬟方自照，玉腕更呈鮮。——裴度", "燕婉人間意，飄颻物外緣。——柳公綽", "詩裁明月扇，歌索想夫憐。——武元衡", "暗染荀香久，長隨楚夢偏。——盧放", "會當來彩鳳。仿佛逐神仙。——盧士玫"]'),
('yuding-0','春池泛舟聯句','裴度','唐','御定全唐诗','yuding','','[]','鳳池新雨後，池上好風光。——劉禹錫',162,'御定全唐詩/json/790.json','["鳳池新雨後，池上好風光。——劉禹錫", "取酒愁春盡，留賓喜日長。——裴度", "柳絲迎畫舸，水鏡寫雕梁，——崔群", "潭洞迷仙府，煙霞認醉鄉。——賈餗", "鶯聲隨笑語，竹色入壺觴。——張籍", "晚景含澄澈，時芳得豔陽。——劉禹錫", "飛鳧拂輕浪，綠柳暗回塘。——裴度", "逸韻追安石，高居勝辟強。——崔群", "杯停新令舉，詩動彩箋忙。——賈餗", "顧謂同來客，歡游不可忘。——張籍"]'),
('yuding-1','西池落泉聯句','裴度','唐','御定全唐诗','yuding','','[]','東閣聽泉落，能令野興多。——行式',132,'御定全唐詩/json/790.json','["東閣聽泉落，能令野興多。——行式", "散時猶帶沫，淙處即跳波。——裴度", "偏洗磷磷石，還驚泛泛鵝。——張籍", "色清塵不染，光白月相和。——白居易", "噴雪縈松竹，攢珠濺芰荷。——劉禹錫", "對吟時合響，觸樹更搖柯。——張籍", "照圃紅分藥，侵階綠浸莎。——白居易", "日斜車馬散，餘韻逐鳴珂。——劉禹錫"]'),
('yuding-2','首夏猶清和聯句','裴度','唐','御定全唐诗','yuding','','[]','記得謝家詩，清和即此時。——白居易',164,'御定全唐詩/json/790.json','["記得謝家詩，清和即此時。——白居易", "餘花數種在，密葉幾重垂。——裴度", "芳謝人人惜，陰成處處宜。——劉禹錫", "水萍爭點綴，梁燕共追隨。——行式", "亂蝶憐疏蕊，殘鶯戀好枝。——張籍", "草香殊未歇，雲勢漸多奇。——白居易", "單服初寧體，新篁已出籬。——裴度", "與春為別近，覺日轉行遲。——劉禹錫", "繞樹風光少，侵階苔蘚滋。——行式", "惟思奉歡樂，長得在西池。——張籍"]'),
('yuding-3','薔薇花聯句','裴度','唐','御定全唐诗','yuding','','[]','似錦如霞色，連春接夏開。——劉禹錫',131,'御定全唐詩/json/790.json','["似錦如霞色，連春接夏開。——劉禹錫", "波紅分影入，風好帶香來。——裴度", "得地依東閣，當階奉上臺。——行式", "淺深皆有態，次第暗相催。——劉禹錫", "滿地愁英落，緣堤惜棹回。——裴度", "芳濃濡雨露，明麗隔塵埃。——行式", "似著胭脂染，如經巧婦裁。——白居易", "奈花無別計，只有酒殘杯。——張籍"]'),
('yuding-4','喜遇劉二十八偶書兩韻聯句','裴度','唐','御定全唐诗','yuding','','[]','病來佳興少，老去舊遊稀。笑語縱橫作，杯觴絡繹飛。——裴度',114,'御定全唐詩/json/790.json','["病來佳興少，老去舊遊稀。笑語縱橫作，杯觴絡繹飛。——裴度", "清談如水玉，逸韻貫珠璣。高位當金鉉，虛懷似布衣。——劉禹錫", "已容狂取樂，仍任醉忘機。舍眷將何適，留歡便是歸。——白居易", "鳳儀常欲附，蚊力自知微。願假尊罍末，膺門自此依。——李紳"]'),
('yuding-5','劉二十八自汝赴左馮，塗經洛中相見聯句','裴度','唐','御定全唐诗','yuding','','[]','不歸丹掖去，銅竹漫云云。唯喜因過我，須知未賀君。——裴度',228,'御定全唐詩/json/790.json','["不歸丹掖去，銅竹漫云云。唯喜因過我，須知未賀君。——裴度", "詩聞安石詠，香見令公熏。欲首函關路，來披緱嶺雲。——白居易", "貂蟬公獨步，鴛鷺我同群。插羽先飛酒，交鋒便戰文。——李紳", "鎮嵩知表德，定鼎為銘勳。顧鄙容商洛，征歡候汝墳。——劉禹錫", "頻年多謔浪，此夕任喧紛。故態猶應在，行期未要聞。——裴度", "游藩榮已久，捧袂惜將分。詎厭杯行疾，唯愁日向曛。——白居易", "窮陰初莽蒼，離思漸氤氳。殘雪午橋岸，斜陽伊水濆。——李紳", "上謨尊右掖，全略靜東軍。萬頃徒稱量，滄溟詎有垠。——劉禹錫"]'),
('yuding-6','度自到洛中與樂天為文酒之會時時構詠樂不可…因為聯句','裴度','唐','御定全唐诗','yuding','','[]','成周文酒會，吾友勝鄒枚。唯憶劉夫子，而今又到來。——裴度',430,'御定全唐詩/json/790.json','["成周文酒會，吾友勝鄒枚。唯憶劉夫子，而今又到來。——裴度", "欲迎先倒屣，亦坐便傾杯。飲許伯倫右，詩推公幹才。——白居易", "久曾聆郢唱，重喜上燕台。晝話牆陰轉，宵歡斗柄回。——劉禹錫", "新聲還共聽，故態複相咍。遇物皆先賞，從花半未開。——裴度", "起時烏帽側，散處玉山頹。墨客喧東閣，文星犯上台。——白居易", "詠吟君稱首，疏放我為魁。憶戴何勞訪，留髡不用猜。——裴度", "奉觴承麹糵，落筆捧瓊瑰。醉弁無妨側，詞鋒不可摧。——白居易", "水軒看翡翠，石徑踐莓苔。童子能騎竹，佳人解詠梅。——劉禹錫", "洛中三可矣，鄴下七悠哉。自向風光急，不須弦管催。——裴度", "樂觀魚踴躍，閑愛鶴裴回。煙柳青凝黛，波萍綠撥醅。——白居易", "春榆初改火，律管又飛灰。紅藥多遲發，碧松宜亂栽。——劉禹錫", "馬嘶駝陌上，鷁泛鳳城隈。色色時堪惜，些些病莫推。——裴度", "涸流尋軋軋，餘刃轉恢恢。從此知心伏，無因敢自媒。——劉禹錫", "室隨親客入，席許舊寮陪。逸興嵇將阮，交情陳與雷。——白居易", "洪爐思哲匠，大廈要群材。他日登龍路，應知免曝鰓。——劉禹錫"]'),
('yuding-7','宴興化池亭送白二十二東歸聯句','裴度','唐','御定全唐诗','yuding','','[]','東洛言歸去，西園告別來。白頭青眼客，池上手中杯。——裴度',228,'御定全唐詩/json/790.json','["東洛言歸去，西園告別來。白頭青眼客，池上手中杯。——裴度", "離瑟殷勤奏，仙舟委曲回。征輪今欲動，賓閣為誰開。——劉禹錫", "坐弄琉璃水，行登綠縟堆。花低妝照影，萍散酒吹醅。——白居易", "岸蔭新抽竹，亭香欲變梅。隨遊多笑傲，遇勝且裴回。——張籍", "澄澈連天境，潺湲出地雷。林塘難共賞，鞍馬莫相催。——裴度", "信及魚還樂，機忘鳥不猜。晚晴槐起露，新雨石添苔。——劉禹錫", "擬作雲泥別，尤思頃刻陪。歌停珠貫斷，飲罷玉峰頹。——白居易", "雖有逍遙志，其如磊落才。會當重入用，此去肯悠哉。——張籍"]'),
('yuding-8','西池送白二十二東歸兼寄令狐相公聯句','裴度','唐','御定全唐诗','yuding','','[]','促坐宴回塘，送君歸洛陽。彼都留上宰，為我說中腸。——裴度',127,'御定全唐詩/json/790.json','["促坐宴回塘，送君歸洛陽。彼都留上宰，為我說中腸。——裴度", "威鳳池邊別，冥鴻天際翔。披雲見居守，望日拜封章。——劉禹錫", "春盡年華少，舟通景氣長。送行歡共惜，寄遠意難忘。——張籍", "東道瞻軒蓋，西園醉羽觴。謝公深眷眄，商皓信輝光。——行式", "舊德推三友，新篇代八行。——"]'),
('yuding-9','杏園聯句','李絳','唐','御定全唐诗','yuding','','[]','杏園千樹欲隨風，一醉同人此暫同。——群上司空',84,'御定全唐詩/json/790.json','["杏園千樹欲隨風，一醉同人此暫同。——群上司空", "老態忽忘絲管裏，衰顏宜解酒杯中。——李絳", "曲江日暮殘紅在，翰苑年深舊事空。——白居易", "二十四年流落者，故人相引到花叢。——劉禹錫"]'),
('yuding-10','花下醉中聯句','李絳','唐','御定全唐诗','yuding','','[]','共醉風光地，花飛落酒杯。——李絳',134,'御定全唐詩/json/790.json','["共醉風光地，花飛落酒杯。——李絳", "殘春猶可賞，晚景莫相催。——劉禹錫", "酒幸年年有，花應歲歲開。——白居易", "且當金韻擲，莫遣玉山頹。——李絳", "高會彌堪惜，良時不易陪。——庾承宣", "誰能拉花住，爭換得春回。——劉禹錫", "我輩尋常有，佳人早晚來。——楊嗣複", "寄言三相府，欲散且裴回。——白居易"]'),
('yuding-11','樂天是月長齋鄙夫此時愁臥裏閭非遠雲霧難披因以…驚禪','劉禹錫','唐','御定全唐诗','yuding','','[]','五月長齋月，文心苦行心。蘭蔥不入戶，薝卜自成林。——劉禹錫',435,'御定全唐詩/json/790.json','["五月長齋月，文心苦行心。蘭蔥不入戶，薝卜自成林。——劉禹錫", "護戒先辭酒，嫌喧亦徹琴。塵埃賓位靜，香火道場深。——白居易", "我靜馴狂象，餐餘施眾禽。定知於佛佞，豈複向書淫。——劉禹錫", "闌藥凋紅豔，庭槐換綠陰。風光徒滿目，雲霧未披襟。——白居易", "樹為清涼倚，池因盥漱臨。蘋芳遭燕拂，蓮坼待蜂尋。——劉禹錫", "捨下環流水，窗中列遠岑。苔斑錢剝落，石怪玉嶔岑。——白居易", "鵲頂迎秋禿，鶯喉入夏瘖。綠楊垂嫩色，綖棘露長針。——劉禹錫", "散秩身猶幸，趨朝力不任。官將方共拙，年與病交侵。——白居易", "徇樂非時選，忘機似陸沈。鑒容稱四皓，捫腹有三壬。——劉禹錫", "攜手慚連璧，同心許斷金。紫芝雖繼唱，白雪少知音。——白居易", "憶罷吳門守，相逢楚水潯。舟中頻曲晏，夜後各加斟。——劉禹錫", "濁酒銷殘漏，弦聲間遠砧。酡顏舞長袖，密坐接華簪。——白居易", "持論峰巒峻，戰文矛戟森。笑言誠莫逆，造次必相箴。——劉禹錫", "往事應如昨，餘歡迄至今。迎君常倒屣，訪我輒攜衾。——白居易", "陰魄初離畢，陽光正在參。待公休一食，縱飲共狂吟。——劉禹錫"]'),
('yuding-12','秋霖即事聯句三十韻','白居易','唐','御定全唐诗','yuding','','[]','蕭索窮秋月，蒼茫苦雨天。泄雲生棟上，行潦入庭前。——白居易',430,'御定全唐詩/json/790.json','["蕭索窮秋月，蒼茫苦雨天。泄雲生棟上，行潦入庭前。——白居易", "苔色侵三徑，波聲想五弦。井蛙爭入戶，轍鮒亂歸泉。——王起", "高溜愁晨坐，空階驚夜眠。鶴鳴猶未已，蟻穴亦頻遷。——劉禹錫", "散漫疏還密，空蒙斷複連。竹沾青玉潤，荷滴白珠圓。——白居易", "地濕灰蛾滅，池添水馬憐。有苗沾霢霂，無月弄潺湲。——王起", "籬菊潛開秀，園蔬已罷鮮。斷行隨雁翅，孤嘯聳鳶肩。——劉禹錫", "橋柱黏黃菌，牆衣點綠錢。草荒行藥路，沙泛釣魚船。——白居易", "長者車猶阻，高人榻且懸。金烏何日見，玉爵幾時傳。——王起", "近井桐先落，當簷石欲穿。趨風誠有戀，披霧邈無緣。——劉禹錫", "廩米陳生醭，庖薪濕起煙。鳴雞潛報曉，急景暗凋年。——白居易", "蓋灑高松上，絲繁細柳邊。拂叢時起蝶，墮葉乍驚蟬。——王起", "巾角皆爭墊，裙裾別似湔。人多蒙翠被，馬盡著連幹。——劉禹錫", "好客無來者，貧家但悄然。濕泥印鶴跡，漏壁絡蝸涎。——白居易", "蚊聚雷侵室，鷗翻浪滿川。上樓愁冪冪，繞舍厭濺濺。——王起", "律候今秋矣，歡娛久曠焉。但令高興在，晴後奉周旋。——劉禹錫"]'),
('yuding-13','喜晴聯句','白居易','唐','御定全唐诗','yuding','','[]','苦雨晴何喜，喜于未雨時。氣收雲物變，聲樂鳥烏知。——白居易',430,'御定全唐詩/json/790.json','["苦雨晴何喜，喜于未雨時。氣收雲物變，聲樂鳥烏知。——白居易", "蕙泛光風圃，蘭開皎月池。千峰分遠近，九陌好追隨。——王起", "白日開天路，玄陰卷地維。餘清在林薄，新照入漣漪。——劉禹錫", "碧樹涼先落，青蕪濕更滋。曬毛經浴鶴，曳尾出泥龜。——白居易", "舞去商羊速，飛來野馬遲。柱邊無潤礎，臺上有遊絲。——王起", "橋淨行塵息，堤長禁柳垂。宮城開睥睨，觀闕麗罘罳。——劉禹錫", "洛水澄清鎮，嵩煙展翠帷。梁成虹乍見，市散蜃初移。——白居易", "藉草風猶暖，攀條露已晞。屋穿添碧瓦，牆缺召金錘。——王起", "迥徹來雙目，昏煩去四支。霞文晚煥爛，星影夕參差。——劉禹錫", "爽助門庭肅，寒摧草木衰。黃幹向陽菊，紅洗得霜梨。——白居易", "假蓋閑誰惜，彈弦燥更悲。散蹄良馬穩，炙背野人宜。——王起", "洞戶晨暉入，空庭宿霧披。推林出書目，傾笥上衣椸。——劉禹錫", "道路行非阻，軒車望可期。無辭訪圭竇，且願見瓊枝。——白居易", "山閣蓬萊客，儲宮羽翼師。每優陪麗句，何暇覿英姿。——王起", "玩景方搔首，懷人尚斂眉。因吟仲文什，高興盡於斯。——劉禹錫"]'),
('yuding-14','會昌春連宴即事','白居易','唐','御定全唐诗','yuding','','[]','元年寒食日，上巳暮春天。雞黍三家會，鶯花二節連。——白居易',430,'御定全唐詩/json/790.json','["元年寒食日，上巳暮春天。雞黍三家會，鶯花二節連。——白居易", "光風初澹蕩，美景漸暄妍。簪組蘭亭上，車輿曲水邊。——劉禹錫", "松聲添奏樂，草色助鋪筵。雀舫宜閑泛，螺杯任漫傳。——王起", "園蔬香帶露，廚柳暗藏煙。麗句輕珠玉，清談勝管弦。——白居易", "陌喧金距鬥，樹動彩繩懸。姹女妝梳豔，游童衣服鮮。——劉禹錫", "圃香知種蕙，池暖憶開蓮。怪石雲疑觸，夭桃火欲然。——王起", "正歡唯恐散，雖醉未思眠。嘯傲人間世，追隨地上仙。——白居易", "燕來雙涎涎，雁去累翩翩。行樂真吾事，尋芳獨我先。——劉禹錫", "滯周慚太史，入洛繼先賢。昔恨多分手，今歡謬比肩。——王起", "病猶陪宴飲，老更奉周旋。望重青雲客，情深白首年。——白居易", "遍嘗珍饌後，許入畫堂前。舞袖翻紅炬，歌鬟插寶蟬。——劉禹錫", "斷金多感激，倚玉貴遷延。說史吞顏注，論詩笑鄭箋。——王起", "松筠寒不變，膠漆冷彌堅。興伴王尋戴，榮同隗在燕。——白居易", "擲盧誇使氣，刻燭鬥成篇。實藝皆三捷，虛名愧六聯。——劉禹錫", "興闌猶舉白，話靜每思玄。更說歸時好，亭亭月正圓。——王起"]'),
('yuding-15','僕射來示有三春向晚四者難並之說誠哉是言輒…兼簡尚書','白居易','唐','御定全唐诗','yuding','','[]','三春今向晚，四者昔難並。借問低眉坐，何如攜手行。——白居易',430,'御定全唐詩/json/790.json','["三春今向晚，四者昔難並。借問低眉坐，何如攜手行。——白居易", "舊遊多過隙，新宴且尋盟。鸚鵡林須樂，麒麟閣未成。——王起", "分陰當愛惜，遲景好逢迎。林野熏風起，樓臺穀雨晴。——劉禹錫", "牆低山半出，池廣水初平。橋轉長虹曲，舟回小鷁輕。——白居易", "殘花猶布繡，密竹自聞笙。欲過芳菲節，難忘宴慰情。——王起", "月輪行似箭，時物始如傾。見雁隨兄去，聽鶯求友聲。——劉禹錫", "蕙長書帶展，菰嫩剪刀生。坐密衣裳暖，堂虛絲管清。——白居易", "峰巒侵碧落，草木近朱明。與點非沂水，陪膺是洛城。——王起", "撥醅爭綠醑，臥酪待朱櫻。幾處能留客，何人喚解酲。——劉禹錫", "舊儀尊右揆，新命寵春卿。有喜鵲頻語，無機鷗不驚。——白居易", "青林思小隱，白雪仰芳名。訪舊殊千里，登高賴九城。——王起", "酂侯司管鑰，疏傅傲簪纓。綸綍曾同掌，煙霄即上征。——劉禹錫", "冊庭嘗接武，書殿忝連衡。蘭室春彌馥，松心晚更貞。——白居易", "琴招翠羽下，鉤掣紫鱗呈，只願回烏景。誰能避兕觥。——王起", "方知醉兀兀，應是走營營。鳳閣鸞台路，從他年少爭。——白居易"]'),
('yuding-0','城南聯句','韓愈','唐','御定全唐诗','yuding','','[]','竹影金瑣碎，——孟郊',379,'御定全唐詩/json/791.json','["竹影金瑣碎，——孟郊", "泉音玉淙琤。琉璃剪木葉，——韓愈", "翡翠開園英。流滑隨仄步，——孟郊", "搜尋得深行。遙岑出寸碧，——韓愈", "遠目增雙明。幹穟紛拄地，——孟郊", "化蟲枯挶莖。木腐或垂耳，——韓愈", "草珠競駢睛。浮虛有新劚，——孟郊", "摧扤饒孤撐。囚飛黏網動，——韓愈", "盜啅接彈驚。脫實自開坼，——孟郊", "牽柔誰繞縈。禮鼠拱而立，——韓愈", "駭牛躅且鳴。蔬甲喜臨社，——孟郊", "田毛樂寬征。露螢不自暖，——韓愈", "凍蝶尚思輕。宿羽有先曉，——孟郊", "食鱗時半橫。菱翻紫角利，——韓愈", "荷折碧圓傾。楚膩鱣鮪亂，——孟郊", "獠羞蠃蟹並。桑蠖見虛指，——韓愈", "穴狸聞鬥獰。逗翳翅相築，——孟郊", "擺幽尾交搒。蔓涎角出縮，——韓愈", "樹啄頭敲鏗。修箭嫋金餌，——孟郊", "群鮮沸池羹。岸殼坼玄兆，——韓愈", "野麰漸豐萌。窯煙冪疏島，——孟郊", "沙篆印回平。z9肌遭眊刺，——韓愈", "啾耳聞雞生。奇慮恣回轉，——孟郊", "遐睎縱逢迎。顛林戢遠睫，——韓愈"]'),
('yuding-1','會合聯句','韓愈','唐','御定全唐诗','yuding','','[]','離別言無期，會合意彌重。——張籍',434,'御定全唐詩/json/791.json','["離別言無期，會合意彌重。——張籍", "病添兒女戀，老喪丈夫勇。——韓愈", "劍心知未死，詩思猶孤聳。——孟郊", "愁去劇箭飛，歡來若泉湧。——張徹", "析言多新貫，攄抱無昔壅。——張籍", "念難須勤追，悔易勿輕踵。——韓愈", "吟巴山犖嶨，說楚波堆壟。——孟郊", "馬辭虎豹怒，舟出蛟鼉恐。——張徹", "狂鯨時孤軒，幽狖雜百種。——韓愈", "瘴衣常腥膩，蠻器多疏冗。——張籍", "剝苔吊斑林，角飯餌沈塚。——韓愈", "忽爾銜遠命，歸歟舞新寵。——孟郊", "鬼窟脫幽妖，天居覿清栱。——韓愈", "京游步方振，謫夢意猶恟。——張籍", "詩書誇舊知，酒食接新奉。——韓愈", "嘉言寫清越，愈病失肬腫。——孟郊", "夏陰偶高庇，宵魄接虛擁。——韓愈", "雪弦寂寂聽，茗碗纖纖捧。——孟郊", "馳輝燭浮螢，幽響泄潛蛩。——韓愈", "詩老獨何心，江疾有餘t3。——孟郊", "我家本瀍穀，有地介皋鞏。休跡憶沈冥，峨冠慚闒gl。——韓愈", "升朝高轡逸，振物群聽悚。徒言濯幽泌，誰與薙荒茸。——張籍", "朝紳郁青綠，馬飾曜珪珙。國讎未銷鑠，我志蕩邛隴。——孟郊", "君才誠倜儻，時論方洶溶。格言多彪蔚，懸解無梏拲。——韓愈"]'),
('yuding-2','鬥雞聯句','韓愈','唐','御定全唐诗','yuding','','[]','大雞昂然來，小雞竦而待。——韓愈',361,'御定全唐詩/json/791.json','["大雞昂然來，小雞竦而待。——韓愈", "崢嶸顛盛氣，洗刷凝鮮彩。——孟郊", "高行若矜豪，側睨如伺殆。——韓愈", "精光目相射，劍戟心獨在。——孟郊", "既取冠為胄，複以距為鐓。天時得清寒，地利挾爽塏。——韓愈", "磔毛各噤z9，怒癭爭碨磊。俄膺忽爾低，植立瞥而改。——孟郊", "腷膊戰聲喧，繽翻落羽皠。中休事未決，小挫勢益倍。——韓愈", "妒腸務生敵，賊性專相醢。裂血失鳴聲，啄殷甚饑餒。——孟郊", "對起何急驚，隨旋誠巧紿。毒手飽李陽，神槌因朱亥。——韓愈", "惻心我以仁，碎首爾何罪。獨勝事有然，旁驚汗流浼。——孟郊", "知雄欣動顏，怯負愁看賄。爭觀雲填道，助叫波翻海。——韓愈", "事爪深難解，嗔睛時未怠。一噴一醒然，再接再礪乃。——孟郊", "頭垂碎丹砂，翼拓拖錦彩。連軒尚賈餘，清厲比歸凱。——韓愈", "選俊感收毛，受恩慚始隗。英心甘鬥死，義肉恥庖宰。——孟郊", "君看鬥雞篇，短韻有可采。——孟郊"]'),
('yuding-3','納涼聯句','韓愈','唐','御定全唐诗','yuding','','[]','遞嘯取遙風，微微近秋朔。——孟郊',602,'御定全唐詩/json/791.json','["遞嘯取遙風，微微近秋朔。——孟郊", "金柔氣尚低，火老候愈濁。——韓愈", "熙熙炎光流，竦竦高雲擢。——韓愈", "閃紅驚蚴虯，凝赤聳山嶽。目林恐焚燒，耳井憶瀺灂。——孟郊", "仰懼失交泰，非時結冰雹。化鄧渴且多，奔河誠已愨。——孟郊", "暍道者誰子，叩商者何樂。洗矣得滂沱，感然鳴鸑鷟。——孟郊", "嘉願苟未從，前心空緬邈。清砌千回坐，冷環再三握。——孟郊", "煩懷卻星星，高意還卓卓。——孟郊", "龍沈劇煮鱗，牛喘甚焚角。蟬煩鳴轉喝，烏噪饑不啄。——韓愈", "晝蠅食案繁，宵蚋肌血渥。單絺厭已褫，長wM倦還捉。——韓愈", "幸茲得佳朋，于此蔭華桷。青熒文簟施，淡澉甘瓜濯。——韓愈", "大壁曠凝淨，古畫奇駁犖。淒如羾寒門，皓若攢玉璞。——韓愈", "掃寬延鮮飆，汲冷漬香穱。篚實摘林珍，盤殽饋禽ob。——韓愈", "空堂喜淹留，貧饌羞齷齪。——韓愈", "殷勤相勸勉，左右加礱斫。賈勇發霜硎，爭前曜冰槊。——孟郊", "微然草根響，先被詩情覺。感衰悲舊改，工異逞新貌。——孟郊", "誰言擯朋老，猶自將心學。危簷不敢憑，朽機懼傾撲。——孟郊", "青雲路難近，黃鶴足仍鐲。未能飲淵泉，立滯叫芳藥。——孟郊", "與子昔睽離，嗟餘苦屯剝。直道敗邪徑，拙謀傷巧諑。——韓愈", "炎湖度氛氳，熱石行犖硞。痟肌夏尤甚，瘧渴秋更數。——韓愈", "君顏不可覿，君手無由搦。今來沐新恩，庶見返鴻樸。——韓愈", "儒庠恣遊息，聖籍飽商榷。危行無低徊，正言免咿喔。——韓愈", "車馬獲同驅，酒醪欣共欶。惟憂棄菅蒯，敢望侍帷幄。——韓愈", "此志且何如，希君為追琢。——韓愈"]'),
('yuding-4','秋雨聯句','韓愈','唐','御定全唐诗','yuding','','[]','萬木聲號呼，百川氣交會。——孟郊',420,'御定全唐詩/json/791.json','["萬木聲號呼，百川氣交會。——孟郊", "庭翻樹離合，牖變景明藹。——韓愈", "潈瀉殊未終，飛浮亦雲泰。——孟郊", "牽懷到空山，屬聽邇驚瀨。——韓愈", "簷垂白練直，渠漲清湘大。——孟郊", "甘津澤祥禾，伏潤肥荒艾。——韓愈", "主人吟有歡，客子歌無奈。——孟郊", "侵陽日沈玄，剝節風搜兌。——韓愈", "坱圠遊峽喧，颼飀臥江汰。——孟郊", "微飄來枕前，高灑自天外。——韓愈", "蛩穴何迫迮，蟬枝掃鳴噦。——孟郊", "楥菊茂新芳，徑蘭銷晚馤。——韓愈", "地鏡時昏曉，池星競漂沛。——孟郊", "歡呶尋一聲，灌注咽群籟。——韓愈", "儒宮煙火濕，市舍煎熬忲。——孟郊", "臥冷空避門，衣寒屢循帶。——韓愈", "水怒已倒流，陰繁恐凝害。——孟郊", "憂魚思舟楫，感禹勤畎澮。——韓愈", "懷襄信可畏，疏決須有賴。——孟郊", "筮命或馮蓍，蔔晴將問蔡。——韓愈", "庭商忽驚舞，墉禜亦親酹。——孟郊", "氛醨稍疏映，雺亂還擁薈。陰旌時摎流，帝鼓鎮訇磕。——韓愈", "棗圃落青璣，瓜畦爛文貝。貧薪不燭灶，富粟空填廥。——韓愈", "秦俗動言利，魯儒欲何匄。深路倒羸驂，弱途擁行軑。——孟郊"]'),
('yuding-5','征蜀聯句','韓愈','唐','御定全唐诗','yuding','','[]','日王忿違慠，有命事誅拔。蜀險豁關防，秦師縱橫猾。——韓愈',614,'御定全唐詩/json/791.json','["日王忿違慠，有命事誅拔。蜀險豁關防，秦師縱橫猾。——韓愈", "風旗匝地揚，雷鼓轟天殺。竹兵彼皴脆，鐵刃我槍bR。——孟郊", "刑神吒犛旄，陰焰颭犀劄。翻霓紛偃蹇，塞野澒坱圠。——韓愈", "生獰競掣跌，癡突爭填軋。渴鬥信豗呶，啖奸何噢嗗。——孟郊", "更呼相簸蕩，交斫雙缺齾。火發激鋩腥，血漂騰足滑。——韓愈", "飛猱無整陣，翩鶻有邪戛。江倒沸鯨鯤，山搖潰貙猰。——孟郊", "中離分二三，外變迷七八。逆頸盡徽索，仇頭恣髡鬝。——韓愈", "怒須猶鬇鬡，斷臂仍bsbS。——韓愈", "石潛設奇伏，穴覷騁精察。中矢類妖cd，跳鋒狀驚豽。——孟郊", "蹋翻聚林嶺，鬥起成埃圿。——孟郊", "旆亡多空杠，軸折鮮聯轄。剟膚浹瘡痍，敗面碎黥gp。——韓愈", "渾奔肆狂勷，捷竄脫趫黠。岩鉤踔狙猿，水漉雜鱣螖。——韓愈", "投奅鬧eGcP，填隍btbT傄。——韓愈", "強睛死不閉，獷眼困逾fx。爇堞熇歊熹，抉門呀拗s9。——孟郊", "天刀封未坼，酋膽懾前揠。跧梁排鬱縮，闖竇猰窋窡。——孟郊", "迫脅聞雜驅，咿呦叫冤跀。——孟郊", "窮區指清夷，凶部坐雕鎩。邛文裁斐斖，巴豔收婠妠。——韓愈", "椎肥牛呼牟，載實駝鳴s8。聖靈閔頑嚚，燾養均草y5。——韓愈", "下書遏雄虓，解罪吊攣瞎。——韓愈", "戰血時銷洗，劍霜夜清刮。漢棧罷囂闐，獠江息澎汃。——孟郊", "戍寒絕朝乘，刁暗歇宵詧。始去杏飛蜂，及歸柳嘶xK。——孟郊", "廟獻繁馘級，樂聲洞椌楬。——孟郊", "台圖煥丹玄，郊告儼匏秸。念齒慰黴黧，視傷悼瘢痆。——韓愈", "休輸任訛寢，報力厚麩秳。公歡鐘晨撞，室宴絲曉扴。——韓愈"]'),
('yuding-6','同宿聯句','韓愈','唐','御定全唐诗','yuding','','[]','自從別君來，遠出遭巧譖。——韓愈',265,'御定全唐詩/json/791.json','["自從別君來，遠出遭巧譖。——韓愈", "斑斑落春淚，浩浩浮秋浸。——孟郊", "毛奇睹象犀，羽怪見鵩鴆。——韓愈", "朝行多危棧，夜臥饒驚枕。——孟郊", "生榮今分逾，死棄昔情任。——韓愈", "鵷行參綺陌，雞唱聞清禁。——孟郊", "山晴指高標，槐密騖長蔭。——韓愈", "直辭一以薦，巧舌千皆fE。——孟郊", "匡鼎惟說詩，桓譚不讀讖。——韓愈", "逸韻何嘈嗷，高名俟沽賃。——孟郊", "紛葩歡屢填，曠朗憂早滲。——韓愈", "為君開酒腸，顛倒舞相飲。——孟郊", "曦光霽曙物，景曜鑠宵祲。——韓愈", "儒門雖大啟，奸首不敢闖。義泉雖至近，盜索不敢沁。——孟郊", "清琴試一揮，白鶴叫相喑。欲知心同樂，雙繭抽作紝。——孟郊"]'),
('yuding-7','莎柵聯句','韓愈','唐','御定全唐诗','yuding','','[]','冰溪時咽絕，風櫪方軒舉。——韓愈',32,'御定全唐詩/json/791.json','["冰溪時咽絕，風櫪方軒舉。——韓愈", "此處不斷腸，定知無斷處。——孟郊"]'),
('yuding-8','雨中寄孟刑部幾道聯句','韓愈','唐','御定全唐诗','yuding','','[]','秋潦淹轍跡，高居限參拜。——韓愈',441,'御定全唐詩/json/791.json','["秋潦淹轍跡，高居限參拜。——韓愈", "耿耿蓄良思，遙遙仰嘉話。——孟郊", "一晨長隔歲，百步遠殊界。——韓愈", "商聽饒清聳，悶懷空抑噫。——孟郊", "美君知道腴，逸步謝天械。——韓愈", "吟馨鑠紛雜，抱照瑩疑怪。——孟郊", "撞宏聲不掉，輸邈瀾逾殺。——韓愈", "簷瀉碎江喧，街流淺溪邁。——孟郊", "念初相遭逢，倖免因媒介。祛煩類決癰，愜興劇爬疥。——韓愈", "研文較幽玄，呼博騁雄快。今君軺方馳，伊我羽已鎩。——韓愈", "溫存感深惠，琢切奉明誡。——韓愈", "迨茲更凝情，暫阻若嬰瘵。欲知相從盡，靈珀拾纖芥。——孟郊", "欲知相益多，神藥銷宿憊。德符仙山岸，永立難欹壞。——孟郊", "氣涵秋天河，有朗無驚湃。——孟郊", "祥鳳遺蒿鷃，雲韶掩夷靺。爭名求鵠徒，騰口甚蟬喝。——韓愈", "未來聲已赫，始鼓敵前敗。鬥場再鳴先，遐路一飛屆。——韓愈", "東野繼奇躅，修綸懸眾犗。穿空細丘垤，照日陋菅蒯。——韓愈", "小生何足道，積慎如觸蠆。愔愔抱所諾，翼翼自申戒。——孟郊", "聖書空勘讀，盜食敢求嘬。惟當騎款段，豈望覿珪玠。——孟郊", "弱操愧筠杉，微芳比蕭z1。何以驗高明，柔中有剛夬。——孟郊"]'),
('yuding-9','遠遊聯句','韓愈','唐','御定全唐诗','yuding','','[]','別腸車輪轉，一日一萬周。——孟郊',561,'御定全唐詩/json/791.json','["別腸車輪轉，一日一萬周。——孟郊", "離思春冰泮，爛漫不可收。——韓愈", "馳光忽以迫，飛轡誰能留。——孟郊", "取之詎灼灼，此去信悠悠。——李翱", "楚客宿江上，夜魂棲浪頭。曉日生遠岸，水芳綴孤舟。——孟郊", "村飲泊好木，野蔬拾新柔。獨含淒淒別，中結鬱鬱愁。——孟郊", "人憶舊行樂，鳥吟新得儔。——孟郊", "靈瑟時窅窅，霠猿夜啾啾。憤濤氣尚盛，恨竹淚空幽。——韓愈", "長懷絕無已，多感良自尤。即路涉獻歲，歸期眇涼秋。——韓愈", "兩歡日牢落，孤悲坐綢繆。——韓愈", "觀怪忽蕩漾，叩奇獨冥搜。海鯨吞明月，浪島沒大漚。——孟郊", "我有一寸鉤，欲釣千丈流。良知忽然遠，壯志鬱無抽。——孟郊", "魍魅暫出沒，蛟螭互蟠蟉。昌言拜舜禹，舉eM淩鬥牛。——韓愈", "懷糈饋賢屈，乘桴追聖丘。飄然天外步，豈肯區中囚。——韓愈", "楚些待誰吊，賈辭緘恨投。翳明弗可曉，秘魂安所求。——孟郊", "氣毒放逐域，蓼雜芳菲疇。當春忽淒涼，不枯亦颼飀。——孟郊", "貉謠眾猥款，巴語相咿嚘。默誓去外俗，嘉願還中州。——孟郊", "江生行既樂，躬輦自相戮。飲醇趣明代，味腥謝荒陬。——孟郊", "馳深鼓利楫，趨險驚蜚輶。系石沈靳尚，開弓射鴅吺。——韓愈", "路暗執屏翳，波驚戮陽侯。廣泛信縹緲，高行恣浮游。——韓愈", "外患蕭蕭去，中悒稍稍瘳。振衣造雲闕，跪坐陳清猷。——韓愈", "德風變讒巧，仁氣銷戈矛。名聲照西海，淑問無時休。——韓愈", "歸哉孟夫子，歸去無夷猶。——韓愈"]'),
('yuding-10','晚秋郾城夜會聯句','韓愈','唐','御定全唐诗','yuding','','[]','從軍古雲樂，談笑青油幕。燈明夜觀棋，月暗秋城柝。——李正封',684,'御定全唐詩/json/791.json','["從軍古雲樂，談笑青油幕。燈明夜觀棋，月暗秋城柝。——李正封", "羈客方寂曆，驚烏時落泊。語闌壯氣衰，酒醒寒砧作。——韓愈", "遇主貴陳力，夷凶匪兼弱。百牢犒輿師，千戶購首惡。——李正封", "平生恥論兵，末暮不輕諾。徒然感恩義，誰複論勳爵。——韓愈", "多士被沾汙，小夷施毒蠚。何當鑄劍戟。相與歸台閣。——李正封", "室婦歎鳴鸛，家人祝喜鵲。終朝考蓍龜，何日親烝礿。——韓愈", "間使斷津梁，潛軍索林薄。紅塵羽書靖，大水沙囊涸。——李正封", "銘山子所工，插羽余何怍。未足煩刀俎，只應輸管鑰。——韓愈", "雨矢逐天狼，電矛驅海若。靈誅固無縱，力戰誰敢卻。——李正封", "峨峨雲梯翔，赫赫火箭著。連空隳雉堞，照夜焚城郭。——韓愈", "軍門宣一令，廟算建三略。雷鼓揭千槍，浮橋交萬筰。——李正封", "蹂野馬雲騰，映原旗火鑠。疲氓墜將拯，殘虜狂可縛。——韓愈", "摧鋒若貙兕，超乘如猱玃。逢掖服翻慚，縵胡纓可愕。——李正封", "星隕聞雊雉，師興隨唳鶴。虎豹貪犬羊，鷹鸇憎鳥雀。——韓愈", "燒陂除積聚，灌壘失依託。憑軾諭昏迷，執殳征暴虐。——李正封", "倉空戰卒饑，月黑探兵錯。凶徒更蹈藉，逆族相啖嚼。——韓愈", "軸轤亙淮泗，旆旌連夏鄂。大野縱氐羌，長河浴騮駱。——李正封", "東西競角逐，遠近施矰繳。人怨童聚謠，天殃鬼行瘧。——韓愈", "漢刑支郡黜，周制閒田削。侯社退無功，鬼薪懲不恪。——李正封", "余雖司斧鑕，情本尚丘壑。且待獻俘囚，終當返耕獲。——韓愈", "槁街陳鈇鉞，桃塞興錢鎛。地理畫封疆，天文掃寥廓。——李正封", "天子憫瘡痍，將軍禁鹵掠。策勳封龍額，歸獸獲麟腳。——韓愈", "詰誅敬王怒，給複哀人瘼。澤發解兜鍪，酡顏傾鑿落。——李正封", "安存惟恐晚，洗雪不論昨。暮鳥已安巢，春蠶看滿箔。——韓愈"]'),
('yuding-11','石鼎聯句','韓愈','唐','御定全唐诗','yuding','','[]','巧匠斫山骨，刳中事煎烹。——劉師服',419,'御定全唐詩/json/791.json','["巧匠斫山骨，刳中事煎烹。——劉師服", "直柄未當權，塞口且吞聲。——侯喜", "龍頭縮菌蠢，豕腹漲彭亨。——軒轅彌明", "外苞幹蘚文，中有暗浪驚。——劉師服", "在冷足自安，遭焚意彌貞。——侯喜", "謬當鼎鼐間，妄使水火爭。——軒轅彌明", "大似烈士膽，圓如戰馬纓。——劉師服", "上比香爐尖，下與鏡面平。——侯喜", "秋瓜未落蒂，凍芋強抽萌。——軒轅彌明", "一塊元氣閉，細泉幽竇傾。——劉師服", "不值輸寫處，焉知懷抱清。——侯喜", "方當洪爐然，益見小器盈。——軒轅彌明", "睆睆無刃跡，團團類天成。——劉師服", "遙疑龜負圖，出曝曉正晴。——侯喜", "旁有雙耳穿，上有孤髻撐。或訝短尾銚，又似無足鐺。——劉師服", "可惜寒食球，擲此傍路坑。——侯喜", "何當出灰灺，無計離瓶罌。——軒轅彌明", "陋質荷斟酌，狹中愧提擎。——劉師服", "豈能煮仙藥，但未汙羊羹。——侯喜", "形模婦女笑，度量兒童輕。——軒轅彌明", "徒示堅重性，不過升合盛。——劉師服", "傍似廢轂仰，側見折軸橫。——侯喜", "時於蚯蚓竅，微作蒼蠅鳴。——軒轅彌明", "以茲翻溢愆，實負任使誠。——劉師服"]'),
('yuding-12','有所思聯句','孟郊','唐','御定全唐诗','yuding','','[]','相思繞我心，日夕千萬重。年光坐婉娩，春淚銷顏容。——孟郊',56,'御定全唐詩/json/791.json','["相思繞我心，日夕千萬重。年光坐婉娩，春淚銷顏容。——孟郊", "台鏡晦舊暉，庭草滋深茸。望夫山上石，別劍水中龍。——韓愈"]'),
('yuding-13','遣興聯句','孟郊','唐','御定全唐诗','yuding','','[]','我心隨月光，寫君庭中央。——孟郊',192,'御定全唐詩/json/791.json','["我心隨月光，寫君庭中央。——孟郊", "月光有時晦，我心安所忘。——韓愈", "常恐金石契，斷為相思腸。——孟郊", "平生無百歲，岐路有四方。——韓愈", "四方各異俗，適異非所將。——孟郊", "駑蹄顧挫秣，逸翮遺稻粱。——韓愈", "時危抱獨沈，道泰懷同翔。——孟郊", "獨居久寂默，相顧聊慨慷。——韓愈", "慨慷丈夫志，可以曜鋒鋩。——孟郊", "蘧甯知卷舒，孔顏識行藏。——韓愈", "殷鑒諒不遠，佩蘭永芬芳。——孟郊", "苟無夫子聽，誰使知音揚。——韓愈"]'),
('yuding-14','贈劍客李園聯句','孟郊','唐','御定全唐诗','yuding','','[]','天地有靈術，得之者惟君。——孟郊',160,'御定全唐詩/json/791.json','["天地有靈術，得之者惟君。——孟郊", "築爐地區外，積火燒氛氳。——韓愈", "照海鑠幽怪，滿空歊異氛。——孟郊", "山磨電奕奕，水淬龍蝹蝹。——韓愈", "太一裝以寶，列仙篆其文。——孟郊", "可用懾百神，豈惟壯三軍。——韓愈", "有時幽匣吟，忽似深潭聞。——孟郊", "風胡久已死，此劍將誰分。——韓愈", "行當獻天子，然後致殊勳。——孟郊", "豈如豐城下，空有鬥間雲。——韓愈"]'),
('yuding-15','過海聯句','賈島','唐','御定全唐诗','yuding','','[]','沙鳥浮還沒，山雲斷複連。——高麗使',33,'御定全唐詩/json/791.json','["沙鳥浮還沒，山雲斷複連。——高麗使", "棹穿波底月，船壓水中天。——賈島"]'),
('yuding-0','妓席與杜牧之同詠','張祜','唐','御定全唐诗','yuding','','[]','骰子逡巡裹手拈，無因得見玉纖纖。——杜牧',40,'御定全唐詩/json/792.json','["骰子逡巡裹手拈，無因得見玉纖纖。——杜牧", "但知報導金釵落，仿佛還應露指尖。——張祜"]'),
('yuding-1','同趙二十二訪張明府郊居聯句','杜牧','唐','御定全唐诗','yuding','','[]','陶潛官罷酒瓶空，門掩楊花一夜風。——杜牧',80,'御定全唐詩/json/792.json','["陶潛官罷酒瓶空，門掩楊花一夜風。——杜牧", "古調詩吟山色裏，無弦琴在月明中。——趙嘏", "遠簷高樹宜幽鳥，出岫孤雲逐晚虹。——杜牧", "別後東籬數枝菊，不知閑醉與誰同。——趙嘏"]'),
('yuding-2','游長安諸寺聯句：靖恭坊大興善寺：老松青桐聯二…絕句','段成式','唐','御定全唐诗','yuding','','[]','有松堪系馬，遇缽更投針。記得湯師句，高禪助朗吟。——段成式',86,'御定全唐詩/json/792.json','["有松堪系馬，遇缽更投針。記得湯師句，高禪助朗吟。——段成式", "乘晴入精舍，語默想東林。儘是忘機侶，誰驚息影禽。——張希複", "一雨微塵盡，支郎許數過。方同嗅薝蔔，不用算多羅。——鄭符"]'),
('yuding-3','游長安諸寺聯句：靖恭坊大興善寺：蛤像聯二十字絕句','段成式','唐','御定全唐诗','yuding','','[]','相好全如梵，端倪只為隋。寧同蚌頑惡，但與鷸相持。——段成式',58,'御定全唐詩/json/792.json','["相好全如梵，端倪只為隋。寧同蚌頑惡，但與鷸相持。——段成式", "雖因雀變化，不逐月虧盈。縱有天中匠，神工詎可成。——張希複"]'),
('yuding-4','游長安諸寺聯句：靖恭坊大興善寺：聖柱聯句','段成式','唐','御定全唐诗','yuding','','[]','天心惟助善，聖跡此開陽。——段成式',68,'御定全唐詩/json/792.json','["天心惟助善，聖跡此開陽。——段成式", "載恐雷輪重，縆疑電索長。——張希複", "上沖挾螮蝀，不動束鋃鐺。——段成式", "饑鳥未曾啄，乖龍甯敢藏。——張希複"]'),
('yuding-5','游長安諸寺聯句：長樂坊安國寺：紅樓聯句','段成式','唐','御定全唐诗','yuding','','[]','重疊碎晴空，餘霞更照紅。蟬蹤近鳷鵲，鳥道接相風。——張希複',58,'御定全唐詩/json/792.json','["重疊碎晴空，餘霞更照紅。蟬蹤近鳷鵲，鳥道接相風。——張希複", "苔靜金輪路，雲輕白日宮。壁詩傳謝客，門榜占休公。——段成式"]'),
('yuding-6','游長安諸寺聯句：長樂坊安國寺：穗柏聯句','段成式','唐','御定全唐诗','yuding','','[]','一院暑難侵，莓苔共影深。標枝爭息鳥，餘吹正開襟。——段成式',58,'御定全唐詩/json/792.json','["一院暑難侵，莓苔共影深。標枝爭息鳥，餘吹正開襟。——段成式", "宿雨香添色，殘陽石在陰。乘閑動詩意，助靜入禪心。——張希複"]'),
('yuding-7','游長安諸寺聯句：長樂坊安國寺：題璘公院','段成式','唐','御定全唐诗','yuding','','[]','靜，虛。熱際，安居。——鄭符',89,'御定全唐詩/json/792.json','["靜，虛。熱際，安居。——鄭符", "龕燈斂，印香除。東林賓客，西澗圖書。簷外垂青豆，——段成式", "經中發白蕖。縱辯宗因袞袞，忘言理事如如。——段成式", "泉台定將入流否，鄰笛足疑清梵餘。——段成式"]'),
('yuding-8','游長安諸寺聯句：常樂坊趙景公寺：吳畫聯句','段成式','唐','御定全唐诗','yuding','','[]','慘澹十堵內，吳生縱狂跡。風雲將逼人，神鬼如脫壁。——段成式',144,'御定全唐詩/json/792.json','["慘澹十堵內，吳生縱狂跡。風雲將逼人，神鬼如脫壁。——段成式", "其中龍最怪，張甲方汗栗。黑雲夜窸窣，焉知不霹靂。——張希複", "此際忽仙子，獵獵衣舄奕。妙瞬乍疑生，參差奪人魄。——鄭符", "往往乘猛虎，沖梁聳奇石。蒼峭束高泉，角膝驚欹側。——段成式", "冥獄不可視，毛戴腋流液。苟能水成河，刹那沈火宅。——升上人"]'),
('yuding-9','游長安諸寺聯句：常樂坊趙景公寺：題約公院','段成式','唐','御定全唐诗','yuding','','[]','印火熒熒，燈續焰青。——張希複',59,'御定全唐詩/json/792.json','["印火熒熒，燈續焰青。——張希複", "七俱胝咒，四阿含經。——段成式", "各錄佳語，聊事素屏。——鄭符", "丈室安居，延賓不扃。——升上人"]'),
('yuding-10','游長安諸寺聯句：大同坊雲華寺：偶聯句','段成式','唐','御定全唐诗','yuding','','[]','共入夕陽寺，因窺甘露門。——升上人',101,'御定全唐詩/json/792.json','["共入夕陽寺，因窺甘露門。——升上人", "清香惹苔蘚，忍草雜蘭蓀。——鄭符", "捷偈飛鉗答，新詩倚仗論。——段成式", "壞幡標古刹，聖畫煥崇垣。——張希複", "豈慕穿籠鳥，難防在牖猿。——段成式", "一音唯一性，三語更三幡。——張希複"]'),
('yuding-11','游長安諸寺聯句：道政坊寶應寺：僧房聯句','段成式','唐','御定全唐诗','yuding','','[]','古畫思匡嶺，上方疑傅岩。蝶閑移忍草，蟬曉揭高杉。——段成式',58,'御定全唐詩/json/792.json','["古畫思匡嶺，上方疑傅岩。蝶閑移忍草，蟬曉揭高杉。——段成式", "香字消芝印，金經發茝函。井通松底脈，書坼洞中緘。——張希複"]'),
('yuding-12','游長安諸寺聯句：道政坊寶應寺：小小寫真聯句','段成式','唐','御定全唐诗','yuding','','[]','如生小小真，猶自未棲塵。——鄭符',167,'御定全唐詩/json/792.json','["如生小小真，猶自未棲塵。——鄭符", "褕袂將離座，斜柯欲近人。——段成式", "昔時知出眾，情寵占橫陳。——張希複", "不遣游張巷，豈教窺宋鄰。——鄭符", "庾樓吹笛裂，弘閣賞歌新。——段成式", "蟬怯纖腰步，蛾驚半額嚬。——張希複", "圖形誰有術，買笑詎辭貧。——段成式", "複隴迷村徑，重泉隔漢津。——鄭符", "同心知作羽，比目定為鱗。——張希複", "殘月巫山夕，餘霞洛浦晨。——段成式"]'),
('yuding-13','游長安諸寺聯句：平康坊菩薩寺：書事聯句','段成式','唐','御定全唐诗','yuding','','[]','悉為無事者，任被俗流憎。——鄭符',202,'御定全唐詩/json/792.json','["悉為無事者，任被俗流憎。——鄭符", "客異幹時客，僧非出院僧。——段成式", "遠聞疏牖磬，曉辨密龕燈。——張希複", "步觸珠幡響，吟窺缽水澄。——鄭符", "句饒方外趣，遊愜社中朋。——段成式", "靜裏已馴鴿，齋中亦好鷹。——張希複", "金塗筆是褧，彩溜紙非繒。——升上人", "錫杖已克鍛，田衣從懷塍。——段成式", "占床暫一脅，卷箔賴長肱。——張希複", "佛日初開照，魔天破幾層。——段成式", "咒中陳秘計，論處正先登。——張希複", "勇帶綻針石，危防丘井藤。——升上人"]'),
('yuding-14','游長安諸寺聯句：光宅坊光宅寺：中禪師影堂聯句','段成式','唐','御定全唐诗','yuding','','[]','名下固無虛，敖曹貌嚴毅。洞達見空王，圓融入佛地。——張希複',144,'御定全唐詩/json/792.json','["名下固無虛，敖曹貌嚴毅。洞達見空王，圓融入佛地。——張希複", "一言當要害，忽忽醒諸醉。不動須彌山，多方辯無匱。——鄭符", "坦率對萬乘，偈答無所避。爾如毗沙門，外形如脫履。——段成式", "但以理為量，不語怪力事。木石摧貢高，慈悲引貪恚。——升上人", "當時乏支許，何人契深致。隨宜詎說三，直下開不二。——段成式"]'),
('yuding-15','游長安諸寺聯句：翊善坊保壽寺：光天幀贊聯句','段成式','唐','御定全唐诗','yuding','','[]','觀音化身，厥形孔怪。胣腦淫厲，眾魔膜拜。——張希複',174,'御定全唐詩/json/792.json','["觀音化身，厥形孔怪。胣腦淫厲，眾魔膜拜。——張希複", "指夢鴻紛，榜列區界。其事明張，何不可解。——段成式", "閻阿德川，大士先天。眾象參羅，福源田田。——鄭符", "百億花發，百千燈然。膠如絡繹，浩汗連綿。——張希複", "焰摩界戚，洛迦苦霽。正念皈依，眾青如彗。——段成式", "戾宰可汰，癡膜可蛻。稽首如空，睟容若睇。——張希複", "闡提墨師，睹而面之。寸念不生，未遇乎而。——段成式"]'),
('yuding-16','游長安諸寺聯句：宣陽坊靜域寺：三階院聯句','段成式','唐','御定全唐诗','yuding','','[]','密密助堂堂，隋人歌檿桑。雙弧摧孔雀，一矢隕貪狼。——段成式',144,'御定全唐詩/json/792.json','["密密助堂堂，隋人歌檿桑。雙弧摧孔雀，一矢隕貪狼。——段成式", "百步望雲立，九規看月張。獲蛟徒破浪，中乙漫如牆。——張希複", "還似貫金鼓，更疑穿石樑。因添挽河力，為滅射天狂。——段成式", "絕藝卻南牧，英聲來鬼方。麗龜何足敵，殪豕未為長。——鄭符", "龍臂勝猿臂，星芒超箭芒。虛誇絕高鳥，垂拱議明堂。——段成式"]'),
('yuding-17','游長安諸寺聯句：崇義坊招福院：贈諸上人聯句','段成式','唐','御定全唐诗','yuding','','[]','翻了西天偈，燒餘梵宇香。撚眉愁俗客，支頰背殘陽。——段成式',116,'御定全唐詩/json/792.json','["翻了西天偈，燒餘梵宇香。撚眉愁俗客，支頰背殘陽。——段成式", "洲號惟思沃，山名只記匡。辨中摧世智，定裏破魔強。——張希複", "許睿禪心徹，湯休詩思長。朗吟疏磬斷，久語貫珠妨。——段成式", "乘興書芭葉，閑來入豆房。漫題存古壁，怪畫匝長廊。——張希複"]'),
('yuding-18','游長安諸寺聯句：招國坊崇濟寺：奇松聯二十字絕句','段成式','唐','御定全唐诗','yuding','','[]','杉松何相疏，榆柳方迥屑。無人擅談柄，一枝不敢折。——段成式',144,'御定全唐詩/json/792.json','["杉松何相疏，榆柳方迥屑。無人擅談柄，一枝不敢折。——段成式", "中庭苔蘚深，吹餘鳴佛禽。至於摧折枝，凡草猶避陰。——張希複", "僻徑根從露，閒房枝任侵。一株風正好，來助碧雲吟。——鄭符", "時時掃窗聲，重露滴寒砌。風颭一枝遒，閑窺別生勢。——升上人", "偃蓋入樓妨，盤根侵井窄。高僧獨惆悵，為與澄嵐隔。——段成式"]'),
('yuding-19','游長安諸寺聯句：永安坊永壽寺：閑中好','段成式','唐','御定全唐诗','yuding','','[]','閑中好，盡日松為侶。此趣人不知，輕風度僧語。——鄭符',80,'御定全唐詩/json/792.json','["閑中好，盡日松為侶。此趣人不知，輕風度僧語。——鄭符", "閑中好，塵務不縈心。坐對當窗木，看移三面陰。——段成式", "閑中好，幽磬度聲遲。卷上論題肇，畫中僧姓支。——張希複"]'),
('yuding-20','游長安諸寺聯句：崇仁坊資聖寺：諸畫聯句','段成式','唐','御定全唐诗','yuding','','[]','吳生畫勇矛戟攢，——段成式',140,'御定全唐詩/json/792.json','["吳生畫勇矛戟攢，——段成式", "出變奇勢千萬端。——張希複", "蒼蒼鬼怪層壁寬，——鄭符", "睹之忽忽毛髮寒。——段成式", "棱伽之力所疲殫，——段成式", "李真周昉優劣難。——鄭符", "活禽生卉推邊鸞，——段成式", "花房嫩彩猶未幹。——張希複", "韓幹變態如激湍，——鄭符", "惜哉壁畫世未殫。——段成式", "後人新畫何汗漫。——張希複"]'),
('yuding-0','北禪院避暑聯句','皮日休','唐','御定全唐诗','yuding','','[]','歊蒸何處避，來入戴顒宅。逍遙脫單絞，放曠拋輕策。——皮日休',460,'御定全唐詩/json/793.json','["歊蒸何處避，來入戴顒宅。逍遙脫單絞，放曠拋輕策。——皮日休", "爬搔林下風，偃仰澗中石。——皮日休", "殘蟬煙外響，野鶴沙中跡。到此失煩襟，蕭然揖禪伯。——陸龜蒙", "藤懸疊霜蛻，桂倚支雲錫。——陸龜蒙", "清陰豎毛髮，爽氣舒筋脈。逐幽隨竹書，選勝鋪苮席。——皮日休", "魚跳上紫芡，蝶化緣青壁。——皮日休", "心是玉蓮徒，耳為金磬敵。吾宗昔高尚，志在羲皇易。——陸龜蒙", "豈獨斷韋編，幾將刓鐵擿。——陸龜蒙", "天書既屢降，野抱難自適。一入承明廬，盱衡論今昔。——皮日休", "流光不容寸，斯道甘枉尺。——皮日休", "既起謝儒玄，亦翻商羽翼。封章帷幄遍，夢寐江湖白。——陸龜蒙", "擺落函谷塵，高欹華陽幘。——陸龜蒙", "詔去雲無信，歸來鶴相識。半病奪牛公，全慵捕魚客。——皮日休", "少微光一點，落此芒磔索。——皮日休", "釋子問池塘，門人廢幽賾。堪悲東序寶，忽變西方籍。——陸龜蒙", "不見步兵詩，空懷康樂屐。——陸龜蒙", "高名不可效，勝境徒堪惜。墨沼轉疏蕪，玄齋逾闃寂。——皮日休", "遲遲不可去，涼颸滿杉柏。——皮日休", "日下洲島清，煙生苾芻碧。俱懷出塵想，共有吟詩癖。——陸龜蒙", "終與淨名遊，還來雪山覓。——陸龜蒙"]'),
('yuding-1','寂上人院聯句','皮日休','唐','御定全唐诗','yuding','','[]','癭床空默坐，清景不知斜。暗數菩提子，閑看薜荔花。——皮日休',174,'御定全唐詩/json/793.json','["癭床空默坐，清景不知斜。暗數菩提子，閑看薜荔花。——皮日休", "有情惟墨客，無語是禪家。背日聊依桂，嘗泉欲試茶。——陸龜蒙", "石形蹲玉虎，池影閃金蛇。經笥安岩匼，瓶囊掛樹椏。——皮日休", "書傳滄海外，龕寄白雲涯。竹色寒淩箔，燈光靜隔紗。——陸龜蒙", "趁幽翻小品，逐勝講南華。莎彩融黃露，蓮衣染素霞。——皮日休", "水堪傷聚沫，風合落天葩。若許傳心印，何辭古堞賒。——陸龜蒙"]'),
('yuding-2','獨在開元寺避暑，頗懷魯望，因飛筆聯句','皮日休','唐','御定全唐诗','yuding','','[]','煩暑雖難避，僧家自有期。泉甘於馬乳，苔滑似龍漦。——皮日休',174,'御定全唐詩/json/793.json','["煩暑雖難避，僧家自有期。泉甘於馬乳，苔滑似龍漦。——皮日休", "任誕襟全散，臨幽榻旋移。松行將雅拜，篁陣欲交麾。——陸龜蒙", "望塔青髇識，登樓白鴿知。石經森欲動，珠像儼將怡。——皮日休", "筠簟臨杉穗，紗巾透雨絲。靜譚蟬噪少，涼步鶴隨遲。——皮日休", "煙重回蕉扇，輕風拂桂帷。對碑吳地說，開卷梵天詞。——陸龜蒙", "積水魚梁壞，殘花病枕欹。懷君瀟灑處，孤夢繞罘罳。——陸龜蒙"]'),
('yuding-3','寒夜文宴聯句','皮日休','唐','御定全唐诗','yuding','','[]','文星今夜聚，應在鬥牛間。——皮日休',168,'御定全唐詩/json/793.json','["文星今夜聚，應在鬥牛間。——皮日休", "載石人方至，乘槎客未還。——張賁", "送觴繁露曲，征句白雲顏。——陸龜蒙", "節奏惟聽竹，從容只話山。——皮日休", "理窮傾秘藏，論猛折玄關。——張賁", "酃酒分中綠，巴箋擘處殷。——陸龜蒙", "清言聞後醒，強韻壓來艱。——皮日休", "犀柄當風揖，瓊枝向月攀。——張賁", "松吟方eP々，泉夢憶潺潺。——陸龜蒙", "一會文章草，昭明不可刪。——皮日休"]'),
('yuding-4','藥名聯句','皮日休','唐','御定全唐诗','yuding','','[]','為待防風餅，須添薏苡杯。——張賁',200,'御定全唐詩/json/793.json','["為待防風餅，須添薏苡杯。——張賁", "香然柏子後，尊泛菊花來。——皮日休", "石耳泉能洗，垣衣雨為裁。——陸龜蒙", "從容犀局靜，斷續玉琴哀。——張賁", "白芷寒猶采，青箱醉尚開。——皮日休", "馬銜衰草臥，烏啄蠹根回。——陸龜蒙", "雨過蘭芳好，霜多桂末摧。——張賁", "朱兒應作粉，雲母詎成灰。——皮日休", "藝可屠龍膽，家曾近燕胎。——陸龜蒙", "牆高牽薜荔，障軟撼玫瑰。——張賁", "鸓鼠啼書戶，蝸牛上研台。——皮日休", "誰能將槁本，封與玉泉才。——陸龜蒙"]'),
('yuding-5','寒夜聯句','陸龜蒙','唐','御定全唐诗','yuding','','[]','靜境揖神凝，寒華射林缺。——陸龜蒙',170,'御定全唐詩/json/793.json','["靜境揖神凝，寒華射林缺。——陸龜蒙", "清知思緒斷，爽覺心源徹。——皮日休", "高唱戛金奏，朗詠鏗玉節。——陸龜蒙", "我思方泬寥，君詞複淒切。——皮日休", "況聞風篁上，擺落殘凍雪。——陸龜蒙", "寂爾萬籟清，皎然諸靄滅。——皮日休", "西窗客無夢，南浦波應結。——陸龜蒙", "河光正如劍，月魄方似玦。——皮日休", "短燼不禁挑，冷毫看欲折。——陸龜蒙", "何夕重相期，濁醪還為設。——皮日休"]'),
('yuding-6','開元寺樓看雨聯句','陸龜蒙','唐','御定全唐诗','yuding','','[]','海上風雨來，掀轟雜飛電。登樓一憑檻，滿眼蛟龍戰。——陸龜蒙',349,'御定全唐詩/json/793.json','["海上風雨來，掀轟雜飛電。登樓一憑檻，滿眼蛟龍戰。——陸龜蒙", "須臾造化慘，倏忽堪輿變。萬戶響戈鋋，千家披組練。——皮日休", "群飛拋輪石，雜下攻城箭。點急似摧胸，行斜如中面。——陸龜蒙", "細灑魂空冷，橫飄目能眩。垂簷珂佩喧，zh瓦珠璣濺。——皮日休", "無言九陔遠，瞬息馳應遍。密處正垂縆，微時又懸線。——陸龜蒙", "寫作玉界破，吹為羽林旋。翻傷列缺勞，卻怕豐隆倦。——皮日休", "遙瞻山露色，漸覺雲成片。遠樹欲鳴蟬，深簷尚藏燕。——陸龜蒙", "殘雷隱轔盡，反照依微見。天光潔似磨，湖彩熟於練。——皮日休", "疏帆逗前渚，晚磬分涼殿。接思強揮毫，窺詞幾焚研。——陸龜蒙", "佶栗烏皮幾，輕明白羽扇。畢景好疏吟，餘涼可清宴。——皮日休", "君攜下高磴，僧引還深院。駁蘚淨鋪筵，低松濕垂鬋。——陸龜蒙", "齋明乍虛豁，林霽逾蔥蒨。早晚重登臨，欲去多離戀。——皮日休"]'),
('yuding-7','報恩寺南池聯句','陸龜蒙','唐','御定全唐诗','yuding','','[]','古岸涵碧落，——陸龜蒙',238,'御定全唐詩/json/793.json','["古岸涵碧落，——陸龜蒙", "虛軒明素波。坐來魚陣變，——皮日休", "吟久菊□多。秋草分杉露，——嵩起", "危橋下竹坡。遠峰青髻並，——陸龜蒙", "□□□髯和。趙論寒仍講，——皮日休", "支硎僻亦過。齋心曾養鶴，——嵩起", "揮翰好邀鵝。倚石收奇藥，——陸龜蒙", "臨溪藉淺莎。桂花晴似拭，——皮日休", "荷鏡曉如磨。翠出牛頭聳，——嵩起", "苔深馬跡跛。傘欹從野醉，——陸龜蒙", "巾側任田歌。跁跒松形矮，——皮日休", "般跚檜樾矬。香飛僧印火，——嵩起", "泉急使鑣珂。菱鈿真堪帖，——陸龜蒙", "蓴絲亦好拖。幾時無一事，——皮日休", "相伴著煙蘿。——嵩起"]'),
('yuding-8','天臺禪院聯句','安守範','唐','御定全唐诗','yuding','','[]','偶到天臺院，因逢物外僧。——安守範',67,'御定全唐詩/json/793.json','["偶到天臺院，因逢物外僧。——安守範", "忘機同一祖，出語離三乘。——楊鼎夫", "樹老中庭寂，窗虛外境澄。——周述", "片時松影下，聯續百千燈。——李仁肇"]'),
('yuding-0','講德聯句','皎然','唐','御定全唐诗','yuding','','[]','先王設位，以正邦國。建立大官，封植有德。——潘述',336,'御定全唐詩/json/794.json','["先王設位，以正邦國。建立大官，封植有德。——潘述", "二南敷化，四嶽述職。其言不朽，其儀不忒。——湯衡", "暨于嬴劉，乃創程式。罷侯置守，剖竹分域。——皎然", "赫矣皇唐，康哉立極。精選藩翰，庸資正直。——潘述", "爰命我公，東土作則。克己恭儉，疲人休息。——湯衡", "濟濟閭閈，油油黍稷。既富既教，足兵足食。——皎然", "恤其凋瘵，剪其荊棘。威懷逋叛，撲滅蝥賊。——潘述", "疾惡如讎，聞善不惑。哀矜鰥寡，旌禮儒墨。——湯衡", "乃修堤防，乃浚溝洫。以利通商，以溉嘉穀。——皎然", "征賦以節，計功以時。人胥懷惠，吏不能欺。——潘述", "我政載孚，我邦載綏。猛獸不暴，嘉魚維滋。——湯衡", "肅恭明神，齊沐不虧。歲或驕陽，雨無愆期。——皎然", "帝嘉有庸，寵命來斯。紫紱載綏，金章陸離。——潘述", "資忠履孝，閱禮敦詩。明德惟馨，自天佑之。——湯衡"]'),
('yuding-1','講古文聯句','皎然','唐','御定全唐诗','yuding','','[]','帝出於震，文明始敷。——潘述',336,'御定全唐詩/json/794.json','["帝出於震，文明始敷。——潘述", "山嶽降氣，龜龍負圖。——裴濟", "爰有書契，乃立典謨。——皎然", "先知孔聖，飛步天衢。——湯衡", "漢承秦弊，尊儒尚學。——潘述", "百氏六經，九流七略。——裴濟", "屈宋接武，班馬繼作。——皎然", "或頌燕然，或贊麟閣。——湯衡", "降及三祖，始變二雅。——潘述", "仲宣閑和，公幹蕭灑。——皎然", "士衡安仁，不史不野。——皎然", "左張精奧，嵇阮高寡。——湯衡", "暨于江表，其文鬱興。——湯衡", "綺麗爭發，繁蕪則懲。——潘述", "詞曄春華，思清冬冰。——潘述", "景純跌宕，游仙獨步。——湯衡", "青雲其情，白璧其句。——湯衡", "靈運山水，實多奇趣。——潘述", "遠派孤峰，龍騰鳳翥。——潘述", "陶令田園，匠意真直。——皎然", "春柳寒松，不凋不飾。——皎然", "江淹雜體，方見才力。——湯衡", "擬之信工，似而不逼。——湯衡", "鮑昭從軍，主意危苦。——潘述"]'),
('yuding-2','項王古祠聯句','皎然','唐','御定全唐诗','yuding','','[]','遺廟風塵積，荒途歲月侵。——潘述',96,'御定全唐詩/json/794.json','["遺廟風塵積，荒途歲月侵。——潘述", "英靈今寂寞，容衛尚森沈。——皎然", "霸楚志何在，平秦功亦深。——湯衡", "諸侯歸複背，青史古將今。——潘述", "星聚分已定，天亡力豈任。——皎然", "采蘩如可薦，舉酒瀝空林。——湯衡"]'),
('yuding-3','還丹可成詩聯句','皎然','唐','御定全唐诗','yuding','','[]','羽化自仙骨，延年資養生。——皎然',192,'御定全唐詩/json/794.json','["羽化自仙骨，延年資養生。——皎然", "金經啟靈秘，玉液流至精。——潘述", "八石思共煉，九丹知可成。——湯衡", "吾心苟無妄，神理期合併。——皎然", "封灶用六一，置門考休京。——潘述", "浮光含日彩，圓質煥雲英。——湯衡", "持此保壽命，服之頤性情。——皎然", "跂予望仙侶，高詠升天行。——潘述", "鶴駕方可致，霓裳定將迎。——湯衡", "不因五色藥，安著七真名。——皎然", "揮妙在微密，全功知感誠。——潘述", "與君棄城市，攜手遊蓬瀛。——湯衡"]'),
('yuding-4','建安寺西院喜王郎中遘恩命初至聯句','皎然','唐','御定全唐诗','yuding','','[]','跡就空門退，官從畫省遷。住持良有願，朝謁穴無緣。——王遘',93,'御定全唐詩/json/794.json','["跡就空門退，官從畫省遷。住持良有願，朝謁穴無緣。——王遘", "身淨金繩內，心馳玉扆前。——皎然", "榮添一兩日，恩降九霄年。——齊翔", "慕法能輕冕，追非欲佩弦。——李縱", "棲閑那可久，鴛鷺待行聯。——崔子向"]'),
('yuding-5','建安寺夜會，對雨懷皇甫侍禦曾聯句','皎然','唐','御定全唐诗','yuding','','[]','相思非是遠，風雨遣情多。——皎然',97,'御定全唐詩/json/794.json','["相思非是遠，風雨遣情多。——皎然", "願欲披雲見，難堪候曉過。——李縱", "夜長同歲月，地近極山河。——鄭說", "戒相初傳授，文章舊切磋。——王遘", "時稱洛下詠，人許郢中歌。——崔子向", "惆悵徒延首，其如一水何。——齊翔"]'),
('yuding-6','泛長城東溪，暝宿崇光寺，寄處士陸羽聯句','皎然','唐','御定全唐诗','yuding','','[]','箬水青似箬，玉山碧於玉。——崔子向',231,'御定全唐詩/json/794.json','["箬水青似箬，玉山碧於玉。——崔子向", "逼霄遝萬狀，截地分千曲。——皎然", "萍解深可窺，林豁遙在矚。——崔子向", "已高物外賞，稍滌區中欲。——皎然", "野鶴翔又飛，世人羈且局。——崔子向", "沈吟跡所誤，放浪心自足。——皎然", "緬懷虛舟客，願寄生芻束。——崔子向", "說詩整頹波，立義激浮俗。——皎然", "荊吳備登曆，風土隨編錄。——崔子向", "恨與清景別，擬教長路促。——皎然", "溪鳥語鸝嘍，寺花翻躑躅。——崔子向", "印圍水壇淨，香護蓮衣觸。——皎然", "捧經啟紗燈，收衽禮金粟。——崔子向", "安得扣關子，玄言對吾屬。——皎然"]'),
('yuding-7','與崔子向泛舟自招橘經箬裏宿天居寺…聯一十六韻以寄之','皎然','唐','御定全唐诗','yuding','','[]','晴日春態深，寄遊恣所適。——皎然',264,'御定全唐詩/json/794.json','["晴日春態深，寄遊恣所適。——皎然", "寧妨花木亂，轉學心耳寂。——崔子向", "取性憐鶴高，謀閑任山僻。——皎然", "倚舷息空曲，舍履行淺磧。——崔子向", "渚箬入裏逢，野梅到村摘。——皎然", "碑殘飛雉嶺，井翳潛龍宅。——崔子向", "壞寺鄰壽陵，古壇留劫石。——皎然", "穿階筍節露，拂瓦松梢碧。——崔子向", "天界細雲還，牆陰雜英積。——皎然", "懸燈寄前焰，遙月升圓魄。——崔子向", "何意清夜期，坐為高峰隔。——皎然", "茗園可交袂，藤澗好停錫。——崔子向", "微雨聽濕巾，迸流從點席。——皎然", "戲猿隔枝透，驚鹿逢人躑。——崔子向", "睹物賞已奇，感時思彌極。——皎然", "芳菲如馳箭，望望共君惜。——崔子向"]'),
('yuding-8','渚山春暮，會顧丞茗舍，聯句效小庾體','皎然','唐','御定全唐诗','yuding','','[]','誰是惜暮人，相攜送春日。因君過茗舍，留客開蘭室。——陸士修',172,'御定全唐詩/json/794.json','["誰是惜暮人，相攜送春日。因君過茗舍，留客開蘭室。——陸士修", "濕苔滑行屐，柔草低藉瑟。鵲喜語成雙，花狂落非一。——崔子向", "煙濃山焙動，泉破水舂疾。莫抝掛瓢枝，會移閬書帙。——皎然", "頗容樵與隱，豈聞禪兼律。欄竹不求疏，網藤從更密。——陸士修", "池添逸少墨，園雜莊生漆。景晏枕猶欹，酒醒頭懶櫛。——崔子向", "雲教淡機慮，地可遺名實。應待禦荈青，幽期踏芳出。——皎然"]'),
('yuding-9','與李司直令從荻塘聯句','皎然','唐','御定全唐诗','yuding','','[]','畫舸悠悠荻塘路，真僧與我相隨去。——李令從',164,'御定全唐詩/json/794.json','["畫舸悠悠荻塘路，真僧與我相隨去。——李令從", "寒花似菊不知名，霜葉如楓是何樹。——李令從", "倦客經秋夜共歸，情多語盡明相顧。——皎然", "遙城候騎來仍少，傍嶺哀猿發無數。——皎然", "心閑清淨得禪寂，興逸縱橫問章句。——李令從", "蟲聲切切草間悲，螢影紛紛月前度。——李令從", "撩亂雲峰好賦詩，嬋娟水月堪為喻。——皎然", "與君出處本不同，從此還依舊山住。——皎然"]'),
('yuding-10','遠意聯句','皎然','唐','御定全唐诗','yuding','','[]','家在炎州往朔方，——疾',95,'御定全唐詩/json/794.json','["家在炎州往朔方，——疾", "豈知於闐望瀟湘。——澄", "曾經隴底複遼陽，——巨川", "更憶東去采扶桑。——皎然", "楂客三千路未央，——嚴伯均", "燭龍之地日無光。——疾", "將遊莽蒼窮大荒，——皎然", "車轍馬足逐周王。——嚴伯均"]'),
('yuding-11','暗思聯句','皎然','唐','御定全唐诗','yuding','','[]','斜風飄雨三十夜，——疾',60,'御定全唐詩/json/794.json','["斜風飄雨三十夜，——疾", "鄰女餘光不相借。——巨川", "跡滅塵生古人畫，——皎然", "洞房重扉無隙罅，——嚴伯均", "燭滅更深月西謝。——從心"]'),
('yuding-12','樂意聯句一首','皎然','唐','御定全唐诗','yuding','','[]','良朋益友自遠來，——嚴伯均',59,'御定全唐詩/json/794.json','["良朋益友自遠來，——嚴伯均", "萬里鄉書對酒開。——皎然", "子孫蔓衍負奇才，——疾", "承顏弄鳥詠南陔，——澄", "鼓腹擊壤歌康哉。——巨川"]'),
('yuding-13','恨意聯句','皎然','唐','御定全唐诗','yuding','','[]','同心同縣不相見，——疾',70,'御定全唐詩/json/794.json','["同心同縣不相見，——疾", "獨采蘼蕪詠團扇。——嚴伯均", "莫聽東鄰搗霜練，——皎然", "遠憶征人淚如霰。——澄", "長信空階荒草遍，——從心", "明妃初別昭陽殿。——杭"]'),
('yuding-14','秋日盧郎中使君幼平泛舟聯句一首','皎然','唐','御定全唐诗','yuding','','[]','共載清秋客船，同瞻皂蓋朝天。——盧藻',127,'御定全唐詩/json/794.json','["共載清秋客船，同瞻皂蓋朝天。——盧藻", "悔使比來相得，如今欲別潸然。——盧幼平", "漸驚徒馭分散，愁望雲山接連。——皎然", "魏闕馳心日日，吳城揮手年年。——陸羽", "送遠已傷飛雁，裁詩更切嘶蟬。——潘述", "空懷鄠杜心醉，永望門欄脰捐。——李恂", "別思無窮無限，還如秋水秋煙。——潘述"]'),
('yuding-15','重聯句一首','皎然','唐','御定全唐诗','yuding','','[]','相將惜別且遲遲，未到新豐欲醉時。——盧幼平',120,'御定全唐詩/json/794.json','["相將惜別且遲遲，未到新豐欲醉時。——盧幼平", "去郡獨攜程氏酒，入朝可忘習家池。——陸羽", "仍憐故吏依依戀，自有清光處處隨。——潘述", "晚景南徐何處宿，秋風北固不堪辭。——皎然", "吳中詩酒饒佳興，秦地關山引夢思。——盧藻", "對酒已傷嘶馬去，銜恩只待掃門期。——惸"]'),
('yuding-16','與潘述集湯衡宅懷李司直縱聯句','皎然','唐','御定全唐诗','yuding','','[]','幽獨何以慰，友人顧茅茨。——湯衡',96,'御定全唐詩/json/794.json','["幽獨何以慰，友人顧茅茨。——湯衡", "已忘歲月念，載說清閒時。——潘述", "旭日舒朱槿，柔風引綠葹。——皎然", "迢迢青溪路，耿耿芳樹枝。——湯衡", "執衽空躑躅，來城自逶迤。——潘述", "相思寄采掇，景晏獨驅馳。——皎然"]'),
('yuding-17','安吉崔明甫山院聯句一首','皎然','唐','御定全唐诗','yuding','','[]','人不擾，政已和。世慮寡，山情多。——皎然',40,'御定全唐詩/json/794.json','["人不擾，政已和。世慮寡，山情多。——皎然", "禪客至，墨卿過。興既洽，情如何。——崔逵"]'),
('yuding-18','重聯句一首','皎然','唐','御定全唐诗','yuding','','[]','肅肅清院，翛翛碧鮮。已見心遠，何關地偏。——皎然',48,'御定全唐詩/json/794.json','["肅肅清院，翛翛碧鮮。已見心遠，何關地偏。——皎然", "自公退食，升堂草玄。紛紛已隔，雲心澹然。——崔逵"]'),
('yuding-19','重聯句一首','皎然','唐','御定全唐诗','yuding','','[]','瀑溜聞窗外，晴風逼座間。——皎然',32,'御定全唐詩/json/794.json','["瀑溜聞窗外，晴風逼座間。——皎然", "掛冠徒有意，芳桂杳難攀。——崔逵"]'),
('yuding-20','重聯句一首','皎然','唐','御定全唐诗','yuding','','[]','清高素非宦侶，疏散從來道流。——皎然',72,'御定全唐詩/json/794.json','["清高素非宦侶，疏散從來道流。——皎然", "今日還輕墨綬，知君意在滄洲。——皎然", "浮雲任從飄蕩，寄隱也信沈浮。——崔逵", "不似漳南地僻，道安為我淹留。——崔逵"]'),
('yuding-21','重聯句一首','皎然','唐','御定全唐诗','yuding','','[]','劉令興多常步履，柴桑事少但援琴。——皎然',80,'御定全唐詩/json/794.json','["劉令興多常步履，柴桑事少但援琴。——皎然", "閑招法侶從山寺，每掇幽芳傍竹林。——皎然", "捲簾只愛荊峰色，入座偏宜郢客吟。——崔逵", "誰許近來輕印綬，因君昨日悟禪心。——崔逵"]'),
('yuding-22','道觀中和潘丞觀青溪圖聯句','皎然','唐','御定全唐诗','yuding','','[]','畫得青溪樣，宜於紫府觀。——皎然',64,'御定全唐詩/json/794.json','["畫得青溪樣，宜於紫府觀。——皎然", "日明煙靄薄，風落水容寬。——崔萬", "畫野高低接，商工井邑攢。——潘述", "疏川因稼穡，出使問艱難。——皎然"]'),
('yuding-23','春日對雨聯句一首','皎然','唐','御定全唐诗','yuding','','[]','春煙帶微雨，漠漠連城邑。桐葉生微陰，桃花更宜濕。——韓章',168,'御定全唐詩/json/794.json','["春煙帶微雨，漠漠連城邑。桐葉生微陰，桃花更宜濕。——韓章", "蕭條暗楊柳，散漫下原隰。歸路不我從，遙心空佇立。——皎然", "林低山影近，岸轉水流急。芳草自堪游，白雲如可揖。——韓章", "尋山禪客意，苦雨陶公什。遊衍情未終，歸飛暮相及。——皎然", "峰高日色轉，潭淨天光入。卻欲學神仙，空思謝朋執。——韓章", "為道貴逍遙，趨時多苦集。瓊英若可餐，青紫徒勞拾。——皎然"]'),
('yuding-24','春日會韓武康章後亭聯句','皎然','唐','御定全唐诗','yuding','','[]','後園堪寄賞，日日對春風。客位繁陰下，公牆細柳中。——皎然',158,'御定全唐詩/json/794.json','["後園堪寄賞，日日對春風。客位繁陰下，公牆細柳中。——皎然", "坐看青嶂遠，心與白雲同。——韓章", "林暗花煙入，池深遠水通。——楊秦卿", "井桃新長蕊，欄藥未成叢。——仲文", "松竹宜禪客，山泉入謝公。——皎然", "砌香翻芍藥，簷靜倚梧桐。——韓章", "外慮宜簾卷，忘情與道空。——楊秦卿", "楚僧招惠遠，蜀客挹揚雄。——仲文", "便寄柴桑隱，何勞訪剡東。——皎然"]'),
('yuding-25','康錄事宅送僧聯句','皎然','唐','御定全唐诗','yuding','','[]','蓮衣宜著雨，竹錫好隨雲。——皎然',33,'御定全唐詩/json/794.json','["蓮衣宜著雨，竹錫好隨雲。——皎然", "見鶴還應養，逢鷗自作群。——崔子向"]'),
('yuding-26','與邢端公李台題庭石聯句','皎然','唐','御定全唐诗','yuding','','[]','共題詩句遍，爭坐蘚文稀。——皎然',16,'御定全唐詩/json/794.json','["共題詩句遍，爭坐蘚文稀。——皎然"]'),
('yuding-27','冬日建安寺西院，喜晝公自吳興至，聯句一首','皎然','唐','御定全唐诗','yuding','','[]','宗系傳康樂，精修學遠公。——王遘',97,'御定全唐詩/json/794.json','["宗系傳康樂，精修學遠公。——王遘", "相尋當暮歲，行李犯寒風。——李縱", "累積浮生裏，機慚半偈中。——鄭說", "傳家知業墜，繼祖忝聲同。——皎然", "雲與輕帆至，山將本寺空。——崔子向", "向來忘起滅，留我宿花宮。——齊翔"]'),
('yuding-28','秋日潘述自長城至霅上與晝公、湯評事遊集累日…以寄之','皎然','唐','御定全唐诗','yuding','','[]','離念非前期，秋風忽已至。——潘述',112,'御定全唐詩/json/794.json','["離念非前期，秋風忽已至。——潘述", "芸黃眾芳晚，搖盪居人思。——皎然", "白霜淒以積，高梧颯而墜。——湯衡", "悠然越山川，複此恨離異。——潘述", "時景易遷謝，歡□難兼遂。——皎然", "惜分緩回舟，懷遙企歸駟。——湯衡", "休浣情自高，來思日雲未。——潘述"]'),
('yuding-29','喜晝公尋山回相遇聯句一首','皎然','唐','御定全唐诗','yuding','','[]','幾年無此會，今日喜相從。——潘述',64,'御定全唐詩/json/794.json','["幾年無此會，今日喜相從。——潘述", "後夏仍多病，前書達幾封。——皎然", "水華迎暮雨，松吹引疏鐘。——皎然", "出谷隨初月，尋僧說五峰。——潘述"]'),
('yuding-30','送晝公聯句','皎然','唐','御定全唐诗','yuding','','[]','相逢情不厭，惜別意難為。——韓章',128,'御定全唐詩/json/794.json','["相逢情不厭，惜別意難為。——韓章", "吾道應無住，前期未可知。——皎然", "輕霜凋古木，寒水縮荒陂。——韓章", "賓雁依沙嶼，浮雲慘路岐。——皎然", "林疏看野迥，岸轉覺山移。——韓章", "寄賞驚搖落，歸心歎別離。——皎然", "草堂思偃蹇，麈尾去相隨。——顧況", "勿謂光陰遠，禪房會一窺。——鄭遨"]'),
('yuding-31','與羅隱之聯句','鄭遨','唐','御定全唐诗','yuding','','[]','一壺天上有名物，兩個世間無事人。——鄭遨',41,'御定全唐詩/json/794.json','["一壺天上有名物，兩個世間無事人。——鄭遨", "醉卻隱之雲叟外，不知何處是天真。——羅隱之"]'),
('yuding-0','句','李日知','唐','御定全唐诗','yuding','','[]','所願暫知居者樂，無使時稱主者勞。',16,'御定全唐詩/json/795.json','["所願暫知居者樂，無使時稱主者勞。"]'),
('yuding-1','句','趙仁奬','唐','御定全唐诗','yuding','','[]','令乘驄馬去，丞脫繡衣來。',12,'御定全唐詩/json/795.json','["令乘驄馬去，丞脫繡衣來。"]'),
('yuding-2','句','郭廷謂','唐','御定全唐诗','yuding','','[]','魂逐東流水，墳依獨坐山。',12,'御定全唐詩/json/795.json','["魂逐東流水，墳依獨坐山。"]'),
('yuding-3','句','韋青','唐','御定全唐诗','yuding','','[]','三代掌綸誥，一身能唱歌。',12,'御定全唐詩/json/795.json','["三代掌綸誥，一身能唱歌。"]'),
